var TG_API = "https://api.telegram.org/bot";
function inlineKeyboard(buttons) {
  if (!buttons || buttons.length === 0) return void 0;
  return { inline_keyboard: [buttons.map((b) => ({ text: b.text, url: b.url }))] };
}
async function tgSendPhoto(token, msg) {
  const body = {
    chat_id: msg.chatId,
    photo: msg.photoUrl,
    caption: msg.caption,
    parse_mode: msg.parseMode || "HTML"
  };
  const kb = inlineKeyboard(msg.buttons);
  if (kb) body.reply_markup = kb;
  try {
    const r = await fetch(`${TG_API}${token}/sendPhoto`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body)
    });
    const data = await r.json();
    if (!data?.ok) return { ok: false, error: data?.description || `HTTP ${r.status}` };
    return { ok: true };
  } catch (err) {
    return { ok: false, error: String(err?.message || err) };
  }
}
async function tgBroadcastPhoto(msg) {
  const token = process.env.TELEGRAM_BOT_TOKEN;
  if (!token) return [];
  const dests = [process.env.TELEGRAM_CHANNEL, process.env.TELEGRAM_CHAT].filter(Boolean);
  const results = [];
  for (const chatId of dests) {
    const r = await tgSendPhoto(token, { ...msg, chatId });
    results.push({ chatId, ...r });
  }
  return results;
}
function tgEscape(s) {
  return String(s || "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

