      headline: "\u{1F537} \u0935\u093F\u0936\u094D\u0935\u093E\u0938 \u0915\u0947 6 \u0938\u094D\u0924\u0902\u092D",
      caption: "\u{1F537} \u0935\u093F\u0936\u094D\u0935\u093E\u0938 \u0915\u0947 6 \u0938\u094D\u0924\u0902\u092D\n\u2726 TurboLoop \u0915\u094D\u092F\u094B\u0902 \u0905\u0932\u0917 \u0939\u0948 \u2014 \u0905\u091F\u0942\u091F \u0928\u0940\u0902\u0935 \u092A\u0930 \u0928\u093F\u0930\u094D\u092E\u093F\u0924\n\n\u0930\u0917 \u092A\u0941\u0932 \u0914\u0930 \u091F\u0942\u091F\u0947 \u0939\u0941\u090F \u0935\u093E\u0926\u094B\u0902 \u0938\u0947 \u0918\u093F\u0930\u0947 DeFi \u092A\u0930\u093F\u0926\u0943\u0936\u094D\u092F \u092E\u0947\u0902, TurboLoop \u0915\u094B \u0936\u0941\u0930\u0942 \u0938\u0947 \u0939\u0940 \u0935\u093F\u0936\u094D\u0935\u093E\u0938 \u0915\u0947 \u091B\u0939 \u0917\u0948\u0930-\u092A\u0930\u0915\u094D\u0930\u093E\u092E\u094D\u092F \u0938\u094D\u0924\u0902\u092D\u094B\u0902 \u0915\u0947 \u0938\u093E\u0925 \u0924\u0948\u092F\u093E\u0930 \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948\u0964 \u0915\u094B\u0921 \u0915\u0940 \u0939\u0930 \u0932\u093E\u0907\u0928 \u0915\u093E \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0930\u0942\u092A \u0938\u0947 \u0911\u0921\u093F\u091F \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948 \u0914\u0930 \u0907\u0938\u0947 99% \u091F\u094D\u0930\u0938\u094D\u091F \u0938\u094D\u0915\u094B\u0930 \u092A\u094D\u0930\u093E\u092A\u094D\u0924 \u0939\u0941\u0906 \u0939\u0948\u0964 \u090F\u0921\u092E\u093F\u0928 \u0915\u0940\u091C\u093C \u0915\u094B \u0938\u094D\u0925\u093E\u092F\u0940 \u0930\u0942\u092A \u0938\u0947 \u092C\u0930\u094D\u0928 \u0915\u0930 \u0926\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948 \u2014 \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0915\u094B \u0921\u0947\u0921 \u090F\u0921\u094D\u0930\u0947\u0938 \u092A\u0930 \u0924\u094D\u092F\u093E\u0917 \u0926\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948, \u091C\u093F\u0938\u0915\u093E \u0905\u0930\u094D\u0925 \u0939\u0948 \u0915\u093F \u0915\u094B\u0908 \u092D\u0940 \u0907\u0902\u0938\u093E\u0928 \u0915\u092D\u0940 \u092D\u0940 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0915\u094B \u0938\u0902\u0936\u094B\u0927\u093F\u0924 \u0928\u0939\u0940\u0902 \u0915\u0930 \u0938\u0915\u0924\u093E \u0939\u0948\u0964 \u0932\u093F\u0915\u094D\u0935\u093F\u0921\u093F\u091F\u0940 \u092A\u0942\u0932 \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F \u0932\u0949\u0915 \u0939\u0948, \u091C\u093F\u0938\u0938\u0947 \u0930\u0917 \u092A\u0941\u0932 \u0915\u0940 \u0915\u094B\u0908 \u092D\u0940 \u0938\u0902\u092D\u093E\u0935\u0928\u093E \u0938\u092E\u093E\u092A\u094D\u0924 \u0939\u094B \u091C\u093E\u0924\u0940 \u0939\u0948\u0964 \u0938\u094B\u0930\u094D\u0938 \u0915\u094B\u0921 BscScan \u092A\u0930 \u092A\u0942\u0930\u0940 \u0924\u0930\u0939 \u0938\u0947 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0939\u0948 \u0924\u093E\u0915\u093F \u0915\u094B\u0908 \u092D\u0940 \u0907\u0938\u0947 \u092A\u0922\u093C \u0938\u0915\u0947 \u0914\u0930 \u0911\u0921\u093F\u091F \u0915\u0930 \u0938\u0915\u0947\u0964 \u0915\u093F\u0938\u0940 KYC \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u0939\u0940 \u0906\u092A\u0915\u0940 \u092A\u0939\u091A\u093E\u0928 \u0939\u0948\u0964 \u0914\u0930 \u092A\u094D\u0930\u094B\u091F\u094B\u0915\u0949\u0932 100% \u0928\u0949\u0928-\u0915\u0938\u094D\u091F\u094B\u0921\u093F\u092F\u0932 \u0939\u0948 \u2014 TurboLoop \u0915\u092D\u0940 \u092D\u0940 \u0906\u092A\u0915\u0947 \u092B\u0902\u0921 \u0915\u094B \u0939\u094B\u0932\u094D\u0921 \u0928\u0939\u0940\u0902 \u0915\u0930\u0924\u093E \u0939\u0948\u0964 \u092F\u0947 \u0915\u0947\u0935\u0932 \u092E\u093E\u0930\u094D\u0915\u0947\u091F\u093F\u0902\u0917 \u0915\u0947 \u0935\u093E\u0926\u0947 \u0928\u0939\u0940\u0902 \u0939\u0948\u0902; \u092F\u0947 \u0911\u0928-\u091A\u0947\u0928 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0924\u0925\u094D\u092F \u0939\u0948\u0902\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0911\u0921\u093F\u091F\u0947\u0921 \u0914\u0930 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u2014 \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0911\u0921\u093F\u091F \u0938\u0947 99% \u091F\u094D\u0930\u0938\u094D\u091F \u0938\u094D\u0915\u094B\u0930\n\u2022 \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0924\u094D\u092F\u093E\u0917 \u0926\u093F\u092F\u093E \u0917\u092F\u093E \u2014 \u090F\u0921\u092E\u093F\u0928 \u0915\u0940\u091C\u093C \u092C\u0930\u094D\u0928 \u0915\u0930 \u0926\u0940 \u0917\u0908\u0902, \u090F\u0921\u094D\u0930\u0947\u0938: 0x000...dead\n\u2022 LP \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F \u0932\u0949\u0915 \u2014 \u0930\u0917 \u092A\u0941\u0932 \u0938\u0902\u092D\u0935 \u0928\u0939\u0940\u0902, \u0932\u093F\u0915\u094D\u0935\u093F\u0921\u093F\u091F\u0940 \u0938\u094D\u0925\u093E\u092F\u0940 \u0930\u0942\u092A \u0938\u0947 \u0938\u0941\u0930\u0915\u094D\u0937\u093F\u0924\n\u2022 \u0915\u094B\u0908 KYC \u0906\u0935\u0936\u094D\u092F\u0915 \u0928\u0939\u0940\u0902 \u2014 \u092A\u0942\u0930\u094D\u0923 \u0917\u094B\u092A\u0928\u0940\u092F\u0924\u093E, \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u0939\u0940 \u0906\u092A\u0915\u0940 \u092A\u0939\u091A\u093E\u0928 \u0939\u0948\n\u2022 BscScan \u092A\u0930 \u0915\u094B\u0921 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u2014 \u0913\u092A\u0928 \u0938\u094B\u0930\u094D\u0938, \u092A\u093E\u0930\u0926\u0930\u094D\u0936\u0940, \u0915\u093F\u0938\u0940 \u0915\u0947 \u092D\u0940 \u092A\u0922\u093C\u0928\u0947 \u092F\u094B\u0917\u094D\u092F\n\n\u{1F48E} \u0935\u093F\u0936\u094D\u0935\u093E\u0938 \u0915\u0947 \u091B\u0939 \u0938\u094D\u0924\u0902\u092D\u0964 \u090F\u0915 \u092A\u094D\u0930\u094B\u091F\u094B\u0915\u0949\u0932\u0964 \u0936\u0942\u0928\u094D\u092F \u0938\u092E\u091D\u094C\u0924\u0947\u0964\n\n\u{1F310} turboloop.io",
