      original: "04_Smart_Contract.png",
      headline: "\u{1F537} Smart Contract \u0915\u094D\u092F\u093E \u0939\u0948?",
      caption: "\u{1F537} Smart Contract \u0915\u094D\u092F\u093E \u0939\u0948?\n\u2726 \u0938\u0947\u0932\u094D\u092B-\u090F\u0915\u094D\u091C\u0940\u0915\u094D\u092F\u0942\u091F\u093F\u0902\u0917 \u0915\u094B\u0921 \u091C\u094B \u092D\u0930\u094B\u0938\u0947 \u0915\u0940 \u091C\u0917\u0939 \u0935\u0947\u0930\u093F\u092B\u093F\u0915\u0947\u0936\u0928 \u0915\u094B \u0938\u094D\u0925\u093E\u092A\u093F\u0924 \u0915\u0930\u0924\u093E \u0939\u0948\n\n\u090F\u0915 Smart Contract \u092C\u094D\u0932\u0949\u0915\u091A\u0947\u0928 \u092A\u0930 \u0921\u093F\u092A\u094D\u0932\u0949\u092F \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u090F\u0915 \u0938\u0947\u0932\u094D\u092B-\u090F\u0915\u094D\u091C\u0940\u0915\u094D\u092F\u0942\u091F\u093F\u0902\u0917 \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E \u0939\u0948 \u091C\u094B \u0905\u092A\u0928\u0947 \u0915\u094B\u0921 \u092E\u0947\u0902 \u0932\u093F\u0916\u0947 \u0917\u090F \u0928\u093F\u092F\u092E\u094B\u0902 \u0915\u094B \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u0932\u093E\u0917\u0942 \u0915\u0930\u0924\u093E \u0939\u0948 \u2014 \u092C\u093F\u0928\u093E \u0915\u093F\u0938\u0940 \u092E\u093E\u0928\u0935\u0940\u092F \u0939\u0938\u094D\u0924\u0915\u094D\u0937\u0947\u092A \u0915\u0947\u0964 \u090F\u0915 \u092C\u093E\u0930 \u0921\u093F\u092A\u094D\u0932\u0949\u092F \u0939\u094B\u0928\u0947 \u0915\u0947 \u092C\u093E\u0926, \u0907\u0938\u0947 \u0915\u093F\u0938\u0940 \u0915\u0947 \u0926\u094D\u0935\u093E\u0930\u093E \u092D\u0940 \u092C\u0926\u0932\u093E, \u0930\u094B\u0915\u093E \u092F\u093E \u0939\u0947\u0930\u092B\u0947\u0930 \u0928\u0939\u0940\u0902 \u0915\u093F\u092F\u093E \u091C\u093E \u0938\u0915\u0924\u093E \u0939\u0948, \u0907\u0938\u0915\u0947 \u0928\u093F\u0930\u094D\u092E\u093E\u0924\u093E\u0913\u0902 \u0926\u094D\u0935\u093E\u0930\u093E \u092D\u0940 \u0928\u0939\u0940\u0902\u0964 \u0907\u0938\u0947 \u090F\u0915 \u0921\u093F\u091C\u093F\u091F\u0932 \u0938\u092E\u091D\u094C\u0924\u0947 \u0915\u0947 \u0930\u0942\u092A \u092E\u0947\u0902 \u0938\u094B\u091A\u0947\u0902 \u091C\u094B \u0916\u0941\u0926 \u0915\u094B \u0928\u093F\u0937\u094D\u092A\u093E\u0926\u093F\u0924 \u0915\u0930\u0924\u093E \u0939\u0948: \u092F\u0926\u093F \u0936\u0930\u094D\u0924 A \u092A\u0942\u0930\u0940 \u0939\u094B\u0924\u0940 \u0939\u0948, \u0924\u094B \u0915\u093E\u0930\u094D\u0930\u0935\u093E\u0908 B \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u0939\u094B\u0924\u0940 \u0939\u0948\u0964 TurboLoop \u092A\u0942\u0930\u0940 \u0924\u0930\u0939 \u0938\u0947 \u090F\u0915 Smart Contract \u092A\u0930 \u091A\u0932\u0924\u093E \u0939\u0948 \u2014 \u0939\u0930 \u0921\u093F\u092A\u0949\u091C\u093F\u091F, \u0939\u0930 \u0926\u0948\u0928\u093F\u0915 \u092F\u0940\u0932\u094D\u0921 \u0915\u0940 \u0917\u0923\u0928\u093E, \u0939\u0930 \u0935\u093F\u0921\u094D\u0930\u0949\u0932 \u0915\u094B\u0921 \u0926\u094D\u0935\u093E\u0930\u093E \u092A\u094D\u0930\u094B\u0938\u0947\u0938 \u0915\u093F\u092F\u093E \u091C\u093E\u0924\u093E \u0939\u0948, \u0932\u094B\u0917\u094B\u0902 \u0926\u094D\u0935\u093E\u0930\u093E \u0928\u0939\u0940\u0902\u0964 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0915\u0940 \u0913\u0928\u0930\u0936\u093F\u092A \u0915\u094B \u0924\u094D\u092F\u093E\u0917 \u0926\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948, \u091C\u093F\u0938\u0915\u093E \u0905\u0930\u094D\u0925 \u0939\u0948 \u0915\u093F \u090F\u0921\u092E\u093F\u0928 \u0915\u0940\u091C\u093C \u0938\u094D\u0925\u093E\u092F\u0940 \u0930\u0942\u092A \u0938\u0947 \u092C\u0930\u094D\u0928 \u0915\u0930 \u0926\u0940 \u0917\u0908 \u0939\u0948\u0902\u0964 \u0915\u094B\u0908 \u092D\u0940 \u0928\u093F\u092F\u092E \u0928\u0939\u0940\u0902 \u092C\u0926\u0932 \u0938\u0915\u0924\u093E\u0964 \u0915\u094B\u0908 \u092D\u0940 \u0906\u092A\u0915\u0947 \u092B\u0902\u0921 \u0924\u0915 \u0928\u0939\u0940\u0902 \u092A\u0939\u0941\u0902\u091A \u0938\u0915\u0924\u093E\u0964 \u0915\u094B\u0921 \u0939\u0940 \u0915\u093E\u0928\u0942\u0928 \u0939\u0948, \u0914\u0930 \u092F\u0939 \u0939\u0930 \u090F\u0915 \u0926\u093F\u0928 \u0917\u0923\u093F\u0924\u0940\u092F \u0938\u091F\u0940\u0915\u0924\u093E \u0915\u0947 \u0938\u093E\u0925 \u0928\u093F\u0937\u094D\u092A\u093E\u0926\u093F\u0924 \u0939\u094B\u0924\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u092C\u094D\u0932\u0949\u0915\u091A\u0947\u0928 \u092A\u0930 \u0938\u0947\u0932\u094D\u092B-\u090F\u0915\u094D\u091C\u0940\u0915\u094D\u092F\u0942\u091F\u093F\u0902\u0917 \u0915\u094B\u0921 \u2014 \u0915\u093F\u0938\u0940 \u092E\u093E\u0928\u0935\u0940\u092F \u0939\u0938\u094D\u0924\u0915\u094D\u0937\u0947\u092A \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0928\u0939\u0940\u0902\n\u2022 \u0905\u092A\u0930\u093F\u0935\u0930\u094D\u0924\u0928\u0940\u092F \u2014 \u090F\u0915 \u092C\u093E\u0930 \u0921\u093F\u092A\u094D\u0932\u0949\u092F \u0939\u094B\u0928\u0947 \u0915\u0947 \u092C\u093E\u0926, \u0915\u094B\u0908 \u092D\u0940 \u0907\u0938\u0947 \u092C\u0926\u0932 \u092F\u093E \u0939\u0947\u0930\u092B\u0947\u0930 \u0928\u0939\u0940\u0902 \u0915\u0930 \u0938\u0915\u0924\u093E\n\u2022 TurboLoop \u0915\u0940 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0913\u0928\u0930\u0936\u093F\u092A \u0924\u094D\u092F\u093E\u0917 \u0926\u0940 \u0917\u0908 \u0939\u0948 \u2014 \u090F\u0921\u092E\u093F\u0928 \u0915\u0940\u091C\u093C \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F \u092C\u0930\u094D\u0928 \u0915\u0930 \u0926\u0940 \u0917\u0908 \u0939\u0948\u0902\n\u2022 \u0939\u0930 \u091F\u094D\u0930\u093E\u0902\u091C\u0947\u0915\u094D\u0936\u0928 \u092A\u093E\u0930\u0926\u0930\u094D\u0936\u0940 \u0939\u0948 \u0914\u0930 BscScan \u092A\u0930 \u0935\u0947\u0930\u093F\u092B\u093E\u0908 \u0915\u093F\u092F\u093E \u091C\u093E \u0938\u0915\u0924\u093E \u0939\u0948\n\u2022 \u0915\u094B\u0921 \u0939\u0940 \u0915\u093E\u0928\u0942\u0928 \u0939\u0948 \u2014 \u0917\u0923\u093F\u0924\u0940\u092F \u0938\u091F\u0940\u0915\u0924\u093E \u0915\u0947 \u0938\u093E\u0925 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u0928\u093F\u0937\u094D\u092A\u093E\u0926\u093F\u0924 \u0939\u094B\u0924\u093E \u0939\u0948\n\n\u{1F48E} \u0932\u094B\u0917\u094B\u0902 \u092A\u0930 \u092D\u0930\u094B\u0938\u093E \u0928 \u0915\u0930\u0947\u0902\u0964 \u0915\u094B\u0921 \u092A\u0930 \u092D\u0930\u094B\u0938\u093E \u0915\u0930\u0947\u0902\u0964 \u0907\u0938\u0947 \u0938\u094D\u0935\u092F\u0902 \u0935\u0947\u0930\u093F\u092B\u093E\u0908 \u0915\u0930\u0947\u0902\u0964\n\n\u{1F310} turboloop.io",
