      caption: '\u{1F537} \u0905\u092A\u0928\u093E \u0935\u0949\u0932\u0947\u091F \u0915\u0928\u0947\u0915\u094D\u091F \u0915\u0930\u0947\u0902\n\u2726 \u0915\u0928\u0947\u0915\u094D\u091F \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u090F\u0915 \u0915\u094D\u0932\u093F\u0915 \u2014 \u0915\u092E\u093E\u0908 \u0936\u0941\u0930\u0942 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u090F\u0915 \u0915\u0926\u092E\n\n\u0905\u092A\u0928\u0947 \u0935\u0949\u0932\u0947\u091F \u0915\u094B TurboLoop \u0938\u0947 \u0915\u0928\u0947\u0915\u094D\u091F \u0915\u0930\u0928\u093E \u0906\u092A\u0915\u0940 DeFi \u092F\u093E\u0924\u094D\u0930\u093E \u0915\u093E \u0938\u092C\u0938\u0947 \u0938\u0930\u0932 \u0915\u0926\u092E \u0939\u0948\u0964 turboloop.io \u092A\u0930 \u091C\u093E\u090F\u0902, "Connect Wallet" \u092C\u091F\u0928 \u092A\u0930 \u0915\u094D\u0932\u093F\u0915 \u0915\u0930\u0947\u0902, \u0914\u0930 \u0905\u092A\u0928\u093E \u0935\u0949\u0932\u0947\u091F \u092A\u094D\u0930\u0926\u093E\u0924\u093E \u091A\u0941\u0928\u0947\u0902 \u2014 MetaMask, Trust Wallet, \u092F\u093E \u0915\u094B\u0908 \u092D\u0940 WalletConnect-\u0938\u0902\u0917\u0924 \u0935\u0949\u0932\u0947\u091F\u0964 \u0915\u0928\u0947\u0915\u094D\u0936\u0928 \u0905\u0928\u0941\u0930\u094B\u0927 \u0915\u094B \u0938\u094D\u0935\u0940\u0915\u0943\u0924 \u0915\u0930\u0947\u0902, \u0938\u0941\u0928\u093F\u0936\u094D\u091A\u093F\u0924 \u0915\u0930\u0947\u0902 \u0915\u093F \u0906\u092A Binance Smart Chain (BSC) \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u092A\u0930 \u0939\u0948\u0902, \u0914\u0930 \u0906\u092A \u0905\u0902\u0926\u0930 \u0939\u0948\u0902\u0964 \u0915\u094B\u0908 \u092A\u0902\u091C\u0940\u0915\u0930\u0923 \u0928\u0939\u0940\u0902\u0964 \u0915\u094B\u0908 \u0908\u092E\u0947\u0932 \u0928\u0939\u0940\u0902\u0964 \u0915\u094B\u0908 \u092A\u093E\u0938\u0935\u0930\u094D\u0921 \u0928\u0939\u0940\u0902\u0964 \u0915\u094B\u0908 KYC \u0928\u0939\u0940\u0902\u0964 \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u092A\u0924\u093E \u0939\u0940 \u0906\u092A\u0915\u093E \u0916\u093E\u0924\u093E \u0939\u0948, \u0914\u0930 \u092C\u094D\u0932\u0949\u0915\u091A\u0947\u0928 \u0906\u092A\u0915\u093E \u092A\u094D\u0930\u092E\u093E\u0923\u0940\u0915\u0930\u0923 \u0939\u0948\u0964 \u090F\u0915 \u092C\u093E\u0930 \u0915\u0928\u0947\u0915\u094D\u091F \u0939\u094B\u0928\u0947 \u0915\u0947 \u092C\u093E\u0926, \u0906\u092A \u0938\u092D\u0940 \u091A\u093E\u0930 \u0928\u093F\u0935\u0947\u0936 \u092F\u094B\u091C\u0928\u093E\u0913\u0902, \u0905\u092A\u0928\u0947 \u0930\u0947\u092B\u0930\u0932 \u0932\u093F\u0902\u0915 \u0914\u0930 \u0905\u092A\u0928\u0940 \u0915\u092E\u093E\u0908 \u0915\u0940 \u0930\u0940\u092F\u0932-\u091F\u093E\u0907\u092E \u091F\u094D\u0930\u0948\u0915\u093F\u0902\u0917 \u0915\u0947 \u0938\u093E\u0925 \u092A\u0942\u0930\u093E \u0921\u0948\u0936\u092C\u094B\u0930\u094D\u0921 \u0926\u0947\u0916\u0947\u0902\u0917\u0947\u0964 \u092A\u0942\u0930\u0940 \u0915\u0928\u0947\u0915\u094D\u0936\u0928 \u092A\u094D\u0930\u0915\u094D\u0930\u093F\u092F\u093E \u092E\u0947\u0902 30 \u0938\u0947\u0915\u0902\u0921 \u0938\u0947 \u092D\u0940 \u0915\u092E \u0938\u092E\u092F \u0932\u0917\u0924\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 turboloop.io \u092A\u0930 \u091C\u093E\u090F\u0902 \u0914\u0930 "Connect Wallet" \u092A\u0930 \u0915\u094D\u0932\u093F\u0915 \u0915\u0930\u0947\u0902 \u2014 30 \u0938\u0947\u0915\u0902\u0921 \u0932\u0917\u0924\u0947 \u0939\u0948\u0902\n\u2022 MetaMask, Trust Wallet, \u0914\u0930 WalletConnect \u0915\u0947 \u0938\u093E\u0925 \u0938\u0902\u0917\u0924\n\u2022 \u0909\u091A\u093F\u0924 \u0915\u093E\u0930\u094D\u092F\u0915\u094D\u0937\u092E\u0924\u093E \u0915\u0947 \u0932\u093F\u090F \u0938\u0941\u0928\u093F\u0936\u094D\u091A\u093F\u0924 \u0915\u0930\u0947\u0902 \u0915\u093F \u0906\u092A BSC \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u092A\u0930 \u0939\u0948\u0902\n\u2022 \u0915\u094B\u0908 \u092A\u0902\u091C\u0940\u0915\u0930\u0923 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0908\u092E\u0947\u0932 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u092A\u093E\u0938\u0935\u0930\u094D\u0921 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 KYC \u0906\u0935\u0936\u094D\u092F\u0915 \u0928\u0939\u0940\u0902\n\u2022 \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u092A\u0924\u093E = \u0906\u092A\u0915\u093E \u0916\u093E\u0924\u093E, \u092C\u094D\u0932\u0949\u0915\u091A\u0947\u0928 = \u0906\u092A\u0915\u093E \u092A\u094D\u0930\u092E\u093E\u0923\u0940\u0915\u0930\u0923\n\n\u{1F48E} \u0915\u0928\u0947\u0915\u094D\u091F \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u090F\u0915 \u0915\u094D\u0932\u093F\u0915\u0964 \u0915\u092E\u093E\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u090F\u0915 \u0915\u0926\u092E\u0964 \u0932\u0942\u092A \u092E\u0947\u0902 \u0906\u092A\u0915\u093E \u0938\u094D\u0935\u093E\u0917\u0924 \u0939\u0948\u0964\n\n\u{1F310} turboloop.io',
