      headline: "\u{1F537} $100 \u0915\u0947\u0938 \u0938\u094D\u091F\u0921\u0940",
      caption: "\u{1F537} $100 \u0915\u0947\u0938 \u0938\u094D\u091F\u0921\u0940\n\u2726 \u091C\u092C \u0906\u092A \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u092A\u094D\u0932\u093E\u0928 \u092E\u0947\u0902 $100 \u091C\u092E\u093E \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u0924\u094B \u0915\u094D\u092F\u093E \u0939\u094B\u0924\u093E \u0939\u0948?\n\n\u0906\u0907\u090F \u0935\u093F\u0938\u094D\u0924\u093E\u0930 \u0938\u0947 \u0938\u092E\u091D\u0947\u0902 \u0915\u093F TurboLoop \u0915\u0947 \u091A\u093E\u0930 \u092A\u094D\u0932\u093E\u0928\u094D\u0938 \u092E\u0947\u0902 $100 \u0915\u093F\u0924\u0928\u093E \u0915\u092E\u093E\u0924\u093E \u0939\u0948\u0964 Sprint Loop \u092E\u0947\u0902, \u0906\u092A\u0915\u093E $100 \u0915\u0947\u0935\u0932 7 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 $103 \u0939\u094B \u091C\u093E\u0924\u093E \u0939\u0948 \u2014 \u090F\u0915 \u0924\u094D\u0935\u0930\u093F\u0924, \u0915\u092E \u091C\u094B\u0916\u093F\u092E \u0935\u093E\u0932\u093E \u092A\u0930\u0940\u0915\u094D\u0937\u0923\u0964 Boost Loop \u092E\u0947\u0902, \u0935\u0939\u0940 $100 14 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 \u092C\u0922\u093C\u0915\u0930 $110 \u0939\u094B \u091C\u093E\u0924\u093E \u0939\u0948 \u2014 \u0926\u094B\u0917\u0941\u0928\u0947 \u0938\u092E\u092F \u092E\u0947\u0902 \u0924\u0940\u0928 \u0917\u0941\u0928\u0947 \u0938\u0947 \u0905\u0927\u093F\u0915 \u0930\u093F\u091F\u0930\u094D\u0928\u0964 Power Loop 30 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 $100 \u0915\u094B $124 \u092E\u0947\u0902 \u092C\u0926\u0932 \u0926\u0947\u0924\u093E \u0939\u0948 \u2014 24% \u0915\u093E \u0932\u093E\u092D \u091C\u094B \u090F\u0915 \u0939\u0940 \u092E\u0939\u0940\u0928\u0947 \u092E\u0947\u0902 \u0905\u0927\u093F\u0915\u093E\u0902\u0936 \u0935\u093E\u0930\u094D\u0937\u093F\u0915 \u092C\u0948\u0902\u0915 \u092C\u091A\u0924 \u0926\u0930\u094B\u0902 \u0915\u094B \u092A\u0940\u091B\u0947 \u091B\u094B\u0921\u093C \u0926\u0947\u0924\u093E \u0939\u0948\u0964 \u0914\u0930 Ultimate Loop? \u0906\u092A\u0915\u093E $100 60 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 $154 \u0939\u094B \u091C\u093E\u0924\u093E \u0939\u0948 \u2014 \u0906\u092A\u0915\u0940 \u091C\u092E\u093E \u0930\u093E\u0936\u093F \u0915\u093E \u0906\u0927\u0947 \u0938\u0947 \u0905\u0927\u093F\u0915 \u0939\u093F\u0938\u094D\u0938\u093E \u0936\u0941\u0926\u094D\u0927 \u0932\u093E\u092D \u0915\u0947 \u0930\u0942\u092A \u092E\u0947\u0902 \u091C\u0941\u0921\u093C \u091C\u093E\u0924\u093E \u0939\u0948\u0964 \u092F\u0947 \u0905\u0928\u0941\u092E\u093E\u0928 \u092F\u093E \u092D\u0935\u093F\u0937\u094D\u092F\u0935\u093E\u0923\u093F\u092F\u093E\u0902 \u0928\u0939\u0940\u0902 \u0939\u0948\u0902\u0964 \u092F\u0947 Smart Contract \u092E\u0947\u0902 \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E \u0915\u093F\u090F \u0917\u090F \u0938\u091F\u0940\u0915 \u0930\u093F\u091F\u0930\u094D\u0928 \u0939\u0948\u0902, \u091C\u093F\u0928\u0915\u0940 \u0917\u0923\u0928\u093E \u092A\u094D\u0930\u0924\u093F\u0926\u093F\u0928 \u0915\u0940 \u091C\u093E\u0924\u0940 \u0939\u0948 \u0914\u0930 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u0935\u093F\u0924\u0930\u093F\u0924 \u0915\u093F\u090F \u091C\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 TurboLoop \u0915\u0940 \u0936\u0915\u094D\u0924\u093F \u0915\u093E \u092A\u094D\u0930\u0924\u094D\u092F\u0915\u094D\u0937 \u0905\u0928\u0941\u092D\u0935 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0915\u0947\u0935\u0932 $100 \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 Sprint Loop: 7 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 $100 \u2192 $103 (3% \u0930\u093F\u091F\u0930\u094D\u0928)\n\u2022 Boost Loop: 14 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 $100 \u2192 $110 (10% \u0930\u093F\u091F\u0930\u094D\u0928)\n\u2022 Power Loop: 30 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 $100 \u2192 $124 (24% \u0930\u093F\u091F\u0930\u094D\u0928)\n\u2022 Ultimate Loop: 60 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 $100 \u2192 $154 (54% \u0930\u093F\u091F\u0930\u094D\u0928)\n\u2022 \u0938\u092D\u0940 \u0930\u093F\u091F\u0930\u094D\u0928 \u0938\u091F\u0940\u0915 \u0939\u0948\u0902, Smart Contract \u092E\u0947\u0902 \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E \u0915\u093F\u090F \u0917\u090F \u0939\u0948\u0902\n\n\u{1F48E} \u0906\u091C $100\u0964 \u0915\u0932 \u0915\u093F\u0924\u0928\u093E? \u0917\u0923\u093F\u0924 \u0916\u0941\u0926 \u092C\u094B\u0932\u0924\u093E \u0939\u0948\u0964\n\n\u{1F310} turboloop.io",
