      original: "22_Netritva_Rank.png",
      headline: "\u{1F537} \u0928\u0947\u0924\u0943\u0924\u094D\u0935 \u0930\u0948\u0902\u0915",
      caption: "\u{1F537} \u0928\u0947\u0924\u0943\u0924\u094D\u0935 \u0930\u0948\u0902\u0915\n\u2726 \u0909\u092A\u0932\u092C\u094D\u0927\u093F \u0915\u0947 \u0938\u093E\u0924 \u0938\u094D\u0924\u0930 \u2014 \u092A\u093E\u0930\u094D\u091F\u0928\u0930 \u0938\u0947 TURBO LEGEND \u0924\u0915\n\nTurboLoop \u0905\u092A\u0928\u0947 \u0938\u092C\u0938\u0947 \u0938\u092E\u0930\u094D\u092A\u093F\u0924 \u0915\u092E\u094D\u092F\u0941\u0928\u093F\u091F\u0940 \u092C\u093F\u0932\u094D\u0921\u0930\u094D\u0938 \u0915\u094B \u0938\u093E\u0924 \u092A\u094D\u0930\u0924\u093F\u0937\u094D\u0920\u093F\u0924 \u0928\u0947\u0924\u0943\u0924\u094D\u0935 \u0930\u0948\u0902\u0915\u094B\u0902 \u0915\u0947 \u0938\u093E\u0925 \u092A\u0941\u0930\u0938\u094D\u0915\u0943\u0924 \u0915\u0930\u0924\u093E \u0939\u0948, \u091C\u093F\u0928\u092E\u0947\u0902 \u0938\u0947 \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u0906\u092A\u0915\u0947 \u092A\u0942\u0930\u0947 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0915\u0940 \u0917\u0924\u093F\u0935\u093F\u0927\u093F \u092A\u0930 \u0909\u0924\u094D\u0924\u0930\u094B\u0924\u094D\u0924\u0930 \u0909\u091A\u094D\u091A \u092C\u094B\u0928\u0938 \u092A\u094D\u0930\u0924\u093F\u0936\u0924 \u0915\u094B \u0905\u0928\u0932\u0949\u0915 \u0915\u0930\u0924\u093E \u0939\u0948\u0964 100 \u091F\u0940\u092E \u0938\u0926\u0938\u094D\u092F\u094B\u0902 \u0915\u0947 \u0938\u093E\u0925 \u090F\u0915 \u092A\u093E\u0930\u094D\u091F\u0928\u0930 \u0915\u0947 \u0930\u0942\u092A \u092E\u0947\u0902 \u0936\u0941\u0930\u0941\u0906\u0924 \u0915\u0930\u0928\u0947 \u092A\u0930 \u0906\u092A\u0915\u094B 1% \u0928\u0947\u0924\u0943\u0924\u094D\u0935 \u092C\u094B\u0928\u0938 \u092E\u093F\u0932\u0924\u093E \u0939\u0948\u0964 \u091C\u0948\u0938\u0947-\u091C\u0948\u0938\u0947 \u0906\u092A\u0915\u093E \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u092C\u0922\u093C\u0924\u093E \u0939\u0948, \u0906\u092A \u0938\u0940\u0928\u093F\u092F\u0930 \u092A\u093E\u0930\u094D\u091F\u0928\u0930 (2%), \u092E\u0948\u0928\u0947\u091C\u0930 (3%), \u0938\u0940\u0928\u093F\u092F\u0930 \u092E\u0948\u0928\u0947\u091C\u0930 (5%), \u0921\u093E\u092F\u0930\u0947\u0915\u094D\u091F\u0930 (7%), \u0914\u0930 \u0938\u0940\u0928\u093F\u092F\u0930 \u0921\u093E\u092F\u0930\u0947\u0915\u094D\u091F\u0930 (8%) \u0915\u0947 \u092E\u093E\u0927\u094D\u092F\u092E \u0938\u0947 \u090A\u092A\u0930 \u0909\u0920\u0924\u0947 \u0939\u0948\u0902\u0964 \u0936\u093F\u0916\u0930 \u092A\u0930 TURBO LEGEND \u0930\u0948\u0902\u0915 \u0939\u0948 \u2014 \u091C\u094B \u0909\u0928 \u0932\u094B\u0917\u094B\u0902 \u0915\u0947 \u0932\u093F\u090F \u0906\u0930\u0915\u094D\u0937\u093F\u0924 \u0939\u0948 \u091C\u094B \u0915\u0941\u0932 \u091F\u0940\u092E \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u092E\u0947\u0902 $1M+ \u0915\u0947 \u0938\u093E\u0925 10,000+ \u0938\u0926\u0938\u094D\u092F\u094B\u0902 \u0915\u0940 \u091F\u0940\u092E \u092C\u0928\u093E\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 10% \u0915\u093E \u0936\u093E\u0928\u0926\u093E\u0930 \u0928\u0947\u0924\u0943\u0924\u094D\u0935 \u092C\u094B\u0928\u0938 \u0905\u0930\u094D\u091C\u093F\u0924 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u092F\u0947 \u092C\u094B\u0928\u0938 \u0906\u092A\u0915\u0947 \u092A\u094D\u0932\u093E\u0928 \u092F\u0940\u0932\u094D\u0921 \u0914\u0930 \u0930\u0947\u092B\u0930\u0932 \u0915\u092E\u0940\u0936\u0928 \u0915\u0947 \u0905\u0924\u093F\u0930\u093F\u0915\u094D\u0924 \u0939\u0948\u0902, \u091C\u094B \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u0915\u0930\u0928\u0947 \u0935\u093E\u0932\u094B\u0902 \u0915\u0947 \u0932\u093F\u090F \u090F\u0915 \u0924\u0940\u0938\u0930\u0940 \u0936\u0915\u094D\u0924\u093F\u0936\u093E\u0932\u0940 \u0906\u092F \u0927\u093E\u0930\u093E \u092C\u0928\u093E\u0924\u0947 \u0939\u0948\u0902\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0906\u0915\u0930\u094D\u0937\u0923:\n\u2022 \u092A\u093E\u0930\u094D\u091F\u0928\u0930: 100 \u0938\u0926\u0938\u094D\u092F \u2192 1% \u0928\u0947\u0924\u0943\u0924\u094D\u0935 \u092C\u094B\u0928\u0938\n\u2022 \u0938\u0940\u0928\u093F\u092F\u0930 \u092A\u093E\u0930\u094D\u091F\u0928\u0930: 250 \u0938\u0926\u0938\u094D\u092F \u2192 2% \u092C\u094B\u0928\u0938\n\u2022 \u092E\u0948\u0928\u0947\u091C\u0930: 500 \u0938\u0926\u0938\u094D\u092F \u2192 3% | \u0938\u0940\u0928\u093F\u092F\u0930 \u092E\u0948\u0928\u0947\u091C\u0930: 1,000 \u0938\u0926\u0938\u094D\u092F \u2192 5%\n\u2022 \u0921\u093E\u092F\u0930\u0947\u0915\u094D\u091F\u0930: 2,500 \u0938\u0926\u0938\u094D\u092F \u2192 7% | \u0938\u0940\u0928\u093F\u092F\u0930 \u0921\u093E\u092F\u0930\u0947\u0915\u094D\u091F\u0930: 5,000 \u0938\u0926\u0938\u094D\u092F \u2192 8%\n\u2022 TURBO LEGEND: 10,000 \u0938\u0926\u0938\u094D\u092F + $1M \u091F\u0940\u092E \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u2192 10% \u092C\u094B\u0928\u0938\n\n\u{1F48E} \u0930\u0948\u0902\u0915 \u092E\u0947\u0902 \u090A\u092A\u0930 \u0909\u0920\u0947\u0902\u0964 \u0905\u0927\u093F\u0915 \u0915\u092E\u093E\u090F\u0902\u0964 \u0936\u093F\u0916\u0930 \u0938\u093E\u0939\u0938\u0940 \u0932\u094B\u0917\u094B\u0902 \u0915\u0940 \u092A\u094D\u0930\u0924\u0940\u0915\u094D\u0937\u093E \u0915\u0930 \u0930\u0939\u093E \u0939\u0948\u0964\n\n\u{1F310} turboloop.io",
