      headline: "\u{1F537} \u0911\u0928\u092C\u094B\u0930\u094D\u0921\u093F\u0902\u0917 \u092C\u094B\u0928\u0938 \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E",
      caption: "\u{1F537} \u0911\u0928\u092C\u094B\u0930\u094D\u0921\u093F\u0902\u0917 \u092C\u094B\u0928\u0938 \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E\n\u2726 $10,000 \u0924\u0915 \u0915\u0947 \u0930\u093F\u0935\u0949\u0930\u094D\u0921\u094D\u0938 \u2014 \u0909\u0928\u0915\u0947 \u0932\u093F\u090F \u091C\u094B \u0924\u0947\u091C\u093C\u0940 \u0938\u0947 \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\n\nTurboLoop \u0915\u093E \u0911\u0928\u092C\u094B\u0930\u094D\u0921\u093F\u0902\u0917 \u092C\u094B\u0928\u0938 \u090F\u0915 \u0938\u0940\u092E\u093F\u0924 \u0938\u092E\u092F \u0915\u093E \u090F\u0915\u094D\u0938\u0947\u0932\u0930\u0947\u0936\u0928 \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E \u0939\u0948 \u091C\u094B \u0924\u0947\u091C\u093C\u0940 \u0938\u0947 \u0915\u092E\u094D\u092F\u0941\u0928\u093F\u091F\u0940 \u092C\u0928\u093E\u0928\u0947 \u0935\u093E\u0932\u094B\u0902 \u0915\u094B \u092D\u093E\u0930\u0940 \u0928\u0915\u0926 \u092C\u094B\u0928\u0938 \u0938\u0947 \u092A\u0941\u0930\u0938\u094D\u0915\u0943\u0924 \u0915\u0930\u0924\u093E \u0939\u0948\u0964 60 \u0926\u093F\u0928\u094B\u0902 \u0915\u0940 \u0905\u0935\u0927\u093F \u0915\u0947 \u092D\u0940\u0924\u0930, \u0935\u093F\u0936\u093F\u0937\u094D\u091F \u092E\u093E\u0907\u0932\u0938\u094D\u091F\u094B\u0928 \u0939\u093E\u0938\u093F\u0932 \u0915\u0930\u0947\u0902 \u0914\u0930 \u092C\u0922\u093C\u0924\u0947 \u0939\u0941\u090F \u0930\u093F\u0935\u0949\u0930\u094D\u0921\u094D\u0938 \u0905\u0928\u0932\u0949\u0915 \u0915\u0930\u0947\u0902: 50 \u0928\u090F \u0938\u0926\u0938\u094D\u092F \u0932\u093E\u090F\u0902 \u0914\u0930 $50 \u0915\u092E\u093E\u090F\u0902\u0964 100 \u0938\u0926\u0938\u094D\u092F\u094B\u0902 \u0924\u0915 \u092A\u0939\u0941\u0902\u091A\u0928\u0947 \u092A\u0930 $200\u0964 250 \u092A\u0930 $750\u0964 500 \u092A\u093E\u0930 \u0915\u0930\u0928\u0947 \u092A\u0930 $2,000\u0964 750 \u0939\u093E\u0938\u093F\u0932 \u0915\u0930\u0928\u0947 \u092A\u0930 $4,000\u0964 \u0914\u0930 \u0905\u0902\u0924\u093F\u092E \u092E\u093E\u0907\u0932\u0938\u094D\u091F\u094B\u0928 \u2014 60 \u0926\u093F\u0928\u094B\u0902 \u0915\u0947 \u092D\u0940\u0924\u0930 1,000 \u0928\u090F \u0938\u0926\u0938\u094D\u092F \u2014 \u090F\u0915 \u0935\u093F\u0936\u093E\u0932 $10,000 \u092C\u094B\u0928\u0938 \u0905\u0928\u0932\u0949\u0915 \u0915\u0930\u0924\u093E \u0939\u0948\u0964 \u092F\u0947 \u092C\u094B\u0928\u0938 \u0906\u092A\u0915\u0947 \u0928\u093F\u092F\u092E\u093F\u0924 \u0930\u0947\u092B\u0930\u0932 \u0915\u092E\u0940\u0936\u0928 \u0914\u0930 \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u092C\u094B\u0928\u0938 \u0915\u0947 \u0905\u0924\u093F\u0930\u093F\u0915\u094D\u0924 \u0926\u093F\u090F \u091C\u093E\u0924\u0947 \u0939\u0948\u0902, \u091C\u093F\u0938\u0938\u0947 \u092A\u0939\u0932\u0947 60 \u0926\u093F\u0928 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u092C\u093F\u0932\u094D\u0921\u0930\u094D\u0938 \u0915\u0947 \u0932\u093F\u090F \u0938\u092C\u0938\u0947 \u0906\u0915\u0930\u094D\u0937\u0915 \u0905\u0935\u0927\u093F \u092C\u0928 \u091C\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u091C\u092C \u0906\u092A \u0905\u092A\u0928\u093E \u092A\u0939\u0932\u093E \u0930\u0947\u092B\u0930\u0932 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u0924\u092C \u0938\u0947 \u0938\u092E\u092F \u0936\u0941\u0930\u0942 \u0939\u094B\u0924\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 60 \u0926\u093F\u0928\u094B\u0902 \u092E\u0947\u0902 50 \u0938\u0926\u0938\u094D\u092F \u2192 $50 \u092C\u094B\u0928\u0938\n\u2022 100 \u0938\u0926\u0938\u094D\u092F \u2192 $200 | 250 \u0938\u0926\u0938\u094D\u092F \u2192 $750\n\u2022 500 \u0938\u0926\u0938\u094D\u092F \u2192 $2,000 | 750 \u0938\u0926\u0938\u094D\u092F \u2192 $4,000\n\u2022 1,000 \u0938\u0926\u0938\u094D\u092F \u2192 $10,000 \u2014 \u0905\u0902\u0924\u093F\u092E \u092E\u093E\u0907\u0932\u0938\u094D\u091F\u094B\u0928\n\u2022 \u092C\u094B\u0928\u0938 \u0930\u0947\u092B\u0930\u0932 \u0915\u092E\u0940\u0936\u0928 \u0914\u0930 \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u0930\u093F\u0935\u0949\u0930\u094D\u0921\u094D\u0938 \u0915\u0947 \u0905\u0924\u093F\u0930\u093F\u0915\u094D\u0924 \u0939\u0948\u0902\n\n\u{1F48E} \u0906\u092E\u0902\u0924\u094D\u0930\u093F\u0924 \u0915\u0930\u0947\u0902\u0964 \u0915\u092E\u093E\u090F\u0902\u0964 \u0926\u094B\u0939\u0930\u093E\u090F\u0902\u0964 \u092A\u0939\u0932\u0947 60 \u0926\u093F\u0928 \u0938\u0941\u0928\u0939\u0930\u0947 \u0939\u0948\u0902\u0964\n\n\u{1F310} turboloop.io",
