      original: "26_Smart_Contract_Challenge.png",
      headline: "\u{1F537} SMART CONTRACT CHALLENGE",
      caption: "\u{1F537} SMART CONTRACT CHALLENGE\n\u2726 $100,000 \u0907\u0928\u093E\u092E \u2014 \u0915\u094D\u092F\u093E \u0906\u092A \u0915\u094B\u0921 \u0924\u094B\u0921\u093C \u0938\u0915\u0924\u0947 \u0939\u0948\u0902?\n\nTurboLoop \u0905\u092A\u0928\u093E \u092A\u0948\u0938\u093E \u0935\u0939\u0940\u0902 \u0932\u0917\u093E\u0924\u093E \u0939\u0948 \u091C\u0939\u093E\u0901 \u0909\u0938\u0915\u093E \u0915\u094B\u0921 \u0939\u0948\u0964 Smart Contract Challenge \u0915\u093F\u0938\u0940 \u092D\u0940 \u0910\u0938\u0947 \u0935\u094D\u092F\u0915\u094D\u0924\u093F \u0915\u094B $100,000 \u0915\u093E \u0907\u0928\u093E\u092E \u0926\u0947\u0924\u093E \u0939\u0948 \u091C\u094B TurboLoop Smart Contract \u092E\u0947\u0902 \u0915\u094B\u0908 \u092D\u0947\u0926\u094D\u092F\u0924\u093E, \u0916\u093E\u092E\u0940 \u092F\u093E \u0926\u094B\u0937 \u0922\u0942\u0902\u0922 \u0938\u0915\u0947\u0964 \u092F\u0939 \u0915\u094B\u0908 \u092E\u093E\u0930\u094D\u0915\u0947\u091F\u093F\u0902\u0917 \u0928\u094C\u091F\u0902\u0915\u0940 \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u092F\u0939 \u092A\u094D\u0930\u094B\u091F\u094B\u0915\u0949\u0932 \u0915\u0947 \u0938\u0941\u0930\u0915\u094D\u0937\u093E \u0906\u0930\u094D\u0915\u093F\u091F\u0947\u0915\u094D\u091A\u0930 \u092E\u0947\u0902 \u0935\u093F\u0936\u094D\u0935\u093E\u0938 \u0915\u093E \u0905\u0902\u0924\u093F\u092E \u092A\u094D\u0930\u092E\u093E\u0923 \u0939\u0948\u0964 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0915\u093E \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0924\u094D\u092F\u093E\u0917 \u0926\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948 (\u090F\u0921\u092E\u093F\u0928 \u0915\u0941\u0902\u091C\u093F\u092F\u093E\u0901 \u091C\u0932\u093E \u0926\u0940 \u0917\u0908 \u0939\u0948\u0902), \u0932\u093F\u0915\u094D\u0935\u093F\u0921\u093F\u091F\u0940 \u092A\u0942\u0932 \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F \u0932\u0949\u0915 \u0939\u0948, \u0938\u094D\u0930\u094B\u0924 \u0915\u094B\u0921 BscScan \u092A\u0930 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0939\u0948, \u0914\u0930 \u090F\u0915 \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0911\u0921\u093F\u091F \u0928\u0947 99% \u091F\u094D\u0930\u0938\u094D\u091F \u0938\u094D\u0915\u094B\u0930 \u0926\u093F\u092F\u093E \u0939\u0948\u0964 \u0938\u0902\u092A\u0942\u0930\u094D\u0923 \u0935\u0948\u0936\u094D\u0935\u093F\u0915 \u0921\u0947\u0935\u0932\u092A\u0930 \u0938\u092E\u0941\u0926\u093E\u092F \u0915\u0947 \u0932\u093F\u090F \u0916\u0941\u0932\u0947 \u0939\u094B\u0928\u0947 \u0915\u0947 \u092C\u093E\u0935\u091C\u0942\u0926, \u0915\u093F\u0938\u0940 \u0928\u0947 \u092D\u0940 \u0907\u0928\u093E\u092E \u0915\u093E \u0926\u093E\u0935\u093E \u0928\u0939\u0940\u0902 \u0915\u093F\u092F\u093E \u0939\u0948\u0964 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0905\u091F\u0942\u091F, \u0938\u092E\u091D\u094C\u0924\u093E \u0930\u0939\u093F\u0924 \u0914\u0930 \u0905\u091C\u0947\u092F \u092C\u0928\u093E \u0939\u0941\u0906 \u0939\u0948 \u2014 \u092C\u093F\u0932\u094D\u0915\u0941\u0932 \u0935\u0948\u0938\u093E \u0939\u0940 \u091C\u0948\u0938\u093E \u0907\u0938\u0947 \u0921\u093F\u091C\u093C\u093E\u0907\u0928 \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u0925\u093E\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0906\u0915\u0930\u094D\u0937\u0923:\n\u2022 \u0907\u0928\u093E\u092E: \u0915\u093F\u0938\u0940 \u092D\u0940 \u092D\u0947\u0926\u094D\u092F\u0924\u093E \u092F\u093E \u0916\u093E\u092E\u0940 \u0915\u094B \u0916\u094B\u091C\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F $100,000\n\u2022 \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0924\u094D\u092F\u093E\u0917 \u0926\u093F\u092F\u093E \u0917\u092F\u093E \u2014 \u090F\u0921\u092E\u093F\u0928 \u0915\u0941\u0902\u091C\u093F\u092F\u093E\u0901 \u0938\u094D\u0925\u093E\u092F\u0940 \u0930\u0942\u092A \u0938\u0947 \u091C\u0932\u093E \u0926\u0940 \u0917\u0908\u0902\n\u2022 LP \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F \u0932\u0949\u0915 \u2014 \u0915\u094B\u0908 \u0930\u0917 \u092A\u0941\u0932 \u0924\u0902\u0924\u094D\u0930 \u092E\u094C\u091C\u0942\u0926 \u0928\u0939\u0940\u0902 \u0939\u0948\n\u2022 BscScan \u092A\u0930 \u0915\u094B\u0921 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u2014 \u092A\u0942\u0930\u0940 \u0924\u0930\u0939 \u0938\u0947 \u092A\u093E\u0930\u0926\u0930\u094D\u0936\u0940 \u0914\u0930 \u0911\u0921\u093F\u091F \u092F\u094B\u0917\u094D\u092F\n\u2022 \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0911\u0921\u093F\u091F: 99% \u091F\u094D\u0930\u0938\u094D\u091F \u0938\u094D\u0915\u094B\u0930 \u2014 \u0915\u094B\u0908 \u092D\u0940 \u0938\u092B\u0932 \u0928\u0939\u0940\u0902 \u0939\u0941\u0906 \u0939\u0948\n\n\u{1F48E} \u0915\u094D\u092F\u093E \u0906\u092A \u0907\u0938\u0947 \u0939\u0948\u0915 \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902? $100,000 \u0915\u0939\u0924\u093E \u0939\u0948 \u0915\u093F \u0906\u092A \u0928\u0939\u0940\u0902 \u0915\u0930 \u0938\u0915\u0924\u0947\u0964 \u0939\u092E\u0947\u0902 \u0917\u0932\u0924 \u0938\u093E\u092C\u093F\u0924 \u0915\u0930\u0947\u0902\u0964\n\n\u{1F310} turboloop.io",
