      headline: "\u{1F537} \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0924\u094D\u092F\u093E\u0917",
      caption: "\u{1F537} \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0924\u094D\u092F\u093E\u0917\n\u2726 \u090F\u0921\u092E\u093F\u0928 \u0915\u0940\u091C\u093C \u0928\u0937\u094D\u091F \u0915\u0930 \u0926\u0940 \u0917\u0908\u0902 \u2014 \u0915\u094B\u0908 \u092D\u0940 \u0907\u0902\u0938\u093E\u0928 \u0928\u093F\u092F\u092E \u0928\u0939\u0940\u0902 \u092C\u0926\u0932 \u0938\u0915\u0924\u093E\n\nSmart Contract \u0915\u0940 \u0926\u0941\u0928\u093F\u092F\u093E \u092E\u0947\u0902, '\u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0924\u094D\u092F\u093E\u0917' \u0935\u093F\u0915\u0947\u0902\u0926\u094D\u0930\u0940\u0915\u0930\u0923 \u0915\u093E \u0938\u0930\u094D\u0935\u094B\u091A\u094D\u091A \u092E\u093E\u0928\u0915 \u0939\u0948\u0964 TurboLoop \u0915\u093E \u0905\u0928\u0941\u092C\u0902\u0927 \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0938\u094D\u0925\u093E\u092F\u0940 \u0930\u0942\u092A \u0938\u0947 \u0921\u0947\u0921 \u090F\u0921\u094D\u0930\u0947\u0938 (0x000...dead) \u092A\u0930 \u0938\u094D\u0925\u093E\u0928\u093E\u0902\u0924\u0930\u093F\u0924 \u0915\u0930 \u0926\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948, \u091C\u093F\u0938\u0915\u093E \u0905\u0930\u094D\u0925 \u0939\u0948 \u0915\u093F \u0935\u0947 \u090F\u0921\u092E\u093F\u0928 \u0915\u0940\u091C\u093C \u091C\u094B \u0905\u0928\u0941\u092C\u0902\u0927 \u0915\u094B \u0938\u0902\u0936\u094B\u0927\u093F\u0924, \u0930\u094B\u0915 \u092F\u093E \u0909\u0938\u092E\u0947\u0902 \u0939\u0938\u094D\u0924\u0915\u094D\u0937\u0947\u092A \u0915\u0930 \u0938\u0915\u0924\u0940 \u0925\u0940\u0902, \u0909\u0928\u094D\u0939\u0947\u0902 \u0905\u092A\u0930\u093F\u0935\u0930\u094D\u0924\u0928\u0940\u092F \u0930\u0942\u092A \u0938\u0947 \u0928\u0937\u094D\u091F \u0915\u0930 \u0926\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948\u0964 \u0915\u094B\u0908 \u092C\u0948\u0915\u0921\u094B\u0930 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0915\u094B\u0908 \u0906\u092A\u093E\u0924\u0915\u093E\u0932\u0940\u0928 \u0915\u093E\u0930\u094D\u092F \u0928\u0939\u0940\u0902\u0964 \u0915\u094B\u0908 \u0930\u094B\u0915 \u0924\u0902\u0924\u094D\u0930 \u0928\u0939\u0940\u0902\u0964 \u0915\u094B\u0908 \u0905\u092A\u0917\u094D\u0930\u0947\u0921 \u092A\u0925 \u0928\u0939\u0940\u0902\u0964 \u0905\u0928\u0941\u092C\u0902\u0927 \u092C\u093F\u0932\u094D\u0915\u0941\u0932 \u0935\u0948\u0938\u093E \u0939\u0940 \u0928\u093F\u0937\u094D\u092A\u093E\u0926\u093F\u0924 \u0939\u094B\u0924\u093E \u0939\u0948 \u091C\u0948\u0938\u093E \u0932\u093F\u0916\u093E \u0917\u092F\u093E \u0939\u0948, \u0938\u094D\u0935\u093E\u092F\u0924\u094D\u0924 \u0930\u0942\u092A \u0938\u0947 \u0914\u0930 \u0905\u0928\u093F\u0936\u094D\u091A\u093F\u0924 \u0915\u093E\u0932 \u0924\u0915, \u092E\u093E\u0928\u0935\u0940\u092F \u0939\u0938\u094D\u0924\u0915\u094D\u0937\u0947\u092A \u0915\u0940 \u0915\u093F\u0938\u0940 \u092D\u0940 \u0938\u0902\u092D\u093E\u0935\u0928\u093E \u0915\u0947 \u092C\u093F\u0928\u093E\u0964 \u092F\u0939 \u0915\u094B\u0908 \u0905\u0938\u094D\u0925\u093E\u092F\u0940 \u0909\u092A\u093E\u092F \u092F\u093E \u0935\u093E\u0926\u093E \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u092F\u0939 \u090F\u0915 \u0938\u094D\u0925\u093E\u092F\u0940, \u0911\u0928-\u091A\u0947\u0928, \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u092F\u094B\u0917\u094D\u092F \u0924\u0925\u094D\u092F \u0939\u0948\u0964 \u090F\u0915 \u092C\u093E\u0930 \u0924\u094D\u092F\u093E\u0917 \u0926\u093F\u090F \u091C\u093E\u0928\u0947 \u0915\u0947 \u092C\u093E\u0926, \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0915\u094B \u0915\u092D\u0940 \u092D\u0940 \u0935\u093E\u092A\u0938 \u0928\u0939\u0940\u0902 \u0932\u093F\u092F\u093E \u091C\u093E \u0938\u0915\u0924\u093E \u0939\u0948\u0964 \u0915\u094B\u0921 \u0939\u0940 \u0915\u093E\u0928\u0942\u0928 \u0939\u0948, \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0906\u0915\u0930\u094D\u0937\u0923:\n\u2022 \u0938\u094D\u0935\u093E\u092E\u093F\u0924\u094D\u0935 \u0921\u0947\u0921 \u090F\u0921\u094D\u0930\u0947\u0938 \u092A\u0930 \u0938\u094D\u0925\u093E\u0928\u093E\u0902\u0924\u0930\u093F\u0924: 0x000...dead\n\u2022 \u090F\u0921\u092E\u093F\u0928 \u0915\u0940\u091C\u093C \u0938\u094D\u0925\u093E\u092F\u0940 \u0914\u0930 \u0905\u092A\u0930\u093F\u0935\u0930\u094D\u0924\u0928\u0940\u092F \u0930\u0942\u092A \u0938\u0947 \u0928\u0937\u094D\u091F \u0915\u0930 \u0926\u0940 \u0917\u0908\u0902\n\u2022 \u0915\u094B\u0908 \u092C\u0948\u0915\u0921\u094B\u0930 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0906\u092A\u093E\u0924\u0915\u093E\u0932\u0940\u0928 \u0915\u093E\u0930\u094D\u092F \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0930\u094B\u0915 \u0915\u094D\u0937\u092E\u0924\u093E \u0928\u0939\u0940\u0902\n\u2022 \u0905\u0928\u0941\u092C\u0902\u0927 \u0938\u094D\u0935\u093E\u092F\u0924\u094D\u0924 \u0930\u0942\u092A \u0938\u0947 \u0928\u093F\u0937\u094D\u092A\u093E\u0926\u093F\u0924 \u0939\u094B\u0924\u093E \u0939\u0948 \u2014 \u0915\u094B\u0908 \u092E\u093E\u0928\u0935\u0940\u092F \u0939\u0938\u094D\u0924\u0915\u094D\u0937\u0947\u092A \u0938\u0902\u092D\u0935 \u0928\u0939\u0940\u0902\n\u2022 BscScan \u092A\u0930 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u092F\u094B\u0917\u094D\u092F \u2014 \u0938\u094D\u0935\u092F\u0902 \u092E\u093E\u0932\u093F\u0915 \u0915\u093E \u092A\u0924\u093E \u091C\u093E\u0902\u091A\u0947\u0902\n\n\u{1F48E} \u0915\u094B\u0921 \u0939\u0940 \u0915\u093E\u0928\u0942\u0928 \u0939\u0948\u0964 \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F\u0964 \u0915\u094B\u0908 \u0905\u092A\u0935\u093E\u0926 \u0928\u0939\u0940\u0902\u0964 \u0915\u094B\u0908 \u0935\u093E\u092A\u0938\u0940 \u0928\u0939\u0940\u0902\u0964\n\n\u{1F310} turboloop.io",
