      original: "32_No_KYC.png",
      headline: "\u{1F537} \u0915\u094B\u0908 KYC \u0906\u0935\u0936\u094D\u092F\u0915 \u0928\u0939\u0940\u0902",
      caption: "\u{1F537} \u0915\u094B\u0908 KYC \u0906\u0935\u0936\u094D\u092F\u0915 \u0928\u0939\u0940\u0902\n\u2726 \u0906\u092A\u0915\u0940 \u0917\u094B\u092A\u0928\u0940\u092F\u0924\u093E, \u0938\u0941\u0930\u0915\u094D\u0937\u093F\u0924 \u2014 \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u0939\u0940 \u0906\u092A\u0915\u0940 \u092A\u0939\u091A\u093E\u0928 \u0939\u0948\n\nTurboLoop \u090F\u0915 \u092E\u094C\u0932\u093F\u0915 DeFi \u0938\u093F\u0926\u094D\u0927\u093E\u0902\u0924 \u092A\u0930 \u0915\u093E\u092E \u0915\u0930\u0924\u093E \u0939\u0948: \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u0939\u0940 \u0906\u092A\u0915\u0940 \u092A\u0939\u091A\u093E\u0928 \u0939\u0948\u0964 \u0915\u094B\u0908 KYC (Know Your Customer) \u092A\u094D\u0930\u0915\u094D\u0930\u093F\u092F\u093E \u0928\u0939\u0940\u0902 \u0939\u0948, \u0915\u094B\u0908 \u092A\u0939\u091A\u093E\u0928 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0926\u0938\u094D\u0924\u093E\u0935\u0947\u091C\u093C \u0905\u092A\u0932\u094B\u0921 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0938\u0947\u0932\u094D\u092B\u0940 \u0928\u0939\u0940\u0902, \u0915\u093F\u0938\u0940 \u092D\u0940 \u092A\u094D\u0930\u0915\u093E\u0930 \u0915\u093E \u0935\u094D\u092F\u0915\u094D\u0924\u093F\u0917\u0924 \u0921\u0947\u091F\u093E \u0938\u0902\u0917\u094D\u0930\u0939 \u0928\u0939\u0940\u0902\u0964 \u0906\u092A \u0905\u092A\u0928\u093E \u0935\u0949\u0932\u0947\u091F \u0915\u0928\u0947\u0915\u094D\u091F \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0906\u092A \u0905\u0902\u0926\u0930 \u0939\u0948\u0902\u0964 \u092F\u0939 \u0915\u0947\u0935\u0932 \u0938\u0941\u0935\u093F\u0927\u093E \u0915\u0947 \u092C\u093E\u0930\u0947 \u092E\u0947\u0902 \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u092F\u0939 \u0935\u093F\u0924\u094D\u0924\u0940\u092F \u0917\u094B\u092A\u0928\u0940\u092F\u0924\u093E \u0915\u0947 \u0906\u092A\u0915\u0947 \u092E\u094C\u0932\u093F\u0915 \u0905\u0927\u093F\u0915\u093E\u0930 \u0915\u0940 \u0930\u0915\u094D\u0937\u093E \u0915\u0930\u0928\u0947 \u0915\u0947 \u092C\u093E\u0930\u0947 \u092E\u0947\u0902 \u0939\u0948\u0964 \u0910\u0938\u0940 \u0926\u0941\u0928\u093F\u092F\u093E \u092E\u0947\u0902 \u091C\u0939\u093E\u0902 \u0921\u0947\u091F\u093E \u0909\u0932\u094D\u0932\u0902\u0918\u0928 \u0932\u093E\u0916\u094B\u0902 \u0909\u092A\u092F\u094B\u0917\u0915\u0930\u094D\u0924\u093E\u0913\u0902 \u0915\u0940 \u0935\u094D\u092F\u0915\u094D\u0924\u093F\u0917\u0924 \u091C\u093E\u0928\u0915\u093E\u0930\u0940 \u0915\u094B \u0909\u091C\u093E\u0917\u0930 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, TurboLoop \u0915\u0947 \u0936\u0942\u0928\u094D\u092F-\u0921\u0947\u091F\u093E \u0926\u0943\u0937\u094D\u091F\u093F\u0915\u094B\u0923 \u0915\u093E \u0905\u0930\u094D\u0925 \u0939\u0948 \u0915\u093F \u0909\u0932\u094D\u0932\u0902\u0918\u0928 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0915\u0941\u091B \u092D\u0940 \u0928\u0939\u0940\u0902 \u0939\u0948, \u0932\u0940\u0915 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0915\u0941\u091B \u092D\u0940 \u0928\u0939\u0940\u0902 \u0939\u0948, \u0938\u092E\u091D\u094C\u0924\u093E \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0915\u0941\u091B \u092D\u0940 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u092A\u0924\u093E \u091B\u0926\u094D\u092E \u0928\u093E\u092E \u0939\u0948, \u0906\u092A\u0915\u0947 \u0932\u0947\u0928\u0926\u0947\u0928 \u0911\u0928-\u091A\u0947\u0928 \u0939\u0948\u0902, \u0914\u0930 \u0906\u092A\u0915\u0940 \u092A\u0939\u091A\u093E\u0928 \u0915\u0947\u0935\u0932 \u0906\u092A\u0915\u0940 \u0930\u0939\u0924\u0940 \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0936\u0942\u0928\u094D\u092F KYC \u2014 \u0915\u093F\u0938\u0940 \u092D\u0940 \u092A\u094D\u0930\u0915\u093E\u0930 \u0915\u093E \u0915\u094B\u0908 \u092A\u0939\u091A\u093E\u0928 \u0938\u0924\u094D\u092F\u093E\u092A\u0928 \u0928\u0939\u0940\u0902\n\u2022 \u0915\u094B\u0908 \u0926\u0938\u094D\u0924\u093E\u0935\u0947\u091C\u093C \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u092B\u093C\u094B\u091F\u094B \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0935\u094D\u092F\u0915\u094D\u0924\u093F\u0917\u0924 \u0921\u0947\u091F\u093E \u090F\u0915\u0924\u094D\u0930 \u0928\u0939\u0940\u0902 \u0915\u093F\u092F\u093E \u0917\u092F\u093E\n\u2022 \u0905\u092A\u0928\u093E \u0935\u0949\u0932\u0947\u091F \u0915\u0928\u0947\u0915\u094D\u091F \u0915\u0930\u0947\u0902 \u0914\u0930 \u0924\u0941\u0930\u0902\u0924 \u0936\u0941\u0930\u0942 \u0915\u0930\u0947\u0902 \u2014 30 \u0938\u0947\u0915\u0902\u0921\n\u2022 \u0936\u0942\u0928\u094D\u092F-\u0921\u0947\u091F\u093E \u0926\u0943\u0937\u094D\u091F\u093F\u0915\u094B\u0923 \u2014 \u0909\u0932\u094D\u0932\u0902\u0918\u0928 \u092F\u093E \u0932\u0940\u0915 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0915\u0941\u091B \u092D\u0940 \u0928\u0939\u0940\u0902\n\u2022 \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u092A\u0924\u093E \u0906\u092A\u0915\u0940 \u091B\u0926\u094D\u092E \u092A\u0939\u091A\u093E\u0928 \u0939\u0948\n\n\u{1F48E} \u0906\u092A\u0915\u093E \u0935\u0949\u0932\u0947\u091F \u0939\u0940 \u0906\u092A\u0915\u0940 \u092A\u0939\u091A\u093E\u0928 \u0939\u0948\u0964 \u0906\u092A\u0915\u0940 \u0917\u094B\u092A\u0928\u0940\u092F\u0924\u093E \u092A\u0930 \u0915\u094B\u0908 \u0938\u092E\u091D\u094C\u0924\u093E \u0928\u0939\u0940\u0902\u0964\n\n\u{1F310} turboloop.io",
