      headline: "\u{1F537} \u0930\u0947\u092B\u0930\u0932 \u0928\u0947\u091F\u0935\u0930\u094D\u0915",
      caption: "\u{1F537} \u0930\u0947\u092B\u0930\u0932 \u0928\u0947\u091F\u0935\u0930\u094D\u0915\n\u2726 \u0905\u092A\u0928\u093E \u0932\u093F\u0902\u0915 \u0936\u0947\u092F\u0930 \u0915\u0930\u0947\u0902, 20 \u0932\u0947\u0935\u0932 \u0938\u0947 \u0915\u092E\u093E\u090F\u0902 \u2014 \u0905\u0938\u0940\u092E\u093F\u0924 \u091A\u094C\u0921\u093C\u093E\u0908\n\nTurboLoop \u0915\u093E \u0930\u0947\u092B\u0930\u0932 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0939\u0930 \u0938\u0926\u0938\u094D\u092F \u0915\u094B \u090F\u0915 \u0938\u0902\u092D\u093E\u0935\u093F\u0924 \u0906\u092F \u0915\u0947\u0902\u0926\u094D\u0930 \u092E\u0947\u0902 \u092C\u0926\u0932 \u0926\u0947\u0924\u093E \u0939\u0948\u0964 \u0905\u092A\u0928\u093E \u0905\u0928\u0942\u0920\u093E \u0930\u0947\u092B\u0930\u0932 \u0932\u093F\u0902\u0915 \u0936\u0947\u092F\u0930 \u0915\u0930\u0947\u0902, \u0914\u0930 \u091C\u092C \u0915\u094B\u0908 \u0907\u0938\u0915\u0947 \u092E\u093E\u0927\u094D\u092F\u092E \u0938\u0947 \u091C\u0941\u0921\u093C\u0924\u093E \u0939\u0948 \u0914\u0930 \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u0915\u0930\u0924\u093E \u0939\u0948, \u0924\u094B \u0906\u092A \u0909\u0928\u0915\u0947 \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u0915\u093E \u090F\u0915 \u092A\u094D\u0930\u0924\u093F\u0936\u0924 \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947, \u092A\u094D\u0930\u0924\u093F\u0926\u093F\u0928, Smart Contract \u0926\u094D\u0935\u093E\u0930\u093E \u092A\u094D\u0930\u094B\u0938\u0947\u0938 \u0915\u093F\u092F\u093E \u0917\u092F\u093E\u0964 \u0932\u0947\u0915\u093F\u0928 \u092F\u0939 \u0938\u0940\u0927\u0947 \u0930\u0947\u092B\u0930\u0932 \u092A\u0930 \u0928\u0939\u0940\u0902 \u0930\u0941\u0915\u0924\u093E\u0964 TurboLoop \u0915\u093E \u0928\u0947\u091F\u0935\u0930\u094D\u0915 20 \u0932\u0947\u0935\u0932 \u0917\u0939\u0930\u093E \u0939\u0948, \u091C\u093F\u0938\u0915\u093E \u0905\u0930\u094D\u0925 \u0939\u0948 \u0915\u093F \u0906\u092A \u0905\u092A\u0928\u0947 \u0930\u0947\u092B\u0930\u0932 \u0915\u0947 \u0930\u0947\u092B\u0930\u0932 \u0915\u0947 \u0930\u0947\u092B\u0930\u0932 \u0938\u0947 \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902 \u2014 \u092A\u0942\u0930\u0947 20\u0935\u0947\u0902 \u0932\u0947\u0935\u0932 \u0924\u0915\u0964 \u0938\u092D\u0940 \u0932\u0947\u0935\u0932 \u092E\u0947\u0902 \u0915\u0941\u0932 \u0935\u093F\u0924\u0930\u0923 51% \u0939\u0948, \u091C\u093F\u0938\u092E\u0947\u0902 \u0915\u093F\u0938\u0940 \u092D\u0940 \u0932\u0947\u0935\u0932 \u092A\u0930 \u091A\u094C\u0921\u093C\u093E\u0908 \u0915\u0940 \u0915\u094B\u0908 \u0938\u0940\u092E\u093E \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0906\u092A 10 \u0932\u094B\u0917\u094B\u0902 \u0915\u094B \u0930\u0947\u092B\u0930 \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902 \u092F\u093E 10,000 \u0915\u094B \u2014 Smart Contract \u0939\u0930 \u090F\u0915 \u0915\u0947 \u0932\u093F\u090F, \u0939\u0930 \u090F\u0915 \u0926\u093F\u0928, \u092C\u093F\u0928\u093E \u0915\u093F\u0938\u0940 \u091A\u0942\u0915 \u0915\u0947 \u0915\u092E\u0940\u0936\u0928 \u091F\u094D\u0930\u0948\u0915 \u0914\u0930 \u0935\u093F\u0924\u0930\u093F\u0924 \u0915\u0930\u0924\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 20 \u0932\u0947\u0935\u0932 \u0917\u0939\u0930\u093E \u2014 \u0905\u092A\u0928\u0947 \u092A\u0942\u0930\u0947 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0915\u0940 \u0917\u0924\u093F\u0935\u093F\u0927\u093F \u0938\u0947 \u0915\u092E\u093E\u090F\u0902\n\u2022 \u0938\u092D\u0940 20 \u0930\u0947\u092B\u0930\u0932 \u0932\u0947\u0935\u0932 \u092E\u0947\u0902 51% \u0915\u0941\u0932 \u0935\u093F\u0924\u0930\u0923\n\u2022 \u0905\u0938\u0940\u092E\u093F\u0924 \u091A\u094C\u0921\u093C\u093E\u0908 \u2014 \u0915\u093F\u0938\u0940 \u092D\u0940 \u0932\u0947\u0935\u0932 \u092A\u0930 \u0930\u0947\u092B\u0930\u0932 \u0915\u0940 \u0915\u094B\u0908 \u0938\u0940\u092E\u093E \u0928\u0939\u0940\u0902\n\u2022 Smart Contract \u0926\u094D\u0935\u093E\u0930\u093E \u092A\u094D\u0930\u094B\u0938\u0947\u0938 \u0915\u093F\u090F \u0917\u090F \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0926\u0948\u0928\u093F\u0915 \u092D\u0941\u0917\u0924\u093E\u0928\n\u2022 \u0906\u092A\u0915\u093E \u0905\u0928\u0942\u0920\u093E \u0930\u0947\u092B\u0930\u0932 \u0932\u093F\u0902\u0915 = \u0906\u092A\u0915\u093E \u092A\u0948\u0938\u093F\u0935 \u0907\u0928\u0915\u092E \u0907\u0902\u091C\u0928\n\n\u{1F48E} \u090F\u0915 \u0932\u093F\u0902\u0915\u0964 \u092C\u0940\u0938 \u0932\u0947\u0935\u0932\u0964 \u0905\u0938\u0940\u092E\u093F\u0924 \u0915\u094D\u0937\u092E\u0924\u093E\u0964 \u0936\u0947\u092F\u0930 \u0915\u0930\u0928\u093E \u0936\u0941\u0930\u0942 \u0915\u0930\u0947\u0902\u0964\n\n\u{1F310} turboloop.io",
