      caption: "\u{1F537} REFERRAL LEVELS 1-5\n\u2726 \u0906\u0927\u093E\u0930 \u2014 \u0906\u092A\u0915\u0947 \u0906\u0902\u0924\u0930\u093F\u0915 \u0938\u0930\u094D\u0915\u0932 \u092E\u0947\u0902 31% \u0935\u093F\u0924\u0930\u0923\n\nTurboLoop \u0915\u0947 \u0930\u0947\u092B\u0930\u0932 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0915\u0947 \u092A\u0939\u0932\u0947 \u092A\u093E\u0902\u091A \u0932\u0947\u0935\u0932 \u0906\u092A\u0915\u0940 \u0915\u092E\u093E\u0908 \u0915\u0940 \u0915\u094D\u0937\u092E\u0924\u093E \u0915\u093E \u0906\u0927\u093E\u0930 \u092C\u0928\u093E\u0924\u0947 \u0939\u0948\u0902, \u091C\u094B \u0906\u092A\u0915\u0947 \u0938\u092C\u0938\u0947 \u0915\u0930\u0940\u092C\u0940 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0915\u0928\u0947\u0915\u094D\u0936\u0928 \u092E\u0947\u0902 \u0915\u0941\u0932 31% \u0935\u093F\u0924\u0930\u093F\u0924 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 Level 1 \u2014 \u0906\u092A\u0915\u0947 \u0921\u093E\u092F\u0930\u0947\u0915\u094D\u091F \u0930\u0947\u092B\u0930\u0932 \u2014 \u0906\u092A\u0915\u094B \u0936\u093E\u0928\u0926\u093E\u0930 12% \u0915\u092E\u093E \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u091C\u094B \u092A\u0942\u0930\u0947 \u0938\u094D\u091F\u094D\u0930\u0915\u094D\u091A\u0930 \u092E\u0947\u0902 \u0938\u092C\u0938\u0947 \u0905\u0927\u093F\u0915 \u0938\u093F\u0902\u0917\u0932-\u0932\u0947\u0935\u0932 \u092A\u0947\u0906\u0909\u091F \u0939\u0948\u0964 Level 2 \u092A\u0930 \u092F\u0939 8% \u0939\u094B \u091C\u093E\u0924\u093E \u0939\u0948, \u091C\u094B \u0905\u092D\u0940 \u092D\u0940 \u0906\u092A\u0915\u0947 \u0930\u0947\u092B\u0930\u0932 \u0915\u0947 \u0930\u0947\u092B\u0930\u0932 \u092A\u0930 \u090F\u0915 \u092C\u0921\u093C\u093E \u0915\u092E\u0940\u0936\u0928 \u0939\u0948\u0964 Level 3 \u092A\u0930 5% \u092E\u093F\u0932\u0924\u093E \u0939\u0948, \u091C\u092C\u0915\u093F Level 4 \u0914\u0930 5 \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 3% \u0915\u093E \u092F\u094B\u0917\u0926\u093E\u0928 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u0905\u0915\u0947\u0932\u0947 \u092F\u0947 \u092A\u093E\u0902\u091A \u0932\u0947\u0935\u0932 \u0915\u0941\u0932 51% \u0930\u0947\u092B\u0930\u0932 \u0935\u093F\u0924\u0930\u0923 \u0915\u0947 \u0906\u0927\u0947 \u0938\u0947 \u0905\u0927\u093F\u0915 \u0939\u093F\u0938\u094D\u0938\u0947 \u0915\u093E \u092A\u094D\u0930\u0924\u093F\u0928\u093F\u0927\u093F\u0924\u094D\u0935 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u091C\u093F\u0938\u0938\u0947 \u0906\u092A\u0915\u0940 \u0921\u093E\u092F\u0930\u0947\u0915\u094D\u091F \u0906\u0909\u091F\u0930\u0940\u091A \u0914\u0930 \u092B\u0930\u094D\u0938\u094D\u091F-\u091C\u0947\u0928\u0930\u0947\u0936\u0928 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0906\u092A\u0915\u0940 \u0930\u0947\u092B\u0930\u0932 \u0930\u0923\u0928\u0940\u0924\u093F \u0915\u093E \u0938\u092C\u0938\u0947 \u092E\u0942\u0932\u094D\u092F\u0935\u093E\u0928 \u0939\u093F\u0938\u094D\u0938\u093E \u092C\u0928 \u091C\u093E\u0924\u093E \u0939\u0948\u0964 \u0936\u0940\u0930\u094D\u0937 \u092A\u0930 \u092E\u091C\u092C\u0942\u0924\u0940 \u0938\u0947 \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u0915\u0930\u0947\u0902, \u0914\u0930 \u0917\u0939\u0930\u093E\u0908 \u0905\u092A\u0928\u0947 \u0906\u092A \u0938\u0902\u092D\u0932 \u091C\u093E\u090F\u0917\u0940\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 Level 1 (\u0921\u093E\u092F\u0930\u0947\u0915\u094D\u091F): 12% \u2014 \u0938\u092C\u0938\u0947 \u0905\u0927\u093F\u0915 \u0938\u093F\u0902\u0917\u0932-\u0932\u0947\u0935\u0932 \u092A\u0947\u0906\u0909\u091F\n\u2022 Level 2: 8% \u2014 \u0938\u0947\u0915\u0902\u0921-\u091C\u0947\u0928\u0930\u0947\u0936\u0928 \u0938\u0947 \u092A\u0930\u094D\u092F\u093E\u092A\u094D\u0924 \u0915\u092E\u093E\u0908\n\u2022 Level 3: 5% \u2014 \u0925\u0930\u094D\u0921-\u091C\u0947\u0928\u0930\u0947\u0936\u0928 \u092A\u0930 \u092E\u093F\u0921-\u091F\u093F\u092F\u0930 \u0915\u092E\u0940\u0936\u0928\n\u2022 Levels 4-5: \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 3% \u2014 \u0907\u0928\u0930 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0938\u0947 \u0928\u093F\u0930\u0902\u0924\u0930 \u0915\u092E\u093E\u0908\n\u2022 \u0915\u0941\u0932 Levels 1-5: 31% \u2014 \u0915\u0941\u0932 51% \u0935\u093F\u0924\u0930\u0923 \u0915\u0947 \u0906\u0927\u0947 \u0938\u0947 \u0905\u0927\u093F\u0915\n\n\u{1F48E} \u092A\u0939\u0932\u0947 5 \u0932\u0947\u0935\u0932 = \u0906\u092A\u0915\u0940 \u0930\u0947\u092B\u0930\u0932 \u0915\u092E\u093E\u0908 \u0915\u093E 31%\u0964 \u092E\u091C\u092C\u0942\u0924\u0940 \u0938\u0947 \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u0915\u0930\u0947\u0902\u0964\n\n\u{1F310} turboloop.io",
