      original: "42_Compounding_Power.png",
      headline: "\u{1F537} \u091A\u0915\u094D\u0930\u0935\u0943\u0926\u094D\u0927\u093F \u0915\u0940 \u0936\u0915\u094D\u0924\u093F",
      caption: "\u{1F537} \u091A\u0915\u094D\u0930\u0935\u0943\u0926\u094D\u0927\u093F \u0915\u0940 \u0936\u0915\u094D\u0924\u093F\n\u2726 \u0906\u0907\u0902\u0938\u094D\u091F\u0940\u0928 \u0915\u093E \u0906\u0920\u0935\u093E\u0902 \u0905\u091C\u0942\u092C\u093E \u2014 DeFi \u092F\u0940\u0932\u094D\u0921 \u092A\u0930 \u0932\u093E\u0917\u0942\n\n\u0905\u0932\u094D\u092C\u0930\u094D\u091F \u0906\u0907\u0902\u0938\u094D\u091F\u0940\u0928 \u0928\u0947 \u0915\u0925\u093F\u0924 \u0924\u094C\u0930 \u092A\u0930 \u091A\u0915\u094D\u0930\u0935\u0943\u0926\u094D\u0927\u093F \u092C\u094D\u092F\u093E\u091C \u0915\u094B '\u0926\u0941\u0928\u093F\u092F\u093E \u0915\u093E \u0906\u0920\u0935\u093E\u0902 \u0905\u091C\u0942\u092C\u093E' \u0915\u0939\u093E \u0925\u093E, \u0914\u0930 TurboLoop \u0907\u0938 \u0905\u091C\u0942\u092C\u0947 \u0915\u094B \u0938\u092D\u0940 \u0915\u0947 \u0932\u093F\u090F \u0938\u0941\u0932\u092D \u092C\u0928\u093E\u0924\u093E \u0939\u0948\u0964 \u0938\u093F\u0926\u094D\u0927\u093E\u0902\u0924 \u0938\u0930\u0932 \u0939\u0948: \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u091A\u0915\u094D\u0930 \u0915\u0947 \u0905\u0902\u0924 \u092E\u0947\u0902 \u0905\u092A\u0928\u093E \u0930\u093F\u091F\u0930\u094D\u0928 \u0928\u093F\u0915\u093E\u0932\u0928\u0947 \u0915\u0947 \u092C\u091C\u093E\u092F, \u0909\u0928\u094D\u0939\u0947\u0902 \u090F\u0915 \u0928\u090F \u092A\u094D\u0932\u093E\u0928 \u092E\u0947\u0902 \u092A\u0941\u0928\u0930\u094D\u0928\u093F\u0935\u0947\u0936 \u0915\u0930\u0947\u0902\u0964 \u0906\u092A\u0915\u093E \u0905\u0917\u0932\u093E \u091A\u0915\u094D\u0930 \u090F\u0915 \u092C\u0921\u093C\u0947 \u0906\u0927\u093E\u0930 \u092A\u0930 \u0930\u093F\u091F\u0930\u094D\u0928 \u0905\u0930\u094D\u091C\u093F\u0924 \u0915\u0930\u0924\u093E \u0939\u0948, \u091C\u094B \u0914\u0930 \u092D\u0940 \u092C\u0921\u093C\u093E \u0930\u093F\u091F\u0930\u094D\u0928 \u0909\u0924\u094D\u092A\u0928\u094D\u0928 \u0915\u0930\u0924\u093E \u0939\u0948, \u091C\u094B \u092B\u093F\u0930 \u0938\u0947 \u091A\u0915\u094D\u0930\u0935\u0943\u0926\u094D\u0927\u093F \u0939\u094B\u0924\u093E \u0939\u0948\u0964 Power Loop (24%/30 \u0926\u093F\u0928) \u0915\u094B \u090F\u0915 \u0909\u0926\u093E\u0939\u0930\u0923 \u0915\u0947 \u0930\u0942\u092A \u092E\u0947\u0902 \u0932\u0947\u0924\u0947 \u0939\u0941\u090F: $1,000 \u092E\u0939\u0940\u0928\u0947 1 \u0915\u0947 \u092C\u093E\u0926 $1,240 \u0939\u094B \u091C\u093E\u0924\u093E \u0939\u0948\u0964 \u092A\u0941\u0928\u0930\u094D\u0928\u093F\u0935\u0947\u0936 \u0915\u0930\u0928\u0947 \u092A\u0930, \u092F\u0939 \u092E\u0939\u0940\u0928\u0947 3 \u0924\u0915 $1,907, \u092E\u0939\u0940\u0928\u0947 6 \u0924\u0915 $3,654, \u092E\u0939\u0940\u0928\u0947 9 \u0924\u0915 $7,003, \u0914\u0930 \u092E\u0939\u0940\u0928\u0947 12 \u0924\u0915 \u0909\u0932\u094D\u0932\u0947\u0916\u0928\u0940\u092F $13,220 \u0939\u094B \u091C\u093E\u0924\u093E \u0939\u0948\u0964 \u092F\u0939 \u090F\u0915 \u0939\u0940 \u092A\u094D\u0930\u093E\u0930\u0902\u092D\u093F\u0915 \u091C\u092E\u093E \u0938\u0947 \u090F\u0915 \u0935\u0930\u094D\u0937 \u092E\u0947\u0902 1,200% \u0938\u0947 \u0905\u0927\u093F\u0915 \u0915\u0940 \u0935\u0943\u0926\u094D\u0927\u093F \u0939\u0948\u0964 Smart Contract \u0906\u092A\u0915\u0940 \u091A\u0915\u094D\u0930\u0935\u0943\u0926\u094D\u0927\u093F \u0930\u0923\u0928\u0940\u0924\u093F \u0915\u094B \u0928\u0939\u0940\u0902 \u091C\u093E\u0928\u0924\u093E \u092F\u093E \u0909\u0938\u0915\u0940 \u092A\u0930\u0935\u093E\u0939 \u0928\u0939\u0940\u0902 \u0915\u0930\u0924\u093E \u2014 \u092F\u0939 \u0915\u0947\u0935\u0932 \u0917\u0923\u093F\u0924\u0940\u092F \u0938\u091F\u0940\u0915\u0924\u093E \u0915\u0947 \u0938\u093E\u0925 \u0906\u092A\u0915\u0947 \u0926\u094D\u0935\u093E\u0930\u093E \u091C\u092E\u093E \u0915\u0940 \u0917\u0908 \u0915\u093F\u0938\u0940 \u092D\u0940 \u0930\u093E\u0936\u093F \u092A\u0930 \u0930\u093F\u091F\u0930\u094D\u0928 \u0915\u0940 \u0917\u0923\u0928\u093E \u0915\u0930\u0924\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 $1,000 \u2192 $1,240 (\u092E\u0939\u0940\u0928\u093E 1) \u2192 $1,907 (\u092E\u0939\u0940\u0928\u093E 3)\n\u2022 $3,654 (\u092E\u0939\u0940\u0928\u093E 6) \u2192 $7,003 (\u092E\u0939\u0940\u0928\u093E 9) \u2192 $13,220 (\u092E\u0939\u0940\u0928\u093E 12)\n\u2022 \u0905\u0928\u0941\u0936\u093E\u0938\u093F\u0924 \u092A\u0941\u0928\u0930\u094D\u0928\u093F\u0935\u0947\u0936 \u0915\u0947 \u092E\u093E\u0927\u094D\u092F\u092E \u0938\u0947 12 \u092E\u0939\u0940\u0928\u094B\u0902 \u092E\u0947\u0902 1,200% \u0938\u0947 \u0905\u0927\u093F\u0915 \u0915\u0940 \u0935\u0943\u0926\u094D\u0927\u093F\n\u2022 \u0915\u093F\u0938\u0940 \u092D\u0940 \u091C\u092E\u093E \u0930\u093E\u0936\u093F \u0915\u0947 \u0938\u093E\u0925 \u0915\u093E\u092E \u0915\u0930\u0924\u093E \u0939\u0948 \u2014 \u0917\u0923\u093F\u0924 \u0906\u0928\u0941\u092A\u093E\u0924\u093F\u0915 \u0930\u0942\u092A \u0938\u0947 \u092C\u0922\u093C\u0924\u093E \u0939\u0948\n\u2022 Smart Contract \u0939\u0930 \u091A\u0915\u094D\u0930 \u092E\u0947\u0902 \u0938\u092E\u093E\u0928 \u0938\u091F\u0940\u0915\u0924\u093E \u0915\u0947 \u0938\u093E\u0925 \u0917\u0923\u0928\u093E \u0915\u0930\u0924\u093E \u0939\u0948\n\n\u{1F48E} \u0938\u092E\u092F \u0906\u092A\u0915\u0947 \u092A\u0948\u0938\u0947 \u0915\u094B \u0917\u0941\u0923\u093E \u0915\u0930\u0924\u093E \u0939\u0948\u0964 \u0906\u091C \u0939\u0940 \u091A\u0915\u094D\u0930\u0935\u0943\u0926\u094D\u0927\u093F \u0936\u0941\u0930\u0942 \u0915\u0930\u0947\u0902\u0964\n\n\u{1F310} turboloop.io",
