      headline: "\u{1F537} \u0906\u092F \u0915\u0947 \u0924\u0940\u0928 \u0938\u094D\u0930\u094B\u0924 \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924 \u091C\u093E\u0928\u0915\u093E\u0930\u0940",
      caption: "\u{1F537} \u0906\u092F \u0915\u0947 \u0924\u0940\u0928 \u0938\u094D\u0930\u094B\u0924 \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924 \u091C\u093E\u0928\u0915\u093E\u0930\u0940\n\u2726 Plan Yield + Referrals + Leadership = \u0938\u0902\u092A\u0942\u0930\u094D\u0923 \u0915\u092E\u093E\u0908 \u0915\u0940 \u092E\u0936\u0940\u0928\n\nTurboLoop \u0915\u093E \u0915\u092E\u093E\u0908 \u0915\u093E \u0922\u093E\u0902\u091A\u093E \u0924\u0940\u0928 \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0907\u0902\u091C\u0928\u094B\u0902 \u092A\u0930 \u092C\u0928\u093E \u0939\u0948 \u091C\u094B \u0906\u092A\u0915\u0940 \u0915\u0941\u0932 \u0906\u092F \u0915\u094B \u0905\u0927\u093F\u0915\u0924\u092E \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u090F\u0915 \u0938\u093E\u0925 \u0915\u093E\u092E \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u0907\u0902\u091C\u0928 1 \u2014 Plan Yield \u2014 \u0906\u092A\u0915\u0947 \u091A\u0941\u0928\u0947 \u0939\u0941\u090F \u092A\u094D\u0932\u093E\u0928 \u0915\u0947 \u0906\u0927\u093E\u0930 \u092A\u0930 3% \u0914\u0930 54% \u0915\u0947 \u092C\u0940\u091A \u0930\u093F\u091F\u0930\u094D\u0928 \u0926\u0947\u0924\u093E \u0939\u0948, \u091C\u093F\u0938\u0915\u0940 \u0917\u0923\u0928\u093E \u092A\u094D\u0930\u0924\u093F\u0926\u093F\u0928 \u0915\u0940 \u091C\u093E\u0924\u0940 \u0939\u0948 \u0914\u0930 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u091C\u094B\u0921\u093C \u0926\u0940 \u091C\u093E\u0924\u0940 \u0939\u0948\u0964 \u092F\u0939 \u0906\u092A\u0915\u0940 \u0906\u0927\u093E\u0930\u092D\u0942\u0924 \u0928\u093F\u0937\u094D\u0915\u094D\u0930\u093F\u092F \u0906\u092F \u0939\u0948\u0964 \u0907\u0902\u091C\u0928 2 \u2014 Referral Network \u2014 \u0906\u092A\u0915\u0947 \u0930\u0947\u092B\u0930\u0932 \u091F\u094D\u0930\u0940 \u0915\u0947 20 \u0938\u094D\u0924\u0930\u094B\u0902 \u092E\u0947\u0902 51% \u0935\u093F\u0924\u0930\u093F\u0924 \u0915\u0930\u0924\u093E \u0939\u0948, \u091C\u094B \u0906\u092A\u0915\u094B \u0906\u092A\u0915\u0947 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u092E\u0947\u0902 \u0915\u093F\u0938\u0940 \u0915\u0947 \u092D\u0940 \u0926\u094D\u0935\u093E\u0930\u093E \u0915\u093F\u090F \u0917\u090F \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u092A\u0930 \u0926\u0948\u0928\u093F\u0915 \u0915\u092E\u0940\u0936\u0928 \u0915\u093E \u092D\u0941\u0917\u0924\u093E\u0928 \u0915\u0930\u0924\u093E \u0939\u0948\u0964 \u092F\u0939 \u0906\u092A\u0915\u0940 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0906\u092F \u0939\u0948\u0964 \u0907\u0902\u091C\u0928 3 \u2014 Leadership Bonus \u2014 \u0906\u092A\u0915\u0940 \u0930\u0948\u0902\u0915 \u0915\u0947 \u0906\u0927\u093E\u0930 \u092A\u0930 1% \u0938\u0947 10% \u091C\u094B\u0921\u093C\u0924\u093E \u0939\u0948, \u091C\u094B \u0906\u092A\u0915\u0947 \u092A\u0942\u0930\u0947 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0915\u0940 \u0917\u0924\u093F\u0935\u093F\u0927\u093F \u092A\u0930 \u0932\u093E\u0917\u0942 \u0939\u094B\u0924\u093E \u0939\u0948\u0964 \u092F\u0939 \u0906\u092A\u0915\u0940 \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u0906\u092F \u0939\u0948\u0964 \u0924\u0940\u0928\u094B\u0902 \u0907\u0902\u091C\u0928 \u092A\u0942\u0930\u0940 \u0924\u0930\u0939 \u0938\u0947 \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0939\u0948\u0902 \u2014 \u0906\u092A \u090F\u0915, \u0926\u094B, \u092F\u093E \u0924\u0940\u0928\u094B\u0902 \u0938\u0947 \u090F\u0915 \u0938\u093E\u0925 \u0915\u092E\u093E \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964 \u0924\u0940\u0928\u094B\u0902 \u0915\u094B \u0938\u0915\u094D\u0930\u093F\u092F \u0915\u0930\u0928\u093E \u0939\u0940 \u0935\u0939 \u0924\u0930\u0940\u0915\u093E \u0939\u0948 \u091C\u093F\u0938\u0938\u0947 \u0936\u0940\u0930\u094D\u0937 \u0915\u092E\u093E\u0908 \u0915\u0930\u0928\u0947 \u0935\u093E\u0932\u0947 \u0905\u092A\u0928\u0947 TurboLoop \u0930\u093F\u091F\u0930\u094D\u0928 \u0915\u094B \u0905\u0927\u093F\u0915\u0924\u092E \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0907\u0902\u091C\u0928 1 \u2014 Plan Yield: 3%-54% \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0926\u0948\u0928\u093F\u0915 \u0930\u093F\u091F\u0930\u094D\u0928\n\u2022 \u0907\u0902\u091C\u0928 2 \u2014 Referral: 20 \u0938\u094D\u0924\u0930, 51% \u0935\u093F\u0924\u0930\u0923, \u0905\u0938\u0940\u092E\u093F\u0924 \u091A\u094C\u0921\u093C\u093E\u0908\n\u2022 \u0907\u0902\u091C\u0928 3 \u2014 Leadership: 7 \u0930\u0948\u0902\u0915, \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0917\u0924\u093F\u0935\u093F\u0927\u093F \u092A\u0930 1%-10% \u092C\u094B\u0928\u0938\n\u2022 \u0924\u0940\u0928\u094B\u0902 \u0907\u0902\u091C\u0928 \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0930\u0942\u092A \u0938\u0947 \u0914\u0930 \u090F\u0915 \u0938\u093E\u0925 \u0915\u093E\u092E \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\n\u2022 \u0936\u0940\u0930\u094D\u0937 \u0915\u092E\u093E\u0908 \u0915\u0930\u0928\u0947 \u0935\u093E\u0932\u0947 \u0905\u0927\u093F\u0915\u0924\u092E \u0915\u0941\u0932 \u0906\u092F \u0915\u0947 \u0932\u093F\u090F \u0924\u0940\u0928\u094B\u0902 \u0915\u094B \u0938\u0915\u094D\u0930\u093F\u092F \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\n\n\u{1F48E} \u0924\u0940\u0928 \u0907\u0902\u091C\u0928\u0964 \u0905\u0927\u093F\u0915\u0924\u092E \u0930\u093E\u091C\u0938\u094D\u0935\u0964 \u0909\u0928 \u0938\u092D\u0940 \u0915\u094B \u0938\u0915\u094D\u0930\u093F\u092F \u0915\u0930\u0947\u0902\u0964\n\n\u{1F310} turboloop.io",
