      original: "48_Onboarding_Variant.png",
      headline: "\u{1F537} ONBOARDING BONUS \u2014 DETAILED",
      caption: "\u{1F537} ONBOARDING BONUS \u2014 DETAILED\n\u2726 \u0930\u0948\u092A\u093F\u0921 \u092C\u093F\u0932\u094D\u0921\u0930\u094D\u0938 \u0915\u0947 \u0932\u093F\u090F \u092E\u093E\u0907\u0932\u0938\u094D\u091F\u094B\u0928 \u0930\u093F\u0935\u0949\u0930\u094D\u0921\u094D\u0938 \u2014 \u092A\u0942\u0930\u093E \u0935\u093F\u0935\u0930\u0923\n\nTurboLoop \u0915\u093E Onboarding Bonus \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E \u090F\u0915 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u092C\u093F\u0932\u094D\u0921\u0930 \u0915\u0947 \u0930\u0942\u092A \u092E\u0947\u0902 \u0906\u092A\u0915\u0947 \u092A\u0939\u0932\u0947 60 \u0926\u093F\u0928\u094B\u0902 \u0915\u094B \u0938\u0941\u092A\u0930\u091A\u093E\u0930\u094D\u091C \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0921\u093F\u091C\u093C\u093E\u0907\u0928 \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948\u0964 \u092F\u0939\u093E\u0901 \u092E\u093E\u0907\u0932\u0938\u094D\u091F\u094B\u0928 \u0914\u0930 \u0930\u093F\u0935\u0949\u0930\u094D\u0921\u094D\u0938 \u0915\u093E \u092A\u0942\u0930\u093E \u0935\u093F\u0935\u0930\u0923 \u0926\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948: \u091F\u093F\u092F\u0930 1: 60 \u0926\u093F\u0928\u094B\u0902 \u0915\u0947 \u092D\u0940\u0924\u0930 50 \u0928\u090F \u0938\u0926\u0938\u094D\u092F $50 \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u091F\u093F\u092F\u0930 2: 100 \u0938\u0926\u0938\u094D\u092F $200 \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u091F\u093F\u092F\u0930 3: 250 \u0938\u0926\u0938\u094D\u092F $750 \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u091F\u093F\u092F\u0930 4: 500 \u0938\u0926\u0938\u094D\u092F $2,000 \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u091F\u093F\u092F\u0930 5: 750 \u0938\u0926\u0938\u094D\u092F $4,000 \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u091F\u093F\u092F\u0930 6: 1,000 \u0938\u0926\u0938\u094D\u092F \u0905\u0927\u093F\u0915\u0924\u092E $10,000 \u092C\u094B\u0928\u0938 \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u092F\u0947 \u0930\u093F\u0935\u0949\u0930\u094D\u0921\u094D\u0938 \u0938\u0902\u091A\u092F\u0940 \u0939\u0948\u0902 \u0914\u0930 \u0906\u092A\u0915\u0947 \u0928\u093F\u092F\u092E\u093F\u0924 \u0930\u0947\u092B\u0930\u0932 \u0915\u092E\u0940\u0936\u0928 \u0914\u0930 \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u092C\u094B\u0928\u0938 \u0915\u0947 \u090A\u092A\u0930 \u092D\u0941\u0917\u0924\u093E\u0928 \u0915\u093F\u090F \u091C\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 60-\u0926\u093F\u0928 \u0915\u0940 \u0918\u0921\u093C\u0940 \u0906\u092A\u0915\u0947 \u092A\u0939\u0932\u0947 \u0938\u092B\u0932 \u0930\u0947\u092B\u0930\u0932 \u0938\u0947 \u0936\u0941\u0930\u0942 \u0939\u094B\u0924\u0940 \u0939\u0948, \u091C\u094B \u0906\u092A\u0915\u094B \u0905\u092A\u0928\u0940 \u0911\u0928\u092C\u094B\u0930\u094D\u0921\u093F\u0902\u0917 \u0915\u092E\u093E\u0908 \u0915\u094B \u0905\u0927\u093F\u0915\u0924\u092E \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u090F\u0915 \u0938\u094D\u092A\u0937\u094D\u091F \u0935\u093F\u0902\u0921\u094B \u0926\u0947\u0924\u0940 \u0939\u0948\u0964 \u0924\u0947\u091C\u0940 \u0938\u0947 \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u0915\u0930\u0947\u0902, \u092C\u0921\u093C\u093E \u0915\u092E\u093E\u090F\u0902\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0906\u0915\u0930\u094D\u0937\u0923:\n\u2022 \u091F\u093F\u092F\u0930 1: 50 \u0938\u0926\u0938\u094D\u092F \u2192 $50 | \u091F\u093F\u092F\u0930 2: 100 \u0938\u0926\u0938\u094D\u092F \u2192 $200\n\u2022 \u091F\u093F\u092F\u0930 3: 250 \u0938\u0926\u0938\u094D\u092F \u2192 $750 | \u091F\u093F\u092F\u0930 4: 500 \u0938\u0926\u0938\u094D\u092F \u2192 $2,000\n\u2022 \u091F\u093F\u092F\u0930 5: 750 \u0938\u0926\u0938\u094D\u092F \u2192 $4,000 | \u091F\u093F\u092F\u0930 6: 1,000 \u0938\u0926\u0938\u094D\u092F \u2192 $10,000\n\u2022 \u0938\u092D\u0940 \u091F\u093F\u092F\u0930 \u0928\u093F\u092F\u092E\u093F\u0924 \u0930\u0947\u092B\u0930\u0932 \u0914\u0930 \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u0915\u092E\u093E\u0908 \u0915\u0947 \u090A\u092A\u0930 \u092D\u0941\u0917\u0924\u093E\u0928 \u0915\u093F\u090F \u091C\u093E\u0924\u0947 \u0939\u0948\u0902\n\u2022 \u092A\u0939\u0932\u0947 \u0930\u0947\u092B\u0930\u0932 \u0938\u0947 60-\u0926\u093F\u0928 \u0915\u0940 \u0935\u093F\u0902\u0921\u094B \u2014 \u0924\u0947\u091C\u0940 \u0938\u0947 \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u0915\u0930\u0947\u0902, \u092C\u0921\u093C\u093E \u0915\u092E\u093E\u090F\u0902\n\n\u{1F48E} \u0928\u093F\u0930\u094D\u092E\u093E\u0923 \u0915\u0930\u0947\u0902\u0964 \u0915\u092E\u093E\u090F\u0902\u0964 \u0926\u094B\u0939\u0930\u093E\u090F\u0902\u0964 \u0906\u092A\u0915\u0947 \u092A\u0939\u0932\u0947 60 \u0926\u093F\u0928 \u0938\u092C\u0938\u0947 \u0905\u0927\u093F\u0915 \u092B\u093E\u092F\u0926\u0947\u092E\u0902\u0926 \u0939\u0948\u0902\u0964\n\n\u{1F310} turboloop.io",
