      headline: "\u{1F537} \u091C\u093C\u0942\u092E \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0930 \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924 \u091C\u093E\u0928\u0915\u093E\u0930\u0940",
      caption: "\u{1F537} \u091C\u093C\u0942\u092E \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0930 \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924 \u091C\u093E\u0928\u0915\u093E\u0930\u0940\n\u2726 \u090F\u0915 \u0906\u0927\u093F\u0915\u093E\u0930\u093F\u0915 \u090F\u0902\u092C\u0947\u0938\u0921\u0930 \u092C\u0928\u0947\u0902 \u2014 $100/\u092E\u0939\u0940\u0928\u093E \u0917\u093E\u0930\u0902\u091F\u0940\u0921\n\n\u091C\u093C\u0942\u092E \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0930 \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E TurboLoop \u0915\u0940 \u090F\u0902\u092C\u0947\u0938\u0921\u0930 \u092A\u0939\u0932 \u0939\u0948, \u091C\u094B \u0909\u0924\u094D\u0938\u093E\u0939\u0940 \u0915\u092E\u094D\u092F\u0941\u0928\u093F\u091F\u0940 \u0938\u0926\u0938\u094D\u092F\u094B\u0902 \u0915\u094B \u0936\u093F\u0915\u094D\u0937\u093F\u0924 \u0915\u0930\u0928\u0947 \u0914\u0930 \u0909\u0928\u0915\u0947 \u0938\u094D\u0925\u093E\u0928\u0940\u092F \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0915\u094B \u092C\u0922\u093C\u093E\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0938\u0936\u0915\u094D\u0924 \u092C\u0928\u093E\u0924\u0940 \u0939\u0948\u0964 \u092F\u0939 \u0907\u0938 \u092A\u094D\u0930\u0915\u093E\u0930 \u0915\u093E\u092E \u0915\u0930\u0924\u093E \u0939\u0948: \u0906\u0927\u093F\u0915\u093E\u0930\u093F\u0915 \u091A\u0948\u0928\u0932 \u0915\u0947 \u092E\u093E\u0927\u094D\u092F\u092E \u0938\u0947 \u0906\u0935\u0947\u0926\u0928 \u0915\u0930\u0947\u0902\u0964 \u090F\u0915 \u092C\u093E\u0930 \u0938\u094D\u0935\u0940\u0915\u093E\u0930 \u0915\u093F\u090F \u091C\u093E\u0928\u0947 \u0915\u0947 \u092C\u093E\u0926, \u0906\u092A\u0915\u094B \u092A\u0947\u0936\u0947\u0935\u0930 \u0930\u0942\u092A \u0938\u0947 \u0921\u093F\u091C\u093C\u093E\u0907\u0928 \u0915\u0940 \u0917\u0908 \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0947\u0936\u0928 \u0938\u093E\u092E\u0917\u094D\u0930\u0940 \u092A\u094D\u0930\u093E\u092A\u094D\u0924 \u0939\u094B\u0924\u0940 \u0939\u0948 \u091C\u093F\u0938\u092E\u0947\u0902 TurboLoop \u0915\u0947 \u0939\u0930 \u092A\u0939\u0932\u0942 \u2014 \u092A\u094D\u0932\u093E\u0928, \u0938\u0941\u0930\u0915\u094D\u0937\u093E, \u0930\u0947\u092B\u0930\u0932 \u0914\u0930 \u092C\u0939\u0941\u0924 \u0915\u0941\u091B \u0936\u093E\u092E\u093F\u0932 \u0939\u094B\u0924\u093E \u0939\u0948\u0964 \u0938\u091F\u0940\u0915\u0924\u093E \u0914\u0930 \u092A\u094D\u0930\u092D\u093E\u0935\u0936\u0940\u0932\u0924\u093E \u0938\u0941\u0928\u093F\u0936\u094D\u091A\u093F\u0924 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0906\u092A\u0915\u094B \u092E\u0941\u092B\u094D\u0924 \u092A\u094D\u0930\u0936\u093F\u0915\u094D\u0937\u0923 \u092D\u0940 \u092E\u093F\u0932\u0924\u093E \u0939\u0948\u0964 \u092B\u093F\u0930, \u0905\u092A\u0928\u0940 \u092A\u0938\u0902\u0926\u0940\u0926\u093E \u092D\u093E\u0937\u093E \u092E\u0947\u0902 \u0905\u092A\u0928\u0940 \u0938\u094D\u0925\u093E\u0928\u0940\u092F \u0915\u092E\u094D\u092F\u0941\u0928\u093F\u091F\u0940 \u0915\u0947 \u0932\u093F\u090F \u0928\u093F\u092F\u092E\u093F\u0924 \u091C\u093C\u0942\u092E \u0938\u0924\u094D\u0930 \u0906\u092F\u094B\u091C\u093F\u0924 \u0915\u0930\u0947\u0902\u0964 \u0907\u0938\u0915\u0947 \u092C\u0926\u0932\u0947 \u092E\u0947\u0902, \u0906\u092A \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0930 \u0938\u094D\u091F\u093E\u0907\u092A\u0947\u0902\u0921 \u0915\u0947 \u0930\u0942\u092A \u092E\u0947\u0902 \u0932\u0917\u093E\u0924\u093E\u0930 $100 \u092A\u094D\u0930\u0924\u093F \u092E\u093E\u0939 \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u092F\u0939 \u092A\u094D\u0930\u094B\u0917\u094D\u0930\u093E\u092E \u0926\u0941\u0928\u093F\u092F\u093E \u092D\u0930 \u0915\u0947 \u0938\u0926\u0938\u094D\u092F\u094B\u0902 \u0915\u0947 \u0932\u093F\u090F \u0916\u0941\u0932\u093E \u0939\u0948, \u0914\u0930 \u0906\u092A\u0915\u0947 \u0926\u094D\u0935\u093E\u0930\u093E \u0906\u092F\u094B\u091C\u093F\u0924 \u0915\u093F\u090F \u091C\u093E \u0938\u0915\u0928\u0947 \u0935\u093E\u0932\u0947 \u0938\u0924\u094D\u0930\u094B\u0902 \u0915\u0940 \u0938\u0902\u0916\u094D\u092F\u093E \u092A\u0930 \u0915\u094B\u0908 \u0938\u0940\u092E\u093E \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0906\u092A \u091C\u093F\u0924\u0928\u093E \u0905\u0927\u093F\u0915 \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F \u0915\u0930\u0947\u0902\u0917\u0947, \u0906\u092A\u0915\u093E \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0909\u0924\u0928\u093E \u0939\u0940 \u0905\u0927\u093F\u0915 \u092C\u0922\u093C\u0947\u0917\u093E \u2014 \u091C\u093F\u0938\u0938\u0947 \u0906\u092A\u0915\u0940 \u0930\u0947\u092B\u0930\u0932 \u0914\u0930 \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u0915\u092E\u093E\u0908 \u092E\u0947\u0902 \u0935\u0943\u0926\u094D\u0927\u093F \u0939\u094B\u0917\u0940\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u090F\u0915 \u0906\u0927\u093F\u0915\u093E\u0930\u093F\u0915 TurboLoop \u091C\u093C\u0942\u092E \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0930 \u092C\u0928\u0928\u0947 \u0915\u0947 \u0932\u093F\u090F \u0906\u0935\u0947\u0926\u0928 \u0915\u0930\u0947\u0902\n\u2022 \u092A\u0947\u0936\u0947\u0935\u0930 \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0947\u0936\u0928 \u0938\u093E\u092E\u0917\u094D\u0930\u0940 \u0914\u0930 \u092E\u0941\u092B\u094D\u0924 \u092A\u094D\u0930\u0936\u093F\u0915\u094D\u0937\u0923 \u092A\u094D\u0930\u093E\u092A\u094D\u0924 \u0915\u0930\u0947\u0902\n\u2022 \u0905\u092A\u0928\u0940 \u092D\u093E\u0937\u093E \u0914\u0930 \u0915\u092E\u094D\u092F\u0941\u0928\u093F\u091F\u0940 \u092E\u0947\u0902 \u0928\u093F\u092F\u092E\u093F\u0924 \u091C\u093C\u0942\u092E \u0938\u0924\u094D\u0930 \u0906\u092F\u094B\u091C\u093F\u0924 \u0915\u0930\u0947\u0902\n\u2022 $100/\u092E\u0939\u0940\u0928\u093E \u0917\u093E\u0930\u0902\u091F\u0940\u0921 \u092A\u094D\u0930\u0947\u091C\u0947\u0902\u091F\u0930 \u0938\u094D\u091F\u093E\u0907\u092A\u0947\u0902\u0921 \u0915\u092E\u093E\u090F\u0902\n\u2022 \u0905\u092A\u0928\u0947 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0915\u094B \u0935\u094D\u092F\u0935\u0938\u094D\u0925\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u092C\u0922\u093C\u093E\u090F\u0902 \u2014 \u0930\u0947\u092B\u0930\u0932 \u0915\u092E\u093E\u0908 \u092E\u0947\u0902 \u0935\u0943\u0926\u094D\u0927\u093F \u0915\u0930\u0947\u0902\n\n\u{1F48E} \u0938\u093F\u0916\u093E\u090F\u0902\u0964 \u092A\u094D\u0930\u0947\u0930\u093F\u0924 \u0915\u0930\u0947\u0902\u0964 \u0915\u092E\u093E\u090F\u0902\u0964 \u0926\u0941\u0928\u093F\u092F\u093E \u0915\u094B TurboLoop \u090F\u0902\u092C\u0947\u0938\u0921\u0930\u094B\u0902 \u0915\u0940 \u091C\u0930\u0942\u0930\u0924 \u0939\u0948\u0964\n\n\u{1F310} turboloop.io",
