      headline: "\u{1F537} \u0938\u094D\u092E\u093E\u0930\u094D\u091F \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u091A\u0948\u0932\u0947\u0902\u091C \u2014 \u0938\u0902\u0938\u094D\u0915\u0930\u0923",
      caption: "\u{1F537} \u0938\u094D\u092E\u093E\u0930\u094D\u091F \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u091A\u0948\u0932\u0947\u0902\u091C \u2014 \u0938\u0902\u0938\u094D\u0915\u0930\u0923  \n\u2726 $100,000 \u0915\u093E \u092A\u094D\u0930\u0942\u092B \u0911\u092B\u093C \u0938\u093F\u0915\u094D\u092F\u094B\u0930\u093F\u091F\u0940 \u2014 \u0905\u092D\u0940 \u0924\u0915 \u0905\u0928\u0905\u0927\u093F\u0915\u093E\u0930\u093F\u0924\n\nTurboLoop \u0938\u094D\u092E\u093E\u0930\u094D\u091F \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u091A\u0948\u0932\u0947\u0902\u091C DeFi \u092E\u0947\u0902 \u092A\u094D\u0930\u094B\u091F\u094B\u0915\u0949\u0932 \u0938\u093F\u0915\u094D\u092F\u094B\u0930\u093F\u091F\u0940 \u0915\u093E \u0938\u092C\u0938\u0947 \u0936\u0915\u094D\u0924\u093F\u0936\u093E\u0932\u0940 \u092A\u094D\u0930\u0926\u0930\u094D\u0936\u0928 \u0939\u0948\u0964 $100,000 \u0915\u093E \u0907\u0928\u093E\u092E \u0915\u093F\u0938\u0940 \u092D\u0940 \u0910\u0938\u0947 \u0935\u094D\u092F\u0915\u094D\u0924\u093F \u0915\u0947 \u0932\u093F\u090F \u0909\u092A\u0932\u092C\u094D\u0927 \u0939\u0948 \u091C\u094B \u0938\u094D\u092E\u093E\u0930\u094D\u091F \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0915\u094B\u0921 \u092E\u0947\u0902 \u0915\u094B\u0908 \u0915\u092E\u0940, \u0936\u094B\u0937\u0923 \u092F\u093E \u0926\u094B\u0937 \u092A\u0939\u091A\u093E\u0928 \u0938\u0915\u0947\u0964 \u0932\u0949\u0928\u094D\u091A \u0915\u0947 \u092C\u093E\u0926 \u0938\u0947, \u092F\u0939 \u091A\u0948\u0932\u0947\u0902\u091C \u0939\u0930 \u0921\u0947\u0935\u0932\u092A\u0930, \u0939\u0948\u0915\u0930 \u0914\u0930 \u0938\u0941\u0930\u0915\u094D\u0937\u093E \u0936\u094B\u0927\u0915\u0930\u094D\u0924\u093E \u0915\u0947 \u0932\u093F\u090F \u0916\u0941\u0932\u093E \u0939\u0948 \u2014 \u0914\u0930 \u0905\u092D\u0940 \u0924\u0915 \u0915\u093F\u0938\u0940 \u0928\u0947 \u092D\u0940 \u092F\u0939 \u0907\u0928\u093E\u092E \u0928\u0939\u0940\u0902 \u0932\u093F\u092F\u093E \u0939\u0948\u0964 \u0907\u0938\u0915\u093E \u0915\u093E\u0930\u0923 \u0938\u0930\u0932 \u0939\u0948: \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0907\u0938 \u0924\u0930\u0939 \u092C\u0928\u093E\u092F\u093E \u0917\u092F\u093E \u0939\u0948 \u0915\u093F \u0907\u0938\u0947 \u0924\u094B\u0921\u093C\u093E \u0928 \u091C\u093E \u0938\u0915\u0947\u0964 \u0913\u0928\u0930\u0936\u093F\u092A \u0915\u094B \u0930\u0940\u0928\u093E\u0909\u0902\u0938 \u0915\u093F\u092F\u093E \u0917\u092F\u093E\u0964 LP \u0915\u094B \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F \u0932\u0949\u0915 \u0915\u093F\u092F\u093E \u0917\u092F\u093E\u0964 \u0915\u094B\u0921 BscScan \u092A\u0930 \u0935\u0947\u0930\u0940\u092B\u093E\u0907\u0921\u0964 \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0911\u0921\u093F\u091F: 99% \u091F\u094D\u0930\u0938\u094D\u091F \u0938\u094D\u0915\u094B\u0930\u0964 \u0939\u0930 \u0938\u0902\u092D\u0935 \u0939\u092E\u0932\u0947 \u0915\u0947 \u0930\u093E\u0938\u094D\u0924\u0947 \u0921\u093F\u091C\u093C\u093E\u0907\u0928 \u0915\u0947 \u0905\u0928\u0941\u0938\u093E\u0930 \u0916\u0924\u094D\u092E \u0915\u0930 \u0926\u093F\u090F \u0917\u090F \u0939\u0948\u0902\u0964 $100,000 \u0905\u0928\u0905\u0927\u093F\u0915\u093E\u0930\u093F\u0924 \u0907\u0938\u0932\u093F\u090F \u0939\u0948 \u0915\u094D\u092F\u094B\u0902\u0915\u093F \u0915\u093F\u0938\u0940 \u0928\u0947 \u0915\u094B\u0936\u093F\u0936 \u0928\u0939\u0940\u0902 \u0915\u0940, \u092C\u0932\u094D\u0915\u093F \u0907\u0938 \u0915\u094B\u0921 \u0928\u0947 \u0935\u093E\u0938\u094D\u0924\u0935 \u092E\u0947\u0902 \u092C\u0941\u0932\u0947\u091F\u092A\u094D\u0930\u0942\u092B \u0938\u093E\u092C\u093F\u0924 \u0915\u093F\u092F\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0906\u0915\u0930\u094D\u0937\u0923:  \n\u2022 \u0907\u0928\u093E\u092E: $100,000 \u2014 \u0938\u092D\u0940 \u0915\u0947 \u0932\u093F\u090F \u0916\u0941\u0932\u093E, \u0905\u092D\u0940 \u0924\u0915 \u0905\u0928\u0905\u0927\u093F\u0915\u093E\u0930\u093F\u0924  \n\u2022 \u0913\u0928\u0930\u0936\u093F\u092A \u0930\u0940\u0928\u093E\u0909\u0902\u0938 \u2014 \u0915\u094B\u0908 \u090F\u0921\u092E\u093F\u0928 \u0936\u094B\u0937\u0923 \u0938\u0902\u092D\u0935 \u0928\u0939\u0940\u0902  \n\u2022 LP \u0939\u092E\u0947\u0936\u093E \u0915\u0947 \u0932\u093F\u090F \u0932\u0949\u0915 \u2014 \u0915\u094B\u0908 \u0932\u093F\u0915\u094D\u0935\u093F\u0921\u093F\u091F\u0940 \u0921\u094D\u0930\u0947\u0928 \u0938\u0902\u092D\u0935 \u0928\u0939\u0940\u0902  \n\u2022 \u0915\u094B\u0921 \u0935\u0947\u0930\u0940\u092B\u093E\u0907\u0921 \u2014 \u0936\u094B\u0937\u0923 \u0915\u0947 \u0932\u093F\u090F \u0915\u094B\u0908 \u091B\u093F\u092A\u0940 \u0939\u0941\u0908 \u092B\u0902\u0915\u094D\u0936\u0928 \u0928\u0939\u0940\u0902  \n\u2022 99% \u0911\u0921\u093F\u091F \u0938\u094D\u0915\u094B\u0930 \u2014 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0935\u093E\u0938\u094D\u0924\u0935 \u092E\u0947\u0902 \u092C\u0941\u0932\u0947\u091F\u092A\u094D\u0930\u0942\u092B \u0939\u0948  \n\n\u{1F48E} \u092F\u0939 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0905\u0924\u0942\u091F \u0939\u0948\u0964 $100,000 \u0907\u0938\u0915\u093E \u092A\u094D\u0930\u092E\u093E\u0923 \u0939\u0948\u0964\n\n\u{1F310} turboloop.io",
