      original: "58_Verified_Code_Detail.png",
      headline: "\u{1F537} \u0915\u094B\u0921 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924",
      caption: "\u{1F537} \u0915\u094B\u0921 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924\n\u2726 \u0906\u092A\u0915\u0947 \u0932\u093F\u090F \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0938\u094B\u0930\u094D\u0938 \u0915\u094B\u0921 \u0915\u093E \u0915\u094D\u092F\u093E \u0905\u0930\u094D\u0925 \u0939\u0948\n\n\u091C\u092C \u0939\u092E \u0915\u0939\u0924\u0947 \u0939\u0948\u0902 \u0915\u093F TurboLoop \u0915\u093E \u0915\u094B\u0921 'BscScan \u092A\u0930 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924' \u0939\u0948, \u0924\u094B \u0907\u0938\u0915\u093E \u0920\u0940\u0915 \u092F\u0939\u0940 \u092E\u0924\u0932\u092C \u0939\u0948: \u0938\u094D\u092E\u093E\u0930\u094D\u091F \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0915\u093E \u092A\u0942\u0930\u093E \u0938\u0949\u0932\u093F\u0921\u093F\u091F\u0940 \u0938\u094B\u0930\u094D\u0938 \u0915\u094B\u0921 BscScan \u2014 Binance Smart Chain \u0915\u0947 \u0906\u0927\u093F\u0915\u093E\u0930\u093F\u0915 \u092C\u094D\u0932\u0949\u0915 \u090F\u0915\u094D\u0938\u092A\u094D\u0932\u094B\u0930\u0930 \u2014 \u0915\u094B \u0938\u092C\u092E\u093F\u091F \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u0939\u0948 \u0914\u0930 \u0909\u0938\u0915\u0947 \u0926\u094D\u0935\u093E\u0930\u093E \u092A\u0941\u0937\u094D\u091F\u093F \u0915\u0940 \u0917\u0908 \u0939\u0948\u0964 BscScan \u0928\u0947 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0915\u093F\u092F\u093E \u0939\u0948 \u0915\u093F \u0921\u093F\u092A\u094D\u0932\u0949\u092F \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u092C\u093E\u0907\u091F\u0915\u094B\u0921 \u0938\u092C\u092E\u093F\u091F \u0915\u093F\u090F \u0917\u090F \u0938\u094B\u0930\u094D\u0938 \u0915\u094B\u0921 \u0938\u0947 \u092C\u093F\u0932\u094D\u0915\u0941\u0932 \u092E\u0947\u0932 \u0916\u093E\u0924\u093E \u0939\u0948, \u091C\u093F\u0938\u0915\u093E \u0905\u0930\u094D\u0925 \u0939\u0948 \u0915\u093F \u0906\u092A \u091C\u094B \u092A\u0922\u093C\u0924\u0947 \u0939\u0948\u0902 \u0935\u0939\u0940 \u0928\u093F\u0937\u094D\u092A\u093E\u0926\u093F\u0924 \u0939\u094B\u0924\u093E \u0939\u0948\u0964 \u0915\u094B\u0908 \u092D\u0940 BscScan \u092A\u0930 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u090F\u0921\u094D\u0930\u0947\u0938 \u092A\u0930 \u091C\u093E \u0938\u0915\u0924\u093E \u0939\u0948, 'Contract' \u092A\u0930 \u0915\u094D\u0932\u093F\u0915 \u0915\u0930 \u0938\u0915\u0924\u093E \u0939\u0948, \u092B\u093F\u0930 'Read Contract' \u092F\u093E 'Code' \u092A\u0930 \u0915\u094D\u0932\u093F\u0915 \u0915\u0930 \u0938\u0915\u0924\u093E \u0939\u0948, \u0914\u0930 \u0939\u0930 \u092B\u093C\u0902\u0915\u094D\u0936\u0928, \u0939\u0930 \u0935\u0947\u0930\u093F\u090F\u092C\u0932, \u0932\u0949\u091C\u093F\u0915 \u0915\u0940 \u0939\u0930 \u0932\u093E\u0907\u0928 \u0915\u0940 \u091C\u093E\u0902\u091A \u0915\u0930 \u0938\u0915\u0924\u093E \u0939\u0948\u0964 \u0915\u094B\u0908 \u091B\u093F\u092A\u0947 \u0939\u0941\u090F \u092B\u093C\u0902\u0915\u094D\u0936\u0928 \u0928\u0939\u0940\u0902 \u0939\u0948\u0902, \u0915\u094B\u0908 \u092A\u094D\u0930\u0949\u0915\u094D\u0938\u0940 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0928\u0939\u0940\u0902 \u0939\u0948\u0902 \u091C\u094B \u0905\u0938\u0932\u0940 \u0915\u094B\u0921 \u0915\u094B \u091B\u093F\u092A\u093E\u0924\u0947 \u0939\u094B\u0902, \u0915\u094B\u0908 \u0905\u0938\u094D\u092A\u0937\u094D\u091F\u0924\u093E \u0924\u0915\u0928\u0940\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092A\u093E\u0930\u0926\u0930\u094D\u0936\u093F\u0924\u093E \u0915\u093E \u092F\u0939 \u0938\u094D\u0924\u0930 \u0921\u0947\u0935\u0932\u092A\u0930\u094D\u0938, \u0911\u0921\u093F\u091F\u0930\u094D\u0938 \u0914\u0930 \u0909\u092A\u092F\u094B\u0917\u0915\u0930\u094D\u0924\u093E\u0913\u0902 \u0915\u094B \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0930\u0942\u092A \u0938\u0947 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0915\u0930\u0928\u0947 \u0915\u0940 \u0905\u0928\u0941\u092E\u0924\u093F \u0926\u0947\u0924\u093E \u0939\u0948 \u0915\u093F TurboLoop \u092C\u093F\u0932\u094D\u0915\u0941\u0932 \u0935\u093F\u091C\u094D\u091E\u093E\u092A\u093F\u0924 \u0915\u0947 \u0930\u0942\u092A \u092E\u0947\u0902 \u0915\u093E\u092E \u0915\u0930\u0924\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 \u0938\u094B\u0930\u094D\u0938 \u0915\u094B\u0921 \u0906\u0927\u093F\u0915\u093E\u0930\u093F\u0915 \u0924\u094C\u0930 \u092A\u0930 BscScan \u0915\u094B \u0938\u092C\u092E\u093F\u091F \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u0914\u0930 \u0909\u0938\u0915\u0947 \u0926\u094D\u0935\u093E\u0930\u093E \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0915\u093F\u092F\u093E \u0917\u092F\u093E\n\u2022 \u0921\u093F\u092A\u094D\u0932\u0949\u092F \u0915\u093F\u092F\u093E \u0917\u092F\u093E \u092C\u093E\u0907\u091F\u0915\u094B\u0921 \u0938\u094B\u0930\u094D\u0938 \u0915\u094B\u0921 \u0938\u0947 \u092C\u093F\u0932\u094D\u0915\u0941\u0932 \u092E\u0947\u0932 \u0916\u093E\u0924\u093E \u0939\u0948 \u2014 \u092A\u0941\u0937\u094D\u091F\u093F \u0915\u0940 \u0917\u0908\n\u2022 \u0939\u0930 \u092B\u093C\u0902\u0915\u094D\u0936\u0928, \u0935\u0947\u0930\u093F\u090F\u092C\u0932 \u0914\u0930 \u0932\u0949\u091C\u093F\u0915 \u0932\u093E\u0907\u0928 \u0938\u093E\u0930\u094D\u0935\u091C\u0928\u093F\u0915 \u0930\u0942\u092A \u0938\u0947 \u092A\u0922\u093C\u0928\u0947 \u092F\u094B\u0917\u094D\u092F \u0939\u0948\n\u2022 \u0915\u094B\u0908 \u091B\u093F\u092A\u0947 \u0939\u0941\u090F \u092B\u093C\u0902\u0915\u094D\u0936\u0928 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u092A\u094D\u0930\u0949\u0915\u094D\u0938\u0940 \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0905\u0938\u094D\u092A\u0937\u094D\u091F\u0924\u093E \u0928\u0939\u0940\u0902\n\u2022 \u0915\u094B\u0908 \u092D\u0940 \u0938\u094D\u0935\u0924\u0902\u0924\u094D\u0930 \u0930\u0942\u092A \u0938\u0947 \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0915\u0930 \u0938\u0915\u0924\u093E \u0939\u0948 \u0915\u093F \u0915\u0949\u0928\u094D\u091F\u094D\u0930\u0948\u0915\u094D\u091F \u0935\u093F\u091C\u094D\u091E\u093E\u092A\u093F\u0924 \u0915\u0947 \u0930\u0942\u092A \u092E\u0947\u0902 \u0915\u093E\u092E \u0915\u0930\u0924\u093E \u0939\u0948\n\n\u{1F48E} \u0915\u094B\u0921 \u092A\u0922\u093C\u0947\u0902\u0964 \u0932\u0949\u091C\u093F\u0915 \u0915\u094B \u0938\u0924\u094D\u092F\u093E\u092A\u093F\u0924 \u0915\u0930\u0947\u0902\u0964 \u0936\u092C\u094D\u0926\u094B\u0902 \u092A\u0930 \u0928\u0939\u0940\u0902, \u0917\u0923\u093F\u0924 \u092A\u0930 \u092D\u0930\u094B\u0938\u093E \u0915\u0930\u0947\u0902\u0964\n\n\u{1F310} turboloop.io",
