      headline: "\u{1F537} \u0930\u0947\u092B\u0930\u0932 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924",
      caption: "\u{1F537} \u0930\u0947\u092B\u0930\u0932 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u2014 \u0935\u093F\u0938\u094D\u0924\u0943\u0924\n\u2726 20-Level \u0915\u092E\u093E\u0908 \u0915\u093E \u0938\u0902\u092A\u0942\u0930\u094D\u0923 \u0906\u0930\u094D\u0915\u093F\u091F\u0947\u0915\u094D\u091A\u0930\n\nTurboLoop \u0915\u093E \u0930\u0947\u092B\u0930\u0932 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u090F\u0915 20-level \u0917\u0939\u0930\u093E, \u0905\u0938\u0940\u092E\u093F\u0924-\u091A\u094C\u0921\u093C\u093E\u0908 \u0935\u093E\u0932\u093E \u0905\u0930\u094D\u0928\u093F\u0902\u0917 \u0938\u094D\u091F\u094D\u0930\u0915\u094D\u091A\u0930 \u0939\u0948 \u091C\u094B \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u092C\u093F\u0932\u094D\u0921\u0930\u094D\u0938 \u0915\u094B \u0930\u0947\u092B\u0930\u094D\u0921 \u0921\u093F\u092A\u0949\u091C\u093F\u091F\u094D\u0938 \u0915\u093E 51% \u0935\u093F\u0924\u0930\u093F\u0924 \u0915\u0930\u0924\u093E \u0939\u0948\u0964 \u092F\u0939\u093E\u0901 \u0938\u0902\u092A\u0942\u0930\u094D\u0923 \u0906\u0930\u094D\u0915\u093F\u091F\u0947\u0915\u094D\u091A\u0930 \u0939\u0948: \u091C\u092C \u0906\u092A \u0905\u092A\u0928\u093E \u0935\u0949\u0932\u0947\u091F \u0915\u0928\u0947\u0915\u094D\u091F \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u0924\u094B \u0906\u092A\u0915\u093E \u092F\u0942\u0928\u093F\u0915 \u0930\u0947\u092B\u0930\u0932 \u0932\u093F\u0902\u0915 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0930\u0942\u092A \u0938\u0947 \u091C\u0928\u0930\u0947\u091F \u0939\u094B\u0924\u093E \u0939\u0948\u0964 \u091C\u092C \u0915\u094B\u0908 \u0906\u092A\u0915\u0947 \u0932\u093F\u0902\u0915 \u0915\u0947 \u092E\u093E\u0927\u094D\u092F\u092E \u0938\u0947 \u091C\u0941\u0921\u093C\u0924\u093E \u0939\u0948 \u0914\u0930 \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u0915\u0930\u0924\u093E \u0939\u0948, \u0924\u094B \u0906\u092A \u0909\u0928\u0915\u0947 \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u092A\u0930 Level 1 \u0915\u092E\u0940\u0936\u0928 (12%) \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u091C\u092C \u0935\u0947 \u0915\u093F\u0938\u0940 \u0915\u094B \u0930\u0947\u092B\u0930 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0924\u094B \u0906\u092A Level 2 (8%) \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u092F\u0939 \u0938\u092D\u0940 20 levels \u0924\u0915 \u0915\u0948\u0938\u094D\u0915\u0947\u0921 \u0939\u094B\u0924\u093E \u0939\u0948: L3 (5%), L4-5 (\u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 3%), L6-10 (\u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 2%), L11-20 (\u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 1%)\u0964 \u0915\u092E\u0940\u0936\u0928 \u0915\u0940 \u0917\u0923\u0928\u093E \u0914\u0930 \u0935\u093F\u0924\u0930\u0923 Smart Contract \u0926\u094D\u0935\u093E\u0930\u093E \u092A\u094D\u0930\u0924\u093F\u0926\u093F\u0928 \u0915\u093F\u092F\u093E \u091C\u093E\u0924\u093E \u0939\u0948 \u2014 \u0915\u094B\u0908 \u092E\u0948\u0928\u094D\u092F\u0941\u0905\u0932 \u091F\u094D\u0930\u0948\u0915\u093F\u0902\u0917 \u0928\u0939\u0940\u0902, \u0915\u094B\u0908 \u0935\u093F\u0932\u0902\u092C\u093F\u0924 \u092D\u0941\u0917\u0924\u093E\u0928 \u0928\u0939\u0940\u0902\u0964 \u0906\u092A \u0915\u093F\u0938\u0940 \u092D\u0940 level \u092A\u0930 \u0915\u093F\u0924\u0928\u0947 \u0932\u094B\u0917\u094B\u0902 \u0915\u094B \u0930\u0947\u092B\u0930 \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938\u0915\u0940 \u0915\u094B\u0908 \u0938\u0940\u092E\u093E \u0928\u0939\u0940\u0902 \u0939\u0948, \u0914\u0930 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0911\u0930\u094D\u0917\u0947\u0928\u093F\u0915 \u0930\u0942\u092A \u0938\u0947 \u092C\u0922\u093C\u0924\u093E \u0939\u0948 \u0915\u094D\u092F\u094B\u0902\u0915\u093F \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u0938\u0926\u0938\u094D\u092F \u0905\u092A\u0928\u093E \u0938\u094D\u0935\u092F\u0902 \u0915\u093E \u091F\u094D\u0930\u0940 \u092C\u0928\u093E\u0924\u093E \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0906\u0915\u0930\u094D\u0937\u0923:\n\u2022 L1: 12% | L2: 8% | L3: 5% | L4-5: \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 3% = 31% (\u0936\u0940\u0930\u094D\u0937 5)\n\u2022 L6-10: \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 2% = 10% | L11-20: \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 1% = 10% (\u0917\u0939\u0930\u0947 15)\n\u2022 \u0915\u0941\u0932 \u092F\u094B\u0917: \u0938\u092D\u0940 20 levels \u092E\u0947\u0902 51%\n\u2022 \u0939\u0930 level \u092A\u0930 \u0905\u0938\u0940\u092E\u093F\u0924 \u091A\u094C\u0921\u093C\u093E\u0908 \u2014 \u0915\u094B\u0908 \u0930\u0947\u092B\u0930\u0932 \u0915\u0948\u092A \u0928\u0939\u0940\u0902\n\u2022 Smart Contract \u0926\u094D\u0935\u093E\u0930\u093E \u0926\u0948\u0928\u093F\u0915 \u0938\u094D\u0935\u091A\u093E\u0932\u093F\u0924 \u0915\u092E\u0940\u0936\u0928 \u092D\u0941\u0917\u0924\u093E\u0928\n\n\u{1F48E} \u090F\u0915 \u0932\u093F\u0902\u0915\u0964 20 levels\u0964 51% \u0935\u093F\u0924\u0930\u0923\u0964 \u0905\u092A\u0928\u093E \u0938\u093E\u092E\u094D\u0930\u093E\u091C\u094D\u092F \u092C\u0928\u093E\u090F\u0902\u0964\n\n\u{1F310} turboloop.io",
