      headline: "\u{1F537} \u090F\u0915 \u0932\u0940\u0921\u0930 \u092C\u0928\u0947\u0902",
      caption: "\u{1F537} \u090F\u0915 \u0932\u0940\u0921\u0930 \u092C\u0928\u0947\u0902\n\u2726 Partner \u0938\u0947 TURBO LEGEND \u0924\u0915 \u0915\u093E \u0938\u092B\u0930\n\nTurboLoop \u0915\u0940 \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u092F\u093E\u0924\u094D\u0930\u093E \u0915\u092E\u094D\u092F\u0941\u0928\u093F\u091F\u0940 \u092A\u094D\u0930\u0924\u093F\u092D\u093E\u0917\u0940 \u0938\u0947 \u090F\u0932\u0940\u091F \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0932\u0940\u0921\u0930 \u0924\u0915 \u0915\u093E \u090F\u0915 \u0938\u094D\u092A\u0937\u094D\u091F \u0930\u0942\u092A \u0938\u0947 \u092A\u0930\u093F\u092D\u093E\u0937\u093F\u0924 \u092E\u093E\u0930\u094D\u0917 \u0939\u0948\u0964 \u092F\u0939 \u0924\u092C \u0936\u0941\u0930\u0942 \u0939\u094B\u0924\u093E \u0939\u0948 \u091C\u092C \u0906\u092A 100 \u091F\u0940\u092E \u0938\u0926\u0938\u094D\u092F\u094B\u0902 \u0924\u0915 \u092A\u0939\u0941\u0901\u091A\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u090F\u0915 Partner \u0915\u0947 \u0930\u0942\u092A \u092E\u0947\u0902 \u092F\u094B\u0917\u094D\u092F \u0939\u094B\u0924\u0947 \u0939\u0948\u0902, \u091C\u093F\u0938\u0938\u0947 \u0906\u092A \u0905\u092A\u0928\u0947 \u0928\u0947\u091F\u0935\u0930\u094D\u0915 \u0915\u0940 \u0917\u0924\u093F\u0935\u093F\u0927\u093F \u092A\u0930 1% \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u092C\u094B\u0928\u0938 \u0915\u092E\u093E\u0924\u0947 \u0939\u0948\u0902\u0964 \u0935\u0939\u093E\u0902 \u0938\u0947, \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u092E\u0940\u0932 \u0915\u093E \u092A\u0924\u094D\u0925\u0930 \u092C\u0921\u093C\u0947 \u092A\u0941\u0930\u0938\u094D\u0915\u093E\u0930\u094B\u0902 \u0915\u094B \u0905\u0928\u0932\u0949\u0915 \u0915\u0930\u0924\u093E \u0939\u0948: 250 \u0938\u0926\u0938\u094D\u092F\u094B\u0902 \u092A\u0930 Senior Partner (2%), 500 \u092A\u0930 Manager (3%), 1,000 \u092A\u0930 Senior Manager (5%), 2,500 \u092A\u0930 Director (7%), 5,000 \u092A\u0930 Senior Director (8%)\u0964 \u0936\u093F\u0916\u0930 \u092A\u0930 TURBO LEGEND \u0916\u0921\u093C\u093E \u0939\u0948 \u2014 \u091C\u093F\u0938\u0915\u0947 \u0932\u093F\u090F 10,000 \u091F\u0940\u092E \u0938\u0926\u0938\u094D\u092F\u094B\u0902 \u0914\u0930 \u0915\u0941\u0932 \u091F\u0940\u092E \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u092E\u0947\u0902 $1,000,000 \u0915\u0940 \u0906\u0935\u0936\u094D\u092F\u0915\u0924\u093E \u0939\u094B\u0924\u0940 \u0939\u0948 \u2014 \u091C\u094B \u0905\u0927\u093F\u0915\u0924\u092E 10% \u0932\u0940\u0921\u0930\u0936\u093F\u092A \u092C\u094B\u0928\u0938 \u0915\u092E\u093E\u0924\u093E \u0939\u0948\u0964 \u092F\u0939 \u0915\u0947\u0935\u0932 \u092A\u094D\u0930\u0924\u093F\u0936\u0924 \u0915\u0947 \u092C\u093E\u0930\u0947 \u092E\u0947\u0902 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u0930\u0948\u0902\u0915 \u090F\u0915 \u092C\u0922\u093C\u0924\u0940 \u0915\u092E\u094D\u092F\u0941\u0928\u093F\u091F\u0940, \u090F\u0915 \u0935\u094D\u092F\u093E\u092A\u0915 \u092A\u094D\u0930\u092D\u093E\u0935 \u0914\u0930 TurboLoop \u0907\u0915\u094B\u0938\u093F\u0938\u094D\u091F\u092E \u0915\u0947 \u092A\u094D\u0930\u0924\u093F \u0917\u0939\u0930\u0940 \u092A\u094D\u0930\u0924\u093F\u092C\u0926\u094D\u0927\u0924\u093E \u0915\u093E \u092A\u094D\u0930\u0924\u093F\u0928\u093F\u0927\u093F\u0924\u094D\u0935 \u0915\u0930\u0924\u093E \u0939\u0948\u0964 \u0936\u093F\u0916\u0930 \u0935\u093E\u0938\u094D\u0924\u0935\u093F\u0915 \u0939\u0948\u0964 \u0930\u093E\u0938\u094D\u0924\u093E \u0938\u094D\u092A\u0937\u094D\u091F \u0939\u0948\u0964\n\n\u2705 \u092E\u0941\u0916\u094D\u092F \u0935\u093F\u0936\u0947\u0937\u0924\u093E\u090F\u0902:\n\u2022 Partner: 100 \u0938\u0926\u0938\u094D\u092F, 1% \u2192 Senior Partner: 250, 2%\n\u2022 Manager: 500, 3% \u2192 Senior Manager: 1,000, 5%\n\u2022 Director: 2,500, 7% \u2192 Senior Director: 5,000, 8%\n\u2022 TURBO LEGEND: 10,000 \u0938\u0926\u0938\u094D\u092F + $1M \u091F\u0940\u092E \u0921\u093F\u092A\u0949\u091C\u093F\u091F \u2192 10%\n\u2022 \u092A\u094D\u0930\u0924\u094D\u092F\u0947\u0915 \u0930\u0948\u0902\u0915 = \u092C\u0921\u093C\u0947 \u092A\u0941\u0930\u0938\u094D\u0915\u093E\u0930, \u0935\u094D\u092F\u093E\u092A\u0915 \u092A\u094D\u0930\u092D\u093E\u0935, \u0917\u0939\u0930\u0940 \u092A\u094D\u0930\u0924\u093F\u092C\u0926\u094D\u0927\u0924\u093E\n\n\u{1F48E} \u0936\u093F\u0916\u0930 \u092A\u094D\u0930\u0924\u0940\u0915\u094D\u0937\u093E \u0915\u0930 \u0930\u0939\u093E \u0939\u0948\u0964 \u091A\u0922\u093C\u0928\u093E \u0936\u0941\u0930\u0942 \u0915\u0930\u0947\u0902\u0964 \u0928\u091C\u093C\u093E\u0930\u093E \u0907\u0938\u0915\u0947 \u0932\u093E\u092F\u0915 \u0939\u0948\u0964\n\n\u{1F310} turboloop.io",
