      headline: "\u{1F537} 1,000$ \xD7 12 \u0634\u0647\u0631\u064B\u0627",
      caption: '\u{1F537} 1,000$ \xD7 12 \u0634\u0647\u0631\u064B\u0627  \n\u2726 \u0627\u0644\u0642\u0648\u0629 \u0627\u0644\u0623\u0633\u064A\u0629 \u0644\u0644\u062A\u0631\u0627\u0643\u0645 \u2014 \u0633\u064A\u0646\u0627\u0631\u064A\u0648 \u062D\u0642\u064A\u0642\u064A  \n\n\u0647\u0646\u0627 \u064A\u0643\u0634\u0641 TurboLoop \u0639\u0646 \u0625\u0645\u0643\u0627\u0646\u0627\u062A\u0647 \u0627\u0644\u062D\u0642\u064A\u0642\u064A\u0629. \u062E\u0630 1,000$ \u0648\u0642\u0645 \u0628\u0625\u064A\u062F\u0627\u0639\u0647\u0627 \u0641\u064A Power Loop (24% \u062E\u0644\u0627\u0644 30 \u064A\u0648\u0645\u064B\u0627). \u0641\u064A \u0646\u0647\u0627\u064A\u0629 \u0627\u0644\u0634\u0647\u0631 \u0627\u0644\u0623\u0648\u0644\u060C \u064A\u0635\u0628\u062D \u0644\u062F\u064A\u0643 1,240$. \u0623\u0639\u062F \u0627\u0633\u062A\u062B\u0645\u0627\u0631 \u0627\u0644\u0645\u0628\u0644\u063A \u0628\u0627\u0644\u0643\u0627\u0645\u0644. \u0627\u0644\u0634\u0647\u0631 3: 1,907$. \u0627\u0644\u0634\u0647\u0631 6: 3,654$. \u0627\u0644\u0634\u0647\u0631 9: 7,003$. \u0627\u0644\u0634\u0647\u0631 12: 13,220$. \u0647\u0630\u0627 \u0625\u064A\u062F\u0627\u0639 \u0648\u0627\u062D\u062F \u0628\u0642\u064A\u0645\u0629 1,000$ \u064A\u0646\u0645\u0648 \u0623\u0643\u062B\u0631 \u0645\u0646 13 \u0636\u0639\u0641\u064B\u0627 \u0641\u064A \u0633\u0646\u0629 \u0648\u0627\u062D\u062F\u0629 \u0645\u0646 \u062E\u0644\u0627\u0644 \u0627\u0644\u0645\u0645\u0627\u0631\u0633\u0629 \u0627\u0644\u0645\u0646\u0636\u0628\u0637\u0629 \u0644\u0625\u0639\u0627\u062F\u0629 \u0627\u0633\u062A\u062B\u0645\u0627\u0631 \u0639\u0648\u0627\u0626\u062F \u0643\u0644 \u062F\u0648\u0631\u0629. \u0647\u0630\u0647 \u0647\u064A \u0627\u0644\u0633\u062D\u0631 \u0627\u0644\u0631\u064A\u0627\u0636\u064A \u0644\u0644\u0641\u0627\u0626\u062F\u0629 \u0627\u0644\u0645\u0631\u0643\u0628\u0629 \u2014 "\u0627\u0644\u0639\u062C\u064A\u0628\u0629 \u0627\u0644\u062B\u0627\u0645\u0646\u0629 \u0644\u0644\u0639\u0627\u0644\u0645" \u0644\u0623\u0644\u0628\u0631\u062A \u0623\u064A\u0646\u0634\u062A\u0627\u064A\u0646 \u2014 \u0645\u0637\u0628\u0642\u0629 \u0639\u0644\u0649 \u0639\u0648\u0627\u0626\u062F DeFi. \u0644\u0627 \u064A\u0647\u062A\u0645 Smart Contract \u0628\u0645\u0634\u0627\u0639\u0631 \u0627\u0644\u0633\u0648\u0642 \u0623\u0648 \u0627\u0644\u062F\u0648\u0631\u0627\u062A \u0627\u0644\u0627\u0642\u062A\u0635\u0627\u062F\u064A\u0629 \u0623\u0648 \u0627\u0644\u0623\u062D\u062F\u0627\u062B \u0627\u0644\u062C\u064A\u0648\u0633\u064A\u0627\u0633\u064A\u0629. \u0625\u0646\u0647 \u064A\u062D\u0633\u0628 \u0648\u064A\u0648\u0632\u0639 \u0627\u0644\u0639\u0648\u0627\u0626\u062F \u0628\u0646\u0641\u0633 \u0627\u0644\u062F\u0642\u0629 \u0641\u064A \u0627\u0644\u064A\u0648\u0645 \u0627\u0644\u0623\u0648\u0644 \u0643\u0645\u0627 \u0641\u064A \u0627\u0644\u064A\u0648\u0645 365. \u0627\u0644\u0648\u0642\u062A \u0647\u0648 \u0623\u0639\u0638\u0645 \u0623\u0635\u0648\u0644\u0643. \u062F\u0639\u0647 \u064A\u062A\u0631\u0627\u0643\u0645.  \n\n\u2705 \u0627\u0644\u0646\u0642\u0627\u0637 \u0627\u0644\u0631\u0626\u064A\u0633\u064A\u0629:  \n\u2022 \u0627\u0644\u0625\u064A\u062F\u0627\u0639 \u0627\u0644\u0627\u0628\u062A\u062F\u0627\u0626\u064A: 1,000$ \u0641\u064A Power Loop (24%/30 \u064A\u0648\u0645\u064B\u0627)  \n\u2022 \u0627\u0644\u0634\u0647\u0631 1: 1,240$ | \u0627\u0644\u0634\u0647\u0631 3: 1,907$ | \u0627\u0644\u0634\u0647\u0631 6: 3,654$  \n\u2022 \u0627\u0644\u0634\u0647\u0631 9: 7,003$ | \u0627\u0644\u0634\u0647\u0631 12: 13,220$  \n\u2022 \u0646\u0645\u0648 \u0623\u0643\u062B\u0631 \u0645\u0646 13 \u0636\u0639\u0641\u064B\u0627 \u062E\u0644\u0627\u0644 12 \u0634\u0647\u0631\u064B\u0627 \u0639\u0628\u0631 \u0627\u0644\u062A\u0631\u0627\u0643\u0645  \n\u2022 \u062A\u0646\u0641\u064A\u0630 Smart Contract \u0628\u062F\u0642\u0629 \u0645\u062A\u0637\u0627\u0628\u0642\u0629 \u0641\u064A \u0643\u0644 \u062F\u0648\u0631\u0629  \n\n\u{1F48E} \u0627\u0644\u0648\u0642\u062A \u0647\u0648 \u0623\u0639\u0638\u0645 \u062D\u0644\u064A\u0641 \u0644\u0643. \u0627\u0628\u062F\u0623 \u0627\u0644\u062A\u0631\u0627\u0643\u0645 \u0627\u0644\u064A\u0648\u0645.  \n\n\u{1F310} turboloop.io',
