      original: "25_Muqaddim_Zoom.png",
      headline: "\u{1F537} \u0628\u0631\u0646\u0627\u0645\u062C \u0645\u0642\u062F\u0645\u064A ZOOM",
      caption: "\u{1F537} \u0628\u0631\u0646\u0627\u0645\u062C \u0645\u0642\u062F\u0645\u064A ZOOM\n\u2726 \u0642\u062F\u0645 TurboLoop\u060C \u0648\u0627\u0643\u0633\u0628 $100 \u0643\u0644 \u0634\u0647\u0631\n\n\u064A\u0645\u0643\u0651\u0646 \u0628\u0631\u0646\u0627\u0645\u062C \u0645\u0642\u062F\u0645\u064A Zoom \u0645\u0646 TurboLoop \u0623\u0639\u0636\u0627\u0621 \u0627\u0644\u0645\u062C\u062A\u0645\u0639 \u0627\u0644\u0634\u063A\u0648\u0641\u064A\u0646 \u0645\u0646 \u0623\u0646 \u064A\u0635\u0628\u062D\u0648\u0627 \u0633\u0641\u0631\u0627\u0621 \u0631\u0633\u0645\u064A\u064A\u0646. \u062A\u0642\u062F\u0645 \u0628\u0637\u0644\u0628 \u0644\u0644\u0627\u0646\u0636\u0645\u0627\u0645 \u0625\u0644\u0649 \u0627\u0644\u0628\u0631\u0646\u0627\u0645\u062C\u060C \u0648\u0627\u062D\u0635\u0644 \u0639\u0644\u0649 \u0645\u0648\u0627\u062F \u0639\u0631\u0636 \u0645\u0635\u0645\u0645\u0629 \u0628\u0627\u062D\u062A\u0631\u0627\u0641\u064A\u0629\u060C \u0648\u0627\u0633\u062A\u0636\u0641 \u062C\u0644\u0633\u0627\u062A Zoom \u0645\u062D\u0644\u064A\u0629 \u0644\u062A\u062B\u0642\u064A\u0641 \u0648\u0636\u0645 \u0623\u0639\u0636\u0627\u0621 \u062C\u062F\u062F \u0628\u0644\u063A\u062A\u0643 \u0648\u0645\u062C\u062A\u0645\u0639\u0643. \u0641\u064A \u0627\u0644\u0645\u0642\u0627\u0628\u0644\u060C \u062A\u0643\u0633\u0628 $100 \u0634\u0647\u0631\u064A\u0627\u064B \u0628\u0634\u0643\u0644 \u062B\u0627\u0628\u062A \u2014 \u0645\u0635\u062F\u0631 \u062F\u062E\u0644 \u0645\u0648\u062B\u0648\u0642 \u0644\u0623\u0648\u0644\u0626\u0643 \u0627\u0644\u0630\u064A\u0646 \u064A\u062D\u0628\u0648\u0646 \u0627\u0644\u062A\u062F\u0631\u064A\u0633 \u0648\u0627\u0644\u062A\u0648\u0627\u0635\u0644 \u0645\u0639 \u0627\u0644\u0646\u0627\u0633. \u064A\u062A\u0636\u0645\u0646 \u0627\u0644\u0628\u0631\u0646\u0627\u0645\u062C \u062A\u062F\u0631\u064A\u0628\u0627\u064B \u0645\u062C\u0627\u0646\u064A\u0627\u064B \u0644\u0636\u0645\u0627\u0646 \u062A\u0632\u0648\u064A\u062F\u0643 \u0628\u0627\u0644\u0645\u0639\u0644\u0648\u0645\u0627\u062A \u0627\u0644\u062F\u0642\u064A\u0642\u0629 \u0648\u0645\u0647\u0627\u0631\u0627\u062A \u0627\u0644\u0639\u0631\u0636 \u0627\u0644\u0641\u0639\u0627\u0644\u0629. \u0633\u0648\u0627\u0621 \u0643\u0646\u062A \u0641\u064A \u0644\u0627\u063A\u0648\u0633\u060C \u062C\u0627\u0643\u0631\u062A\u0627\u060C \u0645\u0648\u0645\u0628\u0627\u064A\u060C \u0623\u0648 \u0645\u0643\u0633\u064A\u0643\u0648 \u0633\u064A\u062A\u064A\u060C \u064A\u0645\u0643\u0646\u0643 \u0623\u0646 \u062A\u0635\u0628\u062D \u0645\u0642\u062F\u0645 TurboLoop \u0648\u062A\u0628\u0646\u064A \u0645\u062C\u062A\u0645\u0639\u0643 \u0627\u0644\u0645\u062D\u0644\u064A \u0628\u064A\u0646\u0645\u0627 \u062A\u0643\u0633\u0628.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u062A\u0642\u062F\u0645 \u0628\u0637\u0644\u0628 \u0644\u0628\u0631\u0646\u0627\u0645\u062C \u0645\u0642\u062F\u0645\u064A Zoom \u2014 \u0645\u062A\u0627\u062D \u0644\u062C\u0645\u064A\u0639 \u0627\u0644\u0623\u0639\u0636\u0627\u0621\n\u2022 \u0627\u062D\u0635\u0644 \u0639\u0644\u0649 \u0645\u0648\u0627\u062F \u0639\u0631\u0636 \u0631\u0633\u0645\u064A\u0629 \u0648\u062A\u062F\u0631\u064A\u0628 \u0645\u062C\u0627\u0646\u064A\n\u2022 \u0627\u0633\u062A\u0636\u0641 \u062C\u0644\u0633\u0627\u062A Zoom \u0645\u062D\u0644\u064A\u0629 \u0628\u0644\u063A\u062A\u0643 \u0648\u0645\u062C\u062A\u0645\u0639\u0643\n\u2022 \u0627\u0643\u0633\u0628 $100/\u0634\u0647\u0631\u064A\u0627\u064B \u0643\u062F\u062E\u0644 \u062B\u0627\u0628\u062A \u0644\u0644\u0645\u0642\u062F\u0645\n\u2022 \u0627\u0628\u0646\u0650 \u0634\u0628\u0643\u062A\u0643 \u0627\u0644\u0645\u062D\u0644\u064A\u0629 \u0623\u062B\u0646\u0627\u0621 \u062A\u062B\u0642\u064A\u0641 \u0627\u0644\u0623\u0639\u0636\u0627\u0621 \u0627\u0644\u062C\u062F\u062F\n\n\u{1F48E} \u0639\u0644\u0651\u0645. \u0623\u0644\u0647\u0645. \u0627\u0643\u0633\u0628. \u0643\u0646 \u0633\u0641\u064A\u0631\u0627\u064B \u0644\u0640 TurboLoop.\n\n\u{1F310} turboloop.io",
