      original: "26_Tahadi_SC.png",
      headline: "\u{1F537} \u062A\u062D\u062F\u064A SMART CONTRACT",
      caption: "\u{1F537} \u062A\u062D\u062F\u064A SMART CONTRACT\n\u2726 \u0645\u0643\u0627\u0641\u0623\u0629 \u0628\u0642\u064A\u0645\u0629 $100,000 \u2014 \u0647\u0644 \u064A\u0645\u0643\u0646\u0643 \u0643\u0633\u0631 \u0627\u0644\u0634\u0641\u0631\u0629\u061F\n\n\u062A\u0636\u0639 TurboLoop \u0623\u0645\u0648\u0627\u0644\u0647\u0627 \u062D\u064A\u062B \u064A\u0648\u062C\u062F \u0643\u0648\u062F\u0647\u0627. \u064A\u0642\u062F\u0645 \u062A\u062D\u062F\u064A Smart Contract \u0645\u0643\u0627\u0641\u0623\u0629 \u0628\u0642\u064A\u0645\u0629 $100,000 \u0644\u0623\u064A \u0634\u062E\u0635 \u064A\u0645\u0643\u0646\u0647 \u0627\u0644\u0639\u062B\u0648\u0631 \u0639\u0644\u0649 \u062B\u063A\u0631\u0629 \u0623\u0645\u0646\u064A\u0629 \u0623\u0648 \u0627\u0633\u062A\u063A\u0644\u0627\u0644 \u0623\u0648 \u0639\u064A\u0628 \u0641\u064A TurboLoop smart contract. \u0647\u0630\u0647 \u0644\u064A\u0633\u062A \u062D\u064A\u0644\u0629 \u062A\u0633\u0648\u064A\u0642\u064A\u0629 \u2014 \u0625\u0646\u0647\u0627 \u0627\u0644\u062F\u0644\u064A\u0644 \u0627\u0644\u0642\u0627\u0637\u0639 \u0639\u0644\u0649 \u0627\u0644\u062B\u0642\u0629 \u0641\u064A \u0627\u0644\u0628\u0646\u064A\u0629 \u0627\u0644\u0623\u0645\u0646\u064A\u0629 \u0644\u0644\u0628\u0631\u0648\u062A\u0648\u0643\u0648\u0644. \u062A\u0645 \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0645\u0644\u0643\u064A\u0629 \u0627\u0644\u0639\u0642\u062F (\u062A\u0645 \u062D\u0631\u0642 \u0645\u0641\u0627\u062A\u064A\u062D \u0627\u0644\u0645\u0633\u0624\u0648\u0644)\u060C \u0648\u062A\u0645 \u0642\u0641\u0644 \u0645\u062C\u0645\u0639 \u0627\u0644\u0633\u064A\u0648\u0644\u0629 (LP) \u0625\u0644\u0649 \u0627\u0644\u0623\u0628\u062F\u060C \u0648\u062A\u0645 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646 \u0627\u0644\u0643\u0648\u062F \u0627\u0644\u0645\u0635\u062F\u0631\u064A \u0639\u0644\u0649 BscScan\u060C \u0648\u0623\u0633\u0641\u0631 \u062A\u062F\u0642\u064A\u0642 \u0645\u0633\u062A\u0642\u0644 \u0639\u0646 \u062F\u0631\u062C\u0629 \u062B\u0642\u0629 99%. \u0639\u0644\u0649 \u0627\u0644\u0631\u063A\u0645 \u0645\u0646 \u0643\u0648\u0646\u0647 \u0645\u0641\u062A\u0648\u062D\u064B\u0627 \u0644\u0645\u062C\u062A\u0645\u0639 \u0627\u0644\u0645\u0637\u0648\u0631\u064A\u0646 \u0627\u0644\u0639\u0627\u0644\u0645\u064A \u0628\u0623\u0633\u0631\u0647\u060C \u0644\u0645 \u064A\u0637\u0627\u0644\u0628 \u0623\u062D\u062F \u0628\u0627\u0644\u0645\u0643\u0627\u0641\u0623\u0629. \u064A\u0638\u0644 \u0627\u0644\u0639\u0642\u062F \u063A\u064A\u0631 \u0642\u0627\u0628\u0644 \u0644\u0644\u0643\u0633\u0631\u060C \u0648\u063A\u064A\u0631 \u0642\u0627\u0628\u0644 \u0644\u0644\u0627\u062E\u062A\u0631\u0627\u0642\u060C \u0648\u0644\u0627 \u064A\u0645\u0643\u0646 \u0625\u064A\u0642\u0627\u0641\u0647 \u2014 \u062A\u0645\u0627\u0645\u064B\u0627 \u0643\u0645\u0627 \u062A\u0645 \u062A\u0635\u0645\u064A\u0645\u0647.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u0627\u0644\u0645\u0643\u0627\u0641\u0623\u0629: $100,000 \u0644\u0644\u0639\u062B\u0648\u0631 \u0639\u0644\u0649 \u0623\u064A \u062B\u063A\u0631\u0629 \u0623\u0645\u0646\u064A\u0629 \u0623\u0648 \u0627\u0633\u062A\u063A\u0644\u0627\u0644\n\u2022 \u062A\u0645 \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0627\u0644\u0645\u0644\u0643\u064A\u0629 \u2014 \u062A\u0645 \u062D\u0631\u0642 \u0645\u0641\u0627\u062A\u064A\u062D \u0627\u0644\u0645\u0633\u0624\u0648\u0644 \u0628\u0634\u0643\u0644 \u062F\u0627\u0626\u0645\n\u2022 \u062A\u0645 \u0642\u0641\u0644 LP \u0625\u0644\u0649 \u0627\u0644\u0623\u0628\u062F \u2014 \u0644\u0627 \u062A\u0648\u062C\u062F \u0622\u0644\u064A\u0629 \u0633\u062D\u0628 \u0627\u0644\u0628\u0633\u0627\u0637 (rug pull)\n\u2022 \u062A\u0645 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646 \u0627\u0644\u0643\u0648\u062F \u0639\u0644\u0649 BscScan \u2014 \u0634\u0641\u0627\u0641 \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u0648\u0642\u0627\u0628\u0644 \u0644\u0644\u062A\u062F\u0642\u064A\u0642\n\u2022 \u062A\u062F\u0642\u064A\u0642 \u0645\u0633\u062A\u0642\u0644: \u062F\u0631\u062C\u0629 \u062B\u0642\u0629 99% \u2014 \u0644\u0645 \u064A\u0646\u062C\u062D \u0623\u062D\u062F\n\n\u{1F48E} \u0647\u0644 \u064A\u0645\u0643\u0646\u0643 \u0627\u062E\u062A\u0631\u0627\u0642\u0647\u061F $100,000 \u062A\u0642\u0648\u0644 \u0623\u0646\u0643 \u0644\u0627 \u062A\u0633\u062A\u0637\u064A\u0639. \u0623\u062B\u0628\u062A \u0623\u0646\u0646\u0627 \u0645\u062E\u0637\u0626\u0648\u0646.\n\n\u{1F310} turboloop.io",
