      headline: "\u{1F537} \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0627\u0644\u0645\u0644\u0643\u064A\u0629",
      caption: '\u{1F537} \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0627\u0644\u0645\u0644\u0643\u064A\u0629\n\u2726 \u062A\u0645 \u062D\u0631\u0642 \u0645\u0641\u0627\u062A\u064A\u062D \u0627\u0644\u0625\u062F\u0627\u0631\u0629 \u2014 \u0644\u0627 \u064A\u0645\u0643\u0646 \u0644\u0623\u064A \u0625\u0646\u0633\u0627\u0646 \u062A\u063A\u064A\u064A\u0631 \u0627\u0644\u0642\u0648\u0627\u0639\u062F\n\n\u0641\u064A \u0639\u0627\u0644\u0645 \u0627\u0644\u0640 Smart Contract\u060C \u064A\u0639\u062A\u0628\u0631 "\u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0627\u0644\u0645\u0644\u0643\u064A\u0629" \u0647\u0648 \u0627\u0644\u0645\u0639\u064A\u0627\u0631 \u0627\u0644\u0630\u0647\u0628\u064A \u0644\u0644\u0627\u0645\u0631\u0643\u0632\u064A\u0629. \u062A\u0645 \u0646\u0642\u0644 \u0645\u0644\u0643\u064A\u0629 \u0639\u0642\u062F TurboLoop \u0628\u0634\u0643\u0644 \u062F\u0627\u0626\u0645 \u0625\u0644\u0649 \u0627\u0644\u0639\u0646\u0648\u0627\u0646 \u0627\u0644\u0645\u064A\u062A (0x000...dead)\u060C \u0645\u0645\u0627 \u064A\u0639\u0646\u064A \u0623\u0646 \u0645\u0641\u0627\u062A\u064A\u062D \u0627\u0644\u0625\u062F\u0627\u0631\u0629 \u0627\u0644\u062A\u064A \u064A\u0645\u0643\u0646\u0647\u0627 \u062A\u0639\u062F\u064A\u0644 \u0627\u0644\u0639\u0642\u062F \u0623\u0648 \u0625\u064A\u0642\u0627\u0641\u0647 \u0645\u0624\u0642\u062A\u0627\u064B \u0623\u0648 \u0627\u0644\u062A\u062F\u062E\u0644 \u0641\u064A\u0647 \u0642\u062F \u062A\u0645 \u062A\u062F\u0645\u064A\u0631\u0647\u0627 \u0628\u0634\u0643\u0644 \u0644\u0627 \u0631\u062C\u0639\u0629 \u0641\u064A\u0647. \u0644\u0627 \u062A\u0648\u062C\u062F \u0623\u0628\u0648\u0627\u0628 \u062E\u0644\u0641\u064A\u0629. \u0644\u0627 \u062A\u0648\u062C\u062F \u0648\u0638\u0627\u0626\u0641 \u0637\u0648\u0627\u0631\u0626. \u0644\u0627 \u062A\u0648\u062C\u062F \u0622\u0644\u064A\u0627\u062A \u0625\u064A\u0642\u0627\u0641 \u0645\u0624\u0642\u062A. \u0644\u0627 \u062A\u0648\u062C\u062F \u0645\u0633\u0627\u0631\u0627\u062A \u062A\u0631\u0642\u064A\u0629. \u064A\u062A\u0645 \u062A\u0646\u0641\u064A\u0630 \u0627\u0644\u0639\u0642\u062F \u062A\u0645\u0627\u0645\u0627\u064B \u0643\u0645\u0627 \u0647\u0648 \u0645\u0643\u062A\u0648\u0628\u060C \u0628\u0634\u0643\u0644 \u0645\u0633\u062A\u0642\u0644 \u0648\u0625\u0644\u0649 \u0623\u062C\u0644 \u063A\u064A\u0631 \u0645\u0633\u0645\u0649\u060C \u062F\u0648\u0646 \u0623\u064A \u0625\u0645\u0643\u0627\u0646\u064A\u0629 \u0644\u0644\u062A\u062F\u062E\u0644 \u0627\u0644\u0628\u0634\u0631\u064A. \u0647\u0630\u0627 \u0644\u064A\u0633 \u0625\u062C\u0631\u0627\u0621\u064B \u0645\u0624\u0642\u062A\u0627\u064B \u0623\u0648 \u0648\u0639\u062F\u0627\u064B \u2014 \u0625\u0646\u0647\u0627 \u062D\u0642\u064A\u0642\u0629 \u062F\u0627\u0626\u0645\u0629 \u064A\u0645\u0643\u0646 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646\u0647\u0627 \u0639\u0644\u0649 \u0627\u0644\u0633\u0644\u0633\u0644\u0629. \u0628\u0645\u062C\u0631\u062F \u0627\u0644\u062A\u0646\u0627\u0632\u0644\u060C \u0644\u0627 \u064A\u0645\u0643\u0646 \u0627\u0633\u062A\u0639\u0627\u062F\u0629 \u0627\u0644\u0645\u0644\u0643\u064A\u0629 \u0623\u0628\u062F\u0627\u064B. \u0627\u0644\u0643\u0648\u062F \u0647\u0648 \u0627\u0644\u0642\u0627\u0646\u0648\u0646\u060C \u0625\u0644\u0649 \u0627\u0644\u0623\u0628\u062F.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u062A\u0645 \u0646\u0642\u0644 \u0627\u0644\u0645\u0644\u0643\u064A\u0629 \u0625\u0644\u0649 \u0627\u0644\u0639\u0646\u0648\u0627\u0646 \u0627\u0644\u0645\u064A\u062A: 0x000...dead\n\u2022 \u062A\u0645 \u062D\u0631\u0642 \u0645\u0641\u0627\u062A\u064A\u062D \u0627\u0644\u0625\u062F\u0627\u0631\u0629 \u0628\u0634\u0643\u0644 \u062F\u0627\u0626\u0645 \u0648\u0644\u0627 \u0631\u062C\u0639\u0629 \u0641\u064A\u0647\n\u2022 \u0644\u0627 \u062A\u0648\u062C\u062F \u0623\u0628\u0648\u0627\u0628 \u062E\u0644\u0641\u064A\u0629\u060C \u0644\u0627 \u062A\u0648\u062C\u062F \u0648\u0638\u0627\u0626\u0641 \u0637\u0648\u0627\u0631\u0626\u060C \u0644\u0627 \u062A\u0648\u062C\u062F \u0625\u0645\u0643\u0627\u0646\u064A\u0629 \u0644\u0644\u0625\u064A\u0642\u0627\u0641 \u0627\u0644\u0645\u0624\u0642\u062A\n\u2022 \u064A\u062A\u0645 \u062A\u0646\u0641\u064A\u0630 \u0627\u0644\u0639\u0642\u062F \u0628\u0634\u0643\u0644 \u0645\u0633\u062A\u0642\u0644 \u2014 \u0644\u0627 \u064A\u0645\u0643\u0646 \u0627\u0644\u062A\u062F\u062E\u0644 \u0627\u0644\u0628\u0634\u0631\u064A\n\u2022 \u064A\u0645\u0643\u0646 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646\u0647 \u0639\u0644\u0649 BscScan \u2014 \u062A\u062D\u0642\u0642 \u0645\u0646 \u0639\u0646\u0648\u0627\u0646 \u0627\u0644\u0645\u0627\u0644\u0643 \u0628\u0646\u0641\u0633\u0643\n\n\u{1F48E} \u0627\u0644\u0643\u0648\u062F \u0647\u0648 \u0627\u0644\u0642\u0627\u0646\u0648\u0646. \u0625\u0644\u0649 \u0627\u0644\u0623\u0628\u062F. \u0644\u0627 \u0627\u0633\u062A\u062B\u0646\u0627\u0621\u0627\u062A. \u0644\u0627 \u062A\u0631\u0627\u062C\u0639\u0627\u062A.\n\n\u{1F310} turboloop.io',
