      original: "38_Shabakat_Ihalat_Detail.png",
      headline: "\u{1F537} \u0634\u0628\u0643\u0629 \u0627\u0644\u0625\u062D\u0627\u0644\u0629",
      caption: "\u{1F537} \u0634\u0628\u0643\u0629 \u0627\u0644\u0625\u062D\u0627\u0644\u0629\n\u2726 \u0634\u0627\u0631\u0643 \u0631\u0627\u0628\u0637\u0643\u060C \u0648\u0627\u0643\u0633\u0628 \u0645\u0646 20 \u0645\u0633\u062A\u0648\u0649 \u2014 \u0639\u0631\u0636 \u063A\u064A\u0631 \u0645\u062D\u062F\u0648\u062F\n\n\u062A\u062D\u0648\u0644 \u0634\u0628\u0643\u0629 \u0625\u062D\u0627\u0644\u0629 TurboLoop \u0643\u0644 \u0639\u0636\u0648 \u0625\u0644\u0649 \u0645\u0631\u0643\u0632 \u062F\u062E\u0644 \u0645\u062D\u062A\u0645\u0644. \u0634\u0627\u0631\u0643 \u0631\u0627\u0628\u0637 \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u0627\u0644\u0641\u0631\u064A\u062F \u0627\u0644\u062E\u0627\u0635 \u0628\u0643\u060C \u0648\u0639\u0646\u062F\u0645\u0627 \u064A\u0646\u0636\u0645 \u0634\u062E\u0635 \u0645\u0627 \u0648\u064A\u0648\u062F\u0639 \u0645\u0646 \u062E\u0644\u0627\u0644\u0647\u060C \u062A\u0643\u0633\u0628 \u0646\u0633\u0628\u0629 \u0645\u0626\u0648\u064A\u0629 \u0645\u0646 \u0625\u064A\u062F\u0627\u0639\u0647 \u2014 \u062A\u0644\u0642\u0627\u0626\u064A\u0627\u064B\u060C \u064A\u0648\u0645\u064A\u0627\u064B\u060C \u0648\u062A\u062A\u0645 \u0645\u0639\u0627\u0644\u062C\u062A\u0647\u0627 \u0628\u0648\u0627\u0633\u0637\u0629 \u0627\u0644\u0640 Smart Contract. \u0644\u0643\u0646 \u0627\u0644\u0623\u0645\u0631 \u0644\u0627 \u064A\u062A\u0648\u0642\u0641 \u0639\u0646\u062F \u0627\u0644\u0625\u062D\u0627\u0644\u0627\u062A \u0627\u0644\u0645\u0628\u0627\u0634\u0631\u0629. \u062A\u0645\u062A\u062F \u0634\u0628\u0643\u0629 TurboLoop \u0625\u0644\u0649 \u0639\u0645\u0642 20 \u0645\u0633\u062A\u0648\u0649\u060C \u0645\u0645\u0627 \u064A\u0639\u0646\u064A \u0623\u0646\u0643 \u062A\u0643\u0633\u0628 \u0645\u0646 \u0625\u062D\u0627\u0644\u0627\u062A \u0625\u062D\u0627\u0644\u0627\u062A \u0625\u062D\u0627\u0644\u0627\u062A\u0643 \u2014 \u0648\u0635\u0648\u0644\u0627\u064B \u0625\u0644\u0649 \u0627\u0644\u0645\u0633\u062A\u0648\u0649 \u0627\u0644\u0639\u0634\u0631\u064A\u0646. \u0625\u062C\u0645\u0627\u0644\u064A \u0627\u0644\u062A\u0648\u0632\u064A\u0639 \u0639\u0628\u0631 \u062C\u0645\u064A\u0639 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0647\u0648 51%\u060C \u0645\u0639 \u0639\u062F\u0645 \u0648\u062C\u0648\u062F \u062D\u062F \u0644\u0644\u0639\u0631\u0636 \u0641\u064A \u0623\u064A \u0645\u0633\u062A\u0648\u0649. \u064A\u0645\u0643\u0646\u0643 \u0625\u062D\u0627\u0644\u0629 10 \u0623\u0634\u062E\u0627\u0635 \u0623\u0648 10,000 \u2014 \u064A\u062A\u062A\u0628\u0639 \u0627\u0644\u0640 Smart Contract \u0648\u064A\u0648\u0632\u0639 \u0627\u0644\u0639\u0645\u0648\u0644\u0627\u062A \u0644\u0643\u0644 \u0648\u0627\u062D\u062F \u0645\u0646\u0647\u0645\u060C \u0643\u0644 \u064A\u0648\u0645\u060C \u062F\u0648\u0646 \u0641\u0634\u0644.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u0639\u0645\u0642 20 \u0645\u0633\u062A\u0648\u0649 \u2014 \u0627\u0643\u0633\u0628 \u0645\u0646 \u0646\u0634\u0627\u0637 \u0634\u0628\u0643\u062A\u0643 \u0628\u0627\u0644\u0643\u0627\u0645\u0644\n\u2022 51% \u0625\u062C\u0645\u0627\u0644\u064A \u0627\u0644\u062A\u0648\u0632\u064A\u0639 \u0639\u0628\u0631 \u062C\u0645\u064A\u0639 \u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u0627\u0644\u0639\u0634\u0631\u064A\u0646\n\u2022 \u0639\u0631\u0636 \u063A\u064A\u0631 \u0645\u062D\u062F\u0648\u062F \u2014 \u0644\u0627 \u064A\u0648\u062C\u062F \u062D\u062F \u0623\u0642\u0635\u0649 \u0644\u0644\u0625\u062D\u0627\u0644\u0627\u062A \u0641\u064A \u0623\u064A \u0645\u0633\u062A\u0648\u0649\n\u2022 \u0645\u062F\u0641\u0648\u0639\u0627\u062A \u064A\u0648\u0645\u064A\u0629 \u062A\u0644\u0642\u0627\u0626\u064A\u0629 \u062A\u062A\u0645 \u0645\u0639\u0627\u0644\u062C\u062A\u0647\u0627 \u0628\u0648\u0627\u0633\u0637\u0629 \u0627\u0644\u0640 Smart Contract\n\u2022 \u0631\u0627\u0628\u0637 \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u0627\u0644\u0641\u0631\u064A\u062F \u0627\u0644\u062E\u0627\u0635 \u0628\u0643 = \u0645\u062D\u0631\u0643 \u0627\u0644\u062F\u062E\u0644 \u0627\u0644\u0633\u0644\u0628\u064A \u0627\u0644\u062E\u0627\u0635 \u0628\u0643\n\n\u{1F48E} \u0631\u0627\u0628\u0637 \u0648\u0627\u062D\u062F. \u0639\u0634\u0631\u0648\u0646 \u0645\u0633\u062A\u0648\u0649. \u0625\u0645\u0643\u0627\u0646\u0627\u062A \u063A\u064A\u0631 \u0645\u062D\u062F\u0648\u062F\u0629. \u0627\u0628\u062F\u0623 \u0628\u0627\u0644\u0645\u0634\u0627\u0631\u0643\u0629.\n\n\u{1F310} turboloop.io",
