      original: "48_Onboarding_V2.png",
      headline: "\u{1F537} \u0645\u0643\u0627\u0641\u0623\u0629 \u0627\u0644\u0627\u0646\u0636\u0645\u0627\u0645 \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644",
      caption: "\u{1F537} \u0645\u0643\u0627\u0641\u0623\u0629 \u0627\u0644\u0627\u0646\u0636\u0645\u0627\u0645 \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644\n\u2726 \u0645\u0643\u0627\u0641\u0622\u062A \u0627\u0644\u0625\u0646\u062C\u0627\u0632 \u0644\u0644\u0628\u0646\u0627\u0629 \u0627\u0644\u0633\u0631\u064A\u0639\u064A\u0646 \u2014 \u062A\u0641\u0635\u064A\u0644 \u0643\u0627\u0645\u0644\n\n\u062A\u0645 \u062A\u0635\u0645\u064A\u0645 \u0628\u0631\u0646\u0627\u0645\u062C \u0645\u0643\u0627\u0641\u0623\u0629 \u0627\u0644\u0627\u0646\u0636\u0645\u0627\u0645 \u0627\u0644\u062E\u0627\u0635 \u0628\u0640 TurboLoop \u0644\u062A\u0639\u0632\u064A\u0632 \u0623\u0648\u0644 60 \u064A\u0648\u0645\u064B\u0627 \u0644\u0643 \u0643\u0628\u0627\u0646\u064A \u0634\u0628\u0643\u0629. \u0625\u0644\u064A\u0643 \u0627\u0644\u062A\u0641\u0635\u064A\u0644 \u0627\u0644\u0643\u0627\u0645\u0644 \u0644\u0644\u0625\u0646\u062C\u0627\u0632\u0627\u062A \u0648\u0627\u0644\u0645\u0643\u0627\u0641\u0622\u062A: \u0627\u0644\u0645\u0633\u062A\u0648\u0649 1: 50 \u0639\u0636\u0648\u064B\u0627 \u062C\u062F\u064A\u062F\u064B\u0627 \u062E\u0644\u0627\u0644 60 \u064A\u0648\u0645\u064B\u0627 \u064A\u0643\u0633\u0628\u0643 $50. \u0627\u0644\u0645\u0633\u062A\u0648\u0649 2: 100 \u0639\u0636\u0648 \u064A\u0643\u0633\u0628\u0643 $200. \u0627\u0644\u0645\u0633\u062A\u0648\u0649 3: 250 \u0639\u0636\u0648\u064B\u0627 \u064A\u0643\u0633\u0628\u0643 $750. \u0627\u0644\u0645\u0633\u062A\u0648\u0649 4: 500 \u0639\u0636\u0648 \u064A\u0643\u0633\u0628\u0643 $2,000. \u0627\u0644\u0645\u0633\u062A\u0648\u0649 5: 750 \u0639\u0636\u0648\u064B\u0627 \u064A\u0643\u0633\u0628\u0643 $4,000. \u0627\u0644\u0645\u0633\u062A\u0648\u0649 6: 1,000 \u0639\u0636\u0648 \u064A\u0643\u0633\u0628\u0643 \u0627\u0644\u062D\u062F \u0627\u0644\u0623\u0642\u0635\u0649 \u0644\u0644\u0645\u0643\u0627\u0641\u0623\u0629 \u0648\u0647\u0648 $10,000. \u0647\u0630\u0647 \u0627\u0644\u0645\u0643\u0627\u0641\u0622\u062A \u062A\u0631\u0627\u0643\u0645\u064A\u0629 \u0648\u062A\u064F\u062F\u0641\u0639 \u0628\u0627\u0644\u0625\u0636\u0627\u0641\u0629 \u0625\u0644\u0649 \u0639\u0645\u0648\u0644\u0627\u062A \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u0627\u0644\u0639\u0627\u062F\u064A\u0629 \u0648\u0645\u0643\u0627\u0641\u0622\u062A \u0627\u0644\u0642\u064A\u0627\u062F\u0629 \u0627\u0644\u062E\u0627\u0635\u0629 \u0628\u0643. \u062A\u0628\u062F\u0623 \u0641\u062A\u0631\u0629 \u0627\u0644\u0640 60 \u064A\u0648\u0645\u064B\u0627 \u0645\u0646 \u0623\u0648\u0644 \u0625\u062D\u0627\u0644\u0629 \u0646\u0627\u062C\u062D\u0629 \u0644\u0643\u060C \u0645\u0645\u0627 \u064A\u0645\u0646\u062D\u0643 \u0646\u0627\u0641\u0630\u0629 \u0648\u0627\u0636\u062D\u0629 \u0644\u0632\u064A\u0627\u062F\u0629 \u0623\u0631\u0628\u0627\u062D \u0627\u0644\u0627\u0646\u0636\u0645\u0627\u0645 \u0627\u0644\u062E\u0627\u0635\u0629 \u0628\u0643. \u0627\u0628\u0646\u0650 \u0628\u0633\u0631\u0639\u0629\u060C \u0648\u0627\u0643\u0633\u0628 \u0627\u0644\u0643\u062B\u064A\u0631.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u0627\u0644\u0645\u0633\u062A\u0648\u0649 1: 50 \u0639\u0636\u0648\u064B\u0627 \u2192 $50 | \u0627\u0644\u0645\u0633\u062A\u0648\u0649 2: 100 \u0639\u0636\u0648 \u2192 $200\n\u2022 \u0627\u0644\u0645\u0633\u062A\u0648\u0649 3: 250 \u0639\u0636\u0648\u064B\u0627 \u2192 $750 | \u0627\u0644\u0645\u0633\u062A\u0648\u0649 4: 500 \u0639\u0636\u0648 \u2192 $2,000\n\u2022 \u0627\u0644\u0645\u0633\u062A\u0648\u0649 5: 750 \u0639\u0636\u0648\u064B\u0627 \u2192 $4,000 | \u0627\u0644\u0645\u0633\u062A\u0648\u0649 6: 1,000 \u0639\u0636\u0648 \u2192 $10,000\n\u2022 \u062A\u064F\u062F\u0641\u0639 \u062C\u0645\u064A\u0639 \u0627\u0644\u0645\u0633\u062A\u0648\u064A\u0627\u062A \u0628\u0627\u0644\u0625\u0636\u0627\u0641\u0629 \u0625\u0644\u0649 \u0623\u0631\u0628\u0627\u062D \u0627\u0644\u0625\u062D\u0627\u0644\u0629 \u0648\u0627\u0644\u0642\u064A\u0627\u062F\u0629 \u0627\u0644\u0639\u0627\u062F\u064A\u0629\n\u2022 \u0646\u0627\u0641\u0630\u0629 \u0645\u062F\u062A\u0647\u0627 60 \u064A\u0648\u0645\u064B\u0627 \u0645\u0646 \u0623\u0648\u0644 \u0625\u062D\u0627\u0644\u0629 \u2014 \u0627\u0628\u0646\u0650 \u0628\u0633\u0631\u0639\u0629\u060C \u0648\u0627\u0643\u0633\u0628 \u0627\u0644\u0643\u062B\u064A\u0631\n\n\u{1F48E} \u0627\u0628\u0646\u0650. \u0627\u0643\u0633\u0628. \u0643\u0631\u0631. \u0623\u0648\u0644 60 \u064A\u0648\u0645\u064B\u0627 \u0644\u0643 \u0647\u064A \u0627\u0644\u0623\u0643\u062B\u0631 \u0645\u0643\u0627\u0641\u0623\u0629.\n\n\u{1F310} turboloop.io",
