      original: "50_Zoom_V2.png",
      headline: "\u{1F537} \u0645\u0642\u062F\u0645 \u0639\u0631\u0648\u0636 Zoom \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644",
      caption: "\u{1F537} \u0645\u0642\u062F\u0645 \u0639\u0631\u0648\u0636 Zoom \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644\n\u2726 \u0643\u0646 \u0633\u0641\u064A\u0631\u0627\u064B \u0631\u0633\u0645\u064A\u0627\u064B \u2014 $100/\u0634\u0647\u0631\u064A\u0627\u064B \u0645\u0636\u0645\u0648\u0646\u0629\n\n\u0628\u0631\u0646\u0627\u0645\u062C \u0645\u0642\u062F\u0645 \u0639\u0631\u0648\u0636 Zoom \u0647\u0648 \u0645\u0628\u0627\u062F\u0631\u0629 \u0627\u0644\u0633\u0641\u0631\u0627\u0621 \u0627\u0644\u062E\u0627\u0635\u0629 \u0628\u0640 TurboLoop\u060C \u0648\u0627\u0644\u062A\u064A \u062A\u0647\u062F\u0641 \u0625\u0644\u0649 \u062A\u0645\u0643\u064A\u0646 \u0623\u0639\u0636\u0627\u0621 \u0627\u0644\u0645\u062C\u062A\u0645\u0639 \u0627\u0644\u0634\u063A\u0648\u0641\u064A\u0646 \u0644\u062A\u062B\u0642\u064A\u0641 \u0648\u062A\u0646\u0645\u064A\u0629 \u0634\u0628\u0643\u0627\u062A\u0647\u0645 \u0627\u0644\u0645\u062D\u0644\u064A\u0629. \u0625\u0644\u064A\u0643 \u0643\u064A\u0641 \u064A\u0639\u0645\u0644 \u0627\u0644\u0623\u0645\u0631: \u062A\u0642\u062F\u0645 \u0628\u0637\u0644\u0628\u0643 \u0639\u0628\u0631 \u0627\u0644\u0642\u0646\u0627\u0629 \u0627\u0644\u0631\u0633\u0645\u064A\u0629. \u0628\u0645\u062C\u0631\u062F \u0642\u0628\u0648\u0644\u0643\u060C \u0633\u062A\u062A\u0644\u0642\u0649 \u0645\u0648\u0627\u062F \u0639\u0631\u0636 \u062A\u0642\u062F\u064A\u0645\u064A\u0629 \u0645\u0635\u0645\u0645\u0629 \u0628\u0627\u062D\u062A\u0631\u0627\u0641\u064A\u0629 \u062A\u063A\u0637\u064A \u0643\u0644 \u062C\u0627\u0646\u0628 \u0645\u0646 \u062C\u0648\u0627\u0646\u0628 TurboLoop \u2014 \u0627\u0644\u062E\u0637\u0637\u060C \u0627\u0644\u0623\u0645\u0627\u0646\u060C \u0627\u0644\u0625\u062D\u0627\u0644\u0627\u062A\u060C \u0648\u0627\u0644\u0645\u0632\u064A\u062F. \u0633\u062A\u062A\u0644\u0642\u0649 \u0623\u064A\u0636\u0627\u064B \u062A\u062F\u0631\u064A\u0628\u0627\u064B \u0645\u062C\u0627\u0646\u064A\u0627\u064B \u0644\u0636\u0645\u0627\u0646 \u0627\u0644\u062F\u0642\u0629 \u0648\u0627\u0644\u0641\u0639\u0627\u0644\u064A\u0629. \u0628\u0639\u062F \u0630\u0644\u0643\u060C \u0642\u0645 \u0628\u0627\u0633\u062A\u0636\u0627\u0641\u0629 \u062C\u0644\u0633\u0627\u062A Zoom \u0645\u0646\u062A\u0638\u0645\u0629 \u0644\u0645\u062C\u062A\u0645\u0639\u0643 \u0627\u0644\u0645\u062D\u0644\u064A \u0628\u0644\u063A\u062A\u0643 \u0627\u0644\u0645\u0641\u0636\u0644\u0629. \u0641\u064A \u0627\u0644\u0645\u0642\u0627\u0628\u0644\u060C \u0633\u062A\u0631\u0628\u062D $100 \u0634\u0647\u0631\u064A\u0627\u064B \u0628\u0634\u0643\u0644 \u062B\u0627\u0628\u062A \u0643\u0631\u0627\u062A\u0628 \u0644\u0645\u0642\u062F\u0645 \u0627\u0644\u0639\u0631\u0648\u0636. \u0627\u0644\u0628\u0631\u0646\u0627\u0645\u062C \u0645\u0641\u062A\u0648\u062D \u0644\u0644\u0623\u0639\u0636\u0627\u0621 \u0641\u064A \u062C\u0645\u064A\u0639 \u0623\u0646\u062D\u0627\u0621 \u0627\u0644\u0639\u0627\u0644\u0645\u060C \u0648\u0644\u0627 \u064A\u0648\u062C\u062F \u062D\u062F \u0623\u0642\u0635\u0649 \u0644\u0639\u062F\u062F \u0627\u0644\u062C\u0644\u0633\u0627\u062A \u0627\u0644\u062A\u064A \u064A\u0645\u0643\u0646\u0643 \u0627\u0633\u062A\u0636\u0627\u0641\u062A\u0647\u0627. \u0643\u0644\u0645\u0627 \u0642\u062F\u0645\u062A \u0639\u0631\u0648\u0636\u0627\u064B \u0623\u0643\u062B\u0631\u060C \u0632\u0627\u062F \u0646\u0645\u0648 \u0634\u0628\u0643\u062A\u0643 \u2014 \u0645\u0645\u0627 \u064A\u0636\u0627\u0639\u0641 \u0623\u0631\u0628\u0627\u062D\u0643 \u0645\u0646 \u0627\u0644\u0625\u062D\u0627\u0644\u0627\u062A \u0648\u0627\u0644\u0642\u064A\u0627\u062F\u0629.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u062A\u0642\u062F\u0645 \u0628\u0637\u0644\u0628 \u0644\u062A\u0635\u0628\u062D \u0645\u0642\u062F\u0645 \u0639\u0631\u0648\u0636 Zoom \u0631\u0633\u0645\u064A\u0627\u064B \u0644\u0640 TurboLoop\n\u2022 \u0627\u062D\u0635\u0644 \u0639\u0644\u0649 \u0645\u0648\u0627\u062F \u0639\u0631\u0636 \u062A\u0642\u062F\u064A\u0645\u064A\u0629 \u0627\u062D\u062A\u0631\u0627\u0641\u064A\u0629 \u0648\u062A\u062F\u0631\u064A\u0628 \u0645\u062C\u0627\u0646\u064A\n\u2022 \u0627\u0633\u062A\u0636\u0641 \u062C\u0644\u0633\u0627\u062A Zoom \u0645\u0646\u062A\u0638\u0645\u0629 \u0628\u0644\u063A\u062A\u0643 \u0648\u0644\u0645\u062C\u062A\u0645\u0639\u0643\n\u2022 \u0627\u0631\u0628\u062D $100/\u0634\u0647\u0631\u064A\u0627\u064B \u0643\u0631\u0627\u062A\u0628 \u0645\u0636\u0645\u0648\u0646 \u0644\u0645\u0642\u062F\u0645 \u0627\u0644\u0639\u0631\u0648\u0636\n\u2022 \u0642\u0645 \u0628\u062A\u0646\u0645\u064A\u0629 \u0634\u0628\u0643\u062A\u0643 \u0628\u0634\u0643\u0644 \u0637\u0628\u064A\u0639\u064A \u2014 \u0648\u0636\u0627\u0639\u0641 \u0623\u0631\u0628\u0627\u062D \u0627\u0644\u0625\u062D\u0627\u0644\u0629\n\n\u{1F48E} \u0639\u0644\u0651\u0645. \u0623\u0644\u0647\u0645. \u0627\u0631\u0628\u062D. \u0627\u0644\u0639\u0627\u0644\u0645 \u0628\u062D\u0627\u062C\u0629 \u0625\u0644\u0649 \u0633\u0641\u0631\u0627\u0621 TurboLoop.\n\n\u{1F310} turboloop.io",
