      headline: "\u{1F537} \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0627\u0644\u0645\u0644\u0643\u064A\u0629 \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644",
      caption: "\u{1F537} \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0627\u0644\u0645\u0644\u0643\u064A\u0629 \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644\n\u2726 \u0627\u0644\u0639\u0646\u0648\u0627\u0646 \u0627\u0644\u0645\u064A\u062A \u2014 \u0645\u0627\u0630\u0627 \u064A\u0639\u0646\u064A \u0630\u0644\u0643 \u0644\u0623\u0645\u0627\u0646\u0643\n\n\u0639\u0646\u062F\u0645\u0627 \u062A\u0645 \u0627\u0644\u062A\u0646\u0627\u0632\u0644 \u0639\u0646 \u0645\u0644\u0643\u064A\u0629 TurboLoop\u060C \u062A\u0645 \u0646\u0642\u0644 \u0627\u0645\u062A\u064A\u0627\u0632\u0627\u062A \u0645\u0633\u0624\u0648\u0644 \u0627\u0644\u0639\u0642\u062F \u0628\u0634\u0643\u0644 \u062F\u0627\u0626\u0645 \u0625\u0644\u0649 \u0627\u0644\u0639\u0646\u0648\u0627\u0646 \u0627\u0644\u0645\u064A\u062A: 0x000...dead. \u0647\u0630\u0627 \u0625\u062C\u0631\u0627\u0621 \u0641\u064A \u0627\u062A\u062C\u0627\u0647 \u0648\u0627\u062D\u062F \u0648\u0644\u0627 \u0631\u062C\u0639\u0629 \u0641\u064A\u0647 \u0648\u0644\u0647 \u0622\u062B\u0627\u0631 \u0623\u0645\u0646\u064A\u0629 \u0639\u0645\u064A\u0642\u0629. \u0647\u0630\u0627 \u064A\u0639\u0646\u064A: \u0644\u0627 \u064A\u0645\u0643\u0646 \u0644\u0623\u062D\u062F \u062A\u0639\u062F\u064A\u0644 \u0643\u0648\u062F \u0627\u0644\u0639\u0642\u062F \u0623\u0648 \u0645\u0646\u0637\u0642\u0647. \u0644\u0627 \u064A\u0645\u0643\u0646 \u0644\u0623\u062D\u062F \u0625\u064A\u0642\u0627\u0641 \u0627\u0644\u0639\u0642\u062F \u0645\u0624\u0642\u062A\u0627\u064B \u0623\u0648 \u062A\u062C\u0645\u064A\u062F\u0647. \u0644\u0627 \u064A\u0645\u0643\u0646 \u0644\u0623\u062D\u062F \u0625\u0636\u0627\u0641\u0629 \u0648\u0638\u0627\u0626\u0641 \u0633\u062D\u0628 \u0637\u0627\u0631\u0626\u0629. \u0644\u0627 \u064A\u0645\u0643\u0646 \u0644\u0623\u062D\u062F \u062A\u063A\u064A\u064A\u0631 \u0647\u064A\u0627\u0643\u0644 \u0627\u0644\u0631\u0633\u0648\u0645 \u0623\u0648 \u0645\u0639\u062F\u0644\u0627\u062A \u0627\u0644\u0639\u0627\u0626\u062F. \u0644\u0627 \u064A\u0645\u0643\u0646 \u0644\u0623\u062D\u062F \u062A\u0631\u0642\u064A\u0629 \u0627\u0644\u0639\u0642\u062F \u0623\u0648 \u062A\u0631\u062D\u064A\u0644\u0647. \u0644\u0627 \u064A\u0645\u0643\u0646 \u0644\u0623\u062D\u062F \u0627\u0644\u0648\u0635\u0648\u0644 \u0625\u0644\u0649 \u0623\u0645\u0648\u0627\u0644 \u0627\u0644\u0645\u0633\u062A\u062E\u062F\u0645\u064A\u0646 \u0623\u0648 \u0625\u0639\u0627\u062F\u0629 \u062A\u0648\u062C\u064A\u0647\u0647\u0627. \u0633\u064A\u062A\u0645 \u062A\u0646\u0641\u064A\u0630 \u0627\u0644\u0639\u0642\u062F \u062A\u0645\u0627\u0645\u0627\u064B \u0643\u0645\u0627 \u0647\u0648 \u0645\u0643\u062A\u0648\u0628\u060C \u0628\u0634\u0643\u0644 \u0645\u0633\u062A\u0642\u0644\u060C \u0637\u0627\u0644\u0645\u0627 \u0623\u0646 Binance Smart Chain \u0645\u0648\u062C\u0648\u062F\u0629. \u064A\u0645\u0643\u0646\u0643 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646 \u0630\u0644\u0643 \u0628\u0646\u0641\u0633\u0643 \u0639\u0644\u0649 BscScan \u0639\u0646 \u0637\u0631\u064A\u0642 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646 \u0639\u0646\u0648\u0627\u0646 \u0645\u0627\u0644\u0643 \u0627\u0644\u0639\u0642\u062F. \u0625\u0646\u0647 \u0644\u064A\u0633 \u0648\u0639\u062F\u0627\u064B \u2014 \u0625\u0646\u0647\u0627 \u062D\u0642\u064A\u0642\u0629 \u0639\u0644\u0649 \u0627\u0644\u0633\u0644\u0633\u0644\u0629.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u0639\u0646\u0648\u0627\u0646 \u0627\u0644\u0645\u0627\u0644\u0643: 0x000...dead \u2014 \u062A\u0645 \u062A\u0639\u064A\u064A\u0646\u0647 \u0628\u0634\u0643\u0644 \u062F\u0627\u0626\u0645 \u0648\u0644\u0627 \u0631\u062C\u0639\u0629 \u0641\u064A\u0647\n\u2022 \u0644\u0627 \u064A\u0645\u0643\u0646 \u0625\u062C\u0631\u0627\u0621 \u062A\u0639\u062F\u064A\u0644\u0627\u062A \u0639\u0644\u0649 \u0627\u0644\u0643\u0648\u062F \u2014 \u0627\u0644\u0639\u0642\u062F \u0646\u0647\u0627\u0626\u064A\n\u2022 \u0644\u0627 \u064A\u0645\u0643\u0646 \u0625\u0636\u0627\u0641\u0629 \u0648\u0638\u0627\u0626\u0641 \u0625\u064A\u0642\u0627\u0641 \u0645\u0624\u0642\u062A \u0623\u0648 \u062A\u062C\u0645\u064A\u062F \u0623\u0648 \u0637\u0648\u0627\u0631\u0626\n\u2022 \u0644\u0627 \u064A\u0645\u0643\u0646 \u062A\u063A\u064A\u064A\u0631 \u0627\u0644\u0631\u0633\u0648\u0645 \u0623\u0648 \u062A\u063A\u064A\u064A\u0631 \u0627\u0644\u0645\u0639\u062F\u0644\u0627\u062A \u0623\u0648 \u062A\u062D\u062F\u064A\u062B\u0627\u062A \u0627\u0644\u0645\u0646\u0637\u0642\n\u2022 \u064A\u0645\u0643\u0646 \u0627\u0644\u062A\u062D\u0642\u0642 \u0645\u0646\u0647 \u0639\u0644\u0649 BscScan \u2014 \u062A\u062D\u0642\u0642 \u0645\u0646 \u0639\u0646\u0648\u0627\u0646 \u0627\u0644\u0645\u0627\u0644\u0643 \u0628\u0646\u0641\u0633\u0643\n\n\u{1F48E} \u0627\u0644\u0643\u0648\u062F \u0646\u0647\u0627\u0626\u064A. \u0627\u0644\u0642\u0648\u0627\u0639\u062F \u0645\u062D\u062F\u062F\u0629. \u063A\u064A\u0631 \u0642\u0627\u0628\u0644 \u0644\u0644\u062A\u063A\u064A\u064A\u0631 \u0625\u0644\u0649 \u0627\u0644\u0623\u0628\u062F.\n\n\u{1F310} turboloop.io",
