      original: "60_Arbah_Yawmiya_Tafasil.png",
      headline: "\u{1F537} \u0627\u0644\u0623\u0631\u0628\u0627\u062D \u0627\u0644\u064A\u0648\u0645\u064A\u0629 \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644",
      caption: "\u{1F537} \u0627\u0644\u0623\u0631\u0628\u0627\u062D \u0627\u0644\u064A\u0648\u0645\u064A\u0629 \u2014 \u0628\u0627\u0644\u062A\u0641\u0635\u064A\u0644\n\u2726 \u0627\u0644\u0622\u0644\u064A\u0629 \u0648\u0631\u0627\u0621 \u0639\u0648\u0627\u0626\u062F\u0643 \u0627\u0644\u064A\u0648\u0645\u064A\u0629\n\n\u0625\u0644\u064A\u0643 \u0628\u0627\u0644\u0636\u0628\u0637 \u0643\u064A\u0641 \u062A\u0639\u0645\u0644 \u0622\u0644\u064A\u0629 \u0627\u0644\u0623\u0631\u0628\u0627\u062D \u0627\u0644\u064A\u0648\u0645\u064A\u0629 \u0641\u064A TurboLoop \u0645\u0646 \u0627\u0644\u062F\u0627\u062E\u0644. \u0641\u064A \u062A\u0645\u0627\u0645 \u0627\u0644\u0633\u0627\u0639\u0629 00:00 UTC \u0645\u0646 \u0643\u0644 \u064A\u0648\u0645\u060C \u064A\u0646\u0641\u0630 \u0627\u0644\u0640 Smart Contract \u0648\u0638\u064A\u0641\u0629 \u062D\u0633\u0627\u0628 \u0627\u0644\u0639\u0627\u0626\u062F \u0627\u0644\u062E\u0627\u0635\u0629 \u0628\u0647. \u0644\u0643\u0644 \u0625\u064A\u062F\u0627\u0639 \u0646\u0634\u0637\u060C \u064A\u062A\u0645 \u062D\u0633\u0627\u0628 \u0627\u0644\u0639\u0627\u0626\u062F \u0627\u0644\u064A\u0648\u0645\u064A \u0628\u0646\u0627\u0621\u064B \u0639\u0644\u0649 \u0645\u0639\u062F\u0644 \u0627\u0644\u062E\u0637\u0629: Sprint (~0.43%)\u060C Boost (~0.71%)\u060C Power (~0.8%)\u060C \u0623\u0648 Ultimate (~0.9%). \u064A\u062A\u0645 \u0628\u0639\u062F \u0630\u0644\u0643 \u0625\u0636\u0627\u0641\u0629 \u0647\u0630\u0627 \u0627\u0644\u0645\u0628\u0644\u063A \u0627\u0644\u0645\u062D\u0633\u0648\u0628 \u0625\u0644\u0649 \u0631\u0635\u064A\u062F\u0643 \u0627\u0644\u0645\u062A\u0627\u062D \u062A\u0644\u0642\u0627\u0626\u064A\u0627\u064B. \u0644\u0627 \u062A\u0648\u062C\u062F \u0623\u064A \u0645\u0639\u0627\u0645\u0644\u0629 \u0645\u0637\u0644\u0648\u0628\u0629 \u0645\u0646\u0643 \u2014 \u0644\u0627 \u0631\u0633\u0648\u0645 \u063A\u0627\u0632\u060C \u0644\u0627 \u0645\u0637\u0627\u0644\u0628\u0627\u062A\u060C \u0648\u0644\u0627 \u0623\u064A \u062A\u0641\u0627\u0639\u0644 \u0639\u0644\u0649 \u0627\u0644\u0625\u0637\u0644\u0627\u0642. \u062A\u062A\u0643\u0631\u0631 \u0627\u0644\u0639\u0645\u0644\u064A\u0629 \u0643\u0644 24 \u0633\u0627\u0639\u0629 \u0628\u062F\u0642\u0629 \u0631\u064A\u0627\u0636\u064A\u0629 \u062D\u062A\u0649 \u062A\u0643\u062A\u0645\u0644 \u062F\u0648\u0631\u0629 \u062E\u0637\u062A\u0643. \u0641\u064A \u062A\u0644\u0643 \u0627\u0644\u0644\u062D\u0638\u0629\u060C \u064A\u0635\u0628\u062D \u0631\u0623\u0633 \u0645\u0627\u0644\u0643 \u0628\u0627\u0644\u0643\u0627\u0645\u0644 \u0628\u0627\u0644\u0625\u0636\u0627\u0641\u0629 \u0625\u0644\u0649 \u062C\u0645\u064A\u0639 \u0627\u0644\u0639\u0648\u0627\u0626\u062F \u0627\u0644\u064A\u0648\u0645\u064A\u0629 \u0627\u0644\u0645\u062A\u0631\u0627\u0643\u0645\u0629 \u0645\u062A\u0627\u062D\u0627\u064B \u0644\u0644\u0633\u062D\u0628. \u064A\u0645\u0643\u0646\u0643 \u062A\u062A\u0628\u0639 \u0643\u0644 \u0639\u0645\u0644\u064A\u0629 \u062D\u0633\u0627\u0628\u064A\u0629 \u0641\u064A \u0627\u0644\u0648\u0642\u062A \u0627\u0644\u0641\u0639\u0644\u064A \u0645\u0646 \u062E\u0644\u0627\u0644 \u0644\u0648\u062D\u0629 \u062A\u062D\u0643\u0645 TurboLoop.\n\n\u2705 \u0623\u0628\u0631\u0632 \u0627\u0644\u0646\u0642\u0627\u0637:\n\u2022 \u0645\u062D\u0641\u0632 \u0627\u0644\u062D\u0633\u0627\u0628: \u0641\u064A \u062A\u0645\u0627\u0645 \u0627\u0644\u0633\u0627\u0639\u0629 00:00 UTC \u0643\u0644 24 \u0633\u0627\u0639\u0629\n\u2022 \u0627\u0644\u0645\u0639\u062F\u0644\u0627\u062A \u0627\u0644\u064A\u0648\u0645\u064A\u0629: Sprint ~0.43%\u060C Boost ~0.71%\u060C Power ~0.8%\u060C Ultimate ~0.9%\n\u2022 \u062A\u0636\u0627\u0641 \u0627\u0644\u0639\u0648\u0627\u0626\u062F \u0625\u0644\u0649 \u0627\u0644\u0631\u0635\u064A\u062F \u062A\u0644\u0642\u0627\u0626\u064A\u0627\u064B \u2014 \u0644\u0627 \u064A\u062A\u0637\u0644\u0628 \u0623\u064A \u0625\u062C\u0631\u0627\u0621 \u0645\u0646 \u0627\u0644\u0645\u0633\u062A\u062E\u062F\u0645\n\u2022 \u0644\u0627 \u062A\u0648\u062C\u062F \u0631\u0633\u0648\u0645 \u063A\u0627\u0632 \u0644\u0644\u0623\u0631\u0628\u0627\u062D \u0627\u0644\u064A\u0648\u0645\u064A\u0629 \u2014 \u0627\u0644\u0640 Smart Contract \u064A\u062A\u0648\u0644\u0649 \u0643\u0644 \u0634\u064A\u0621\n\u2022 \u0631\u0623\u0633 \u0627\u0644\u0645\u0627\u0644 \u0628\u0627\u0644\u0643\u0627\u0645\u0644 + \u0627\u0644\u0639\u0648\u0627\u0626\u062F \u0627\u0644\u0645\u062A\u0631\u0627\u0643\u0645\u0629 \u0645\u062A\u0627\u062D\u0629 \u0641\u064A \u0646\u0647\u0627\u064A\u0629 \u0627\u0644\u062F\u0648\u0631\u0629\n\n\u{1F48E} \u062F\u0642\u0629. \u0623\u062A\u0645\u062A\u0629. \u0643\u0644 \u064A\u0648\u0645. \u0643\u0644 \u062F\u0648\u0631\u0629. \u0628\u0644\u0627 \u0641\u0634\u0644.\n\n\u{1F310} turboloop.io",
